# =====================================================================
# Chain 1: Auth Pipeline -- Token -> Permission -> Sandbox
# =====================================================================

def test_chain1_auth_pipeline():
    """Agent authenticates, gets permission checked, sandbox created."""
    bus = PipelineIntegrationBus()
    tokens = AgentTokenManager()
    perms = AgentPermissionManager()
    sandboxes = AgentSandboxManager()

    # Setup: create role with sandbox:create permission
    perms.create_role("developer", permissions=["sandbox:create", "code:read"])
    perms.assign_role("worker-1", "developer")

    def step_issue_token(ctx):
        tid = tokens.issue_token(ctx["agent"], scopes=["sandbox:create", "code:read"])
        ctx["token_id"] = tid
        return ctx

    def step_check_permission(ctx):
        validation = tokens.validate_token(ctx["token_id"], required_scope="sandbox:create")
        assert validation["valid"], f"Token invalid: {validation.get('reason')}"
        has_perm = perms.check(ctx["agent"], "sandbox", "create")
        assert has_perm, "Permission denied"
        ctx["permission_granted"] = True
        return ctx

    def step_create_sandbox(ctx):
        assert ctx.get("permission_granted"), "No permission"
        sid = sandboxes.create_sandbox(ctx["agent"], cpu_limit=30.0, memory_limit=512)
        assert sid, "Sandbox creation failed"
        ctx["sandbox_id"] = sid
        return ctx

    bus.register_chain("auth_pipeline", tags=["security"])
    bus.add_step("auth_pipeline", "issue_token", step_issue_token, "token_manager")
    bus.add_step("auth_pipeline", "check_permission", step_check_permission, "permission_manager")
    bus.add_step("auth_pipeline", "create_sandbox", step_create_sandbox, "sandbox_manager")

    result = bus.execute("auth_pipeline", {"agent": "worker-1"})
    assert result["success"] is True
    assert result["steps_completed"] == 3
    assert result["context"]["sandbox_id"].startswith("sbx-")
    assert result["context"]["token_id"].startswith("tok-")

    # Verify sandbox exists
    sb = sandboxes.get_sandbox(result["context"]["sandbox_id"])
    assert sb is not None
    assert sb["agent"] == "worker-1"
    print("OK: Chain 1 -- Auth Pipeline (Token -> Permission -> Sandbox)")


# =====================================================================
# Chain 2: Execution Pipeline -- Lease -> Pool -> StateMachine -> Resource
# =====================================================================

def test_chain2_execution_pipeline():
    """Agent leases resource, acquires from pool, transitions states, tracks usage."""
    bus = PipelineIntegrationBus()
    leases = AgentLeaseManager()
    pools = AgentPoolManager()
    states = AgentStateMachine()
    resources = PipelineResourceTracker()

    # Setup
    pools.create_pool("gpu_workers")
    pools.add_agent("gpu_workers", "gpu-agent-1")
    pools.add_agent("gpu_workers", "gpu-agent-2")

    states.create_machine("task-fsm", "pending", states=["pending", "running", "completed", "failed"])
    states.add_transition("task-fsm", "pending", "running")
    states.add_transition("task-fsm", "running", "completed")
    states.add_transition("task-fsm", "running", "failed")

    resources.register_resource("gpu_compute", resource_type="cpu", capacity=100.0, unit="TFLOPS")

    def step_lease_resource(ctx):
        lid = leases.acquire("gpu_compute", ctx["requester"], duration=120.0)
        assert lid, "Failed to acquire lease"
        ctx["lease_id"] = lid
        return ctx

    def step_acquire_agent(ctx):
        result = pools.acquire("gpu_workers", requester=ctx["requester"])
        assert result is not None, "No agent available in pool"
        ctx["pool_entry_id"] = result["entry_id"]
        ctx["assigned_agent"] = result["agent_id"]
        return ctx

    def step_transition_running(ctx):
        ok = states.transition("task-fsm", "running")
        assert ok, "Failed to transition to running"
        ctx["state"] = "running"
        return ctx

    def step_track_resources(ctx):
        resources.allocate("gpu_compute", 40.0)
        resources.update_usage("gpu_compute", 35.0)
        ctx["resource_allocated"] = 40.0
        ctx["resource_used"] = 35.0
        return ctx

    bus.register_chain("execution_pipeline", tags=["compute"])
    bus.add_step("execution_pipeline", "lease", step_lease_resource, "lease_manager")
    bus.add_step("execution_pipeline", "acquire", step_acquire_agent, "pool_manager")
    bus.add_step("execution_pipeline", "transition", step_transition_running, "state_machine")
    bus.add_step("execution_pipeline", "track", step_track_resources, "resource_tracker")

    result = bus.execute("execution_pipeline", {"requester": "task-orchestrator"})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["assigned_agent"] == "gpu-agent-1"
    assert states.get_state("task-fsm") == "running"
    assert resources.get_utilization("gpu_compute") == 35.0
    print("OK: Chain 2 -- Execution Pipeline (Lease -> Pool -> State -> Resource)")


# =====================================================================
# Chain 3: Quality Pipeline -- Circuit -> Retry -> Reputation -> Trust
# =====================================================================

def test_chain3_quality_pipeline():
    """Record stage health, apply retry policy, update reputation and trust."""
    bus = PipelineIntegrationBus()
    circuits = PipelineCircuitAnalyzer()
    retries = PipelineRetryPolicy()
    reputation = AgentReputationTracker()
    trust = AgentTrustNetwork()

    # Setup
    circuits.register_stage("api_gateway", failure_threshold=5)
    retries.create_policy("api_retry", max_retries=3, backoff="exponential", initial_delay=0.1)
    reputation.register_agent("agent-alpha", initial_score=50.0)
    reputation.register_agent("agent-beta", initial_score=50.0)
    trust.establish_trust("agent-alpha", "agent-beta")

    def step_record_circuit(ctx):
        # Simulate 2 successes and 1 failure
        circuits.record_success("api_gateway", latency=50.0)
        circuits.record_success("api_gateway", latency=45.0)
        circuits.record_failure("api_gateway", latency=200.0)
        stage = circuits.get_stage("api_gateway")
        ctx["failure_rate"] = stage["failure_rate_pct"]
        ctx["circuit_status"] = stage["status"]
        return ctx

    def step_apply_retry(ctx):
        # Simulate retry logic using the new API
        attempts = 0
        success = False
        while retries.should_retry("api_retry", attempts + 1):
            attempts += 1
            retries.record_attempt("api_retry", success=(attempts >= 2))
            if attempts >= 2:
                success = True
                break
        ctx["retry_success"] = success
        ctx["retry_attempts"] = attempts
        return ctx

    def step_update_reputation(ctx):
        if ctx["retry_success"]:
            reputation.record_outcome("agent-alpha", "api_call", success=True, quality=0.9)
        else:
            reputation.record_outcome("agent-alpha", "api_call", success=False, quality=0.1)
        ctx["reputation_score"] = reputation.get_reputation("agent-alpha")["score"]
        return ctx

    def step_update_trust(ctx):
        # Alpha trusts beta based on quality result
        if ctx["retry_success"]:
            trust.record_positive("agent-alpha", "agent-beta", bonus=10.0)
        else:
            trust.record_negative("agent-alpha", "agent-beta", penalty=10.0)
        ctx["trust_score"] = trust.get_trust("agent-alpha", "agent-beta")
        return ctx

    bus.register_chain("quality_pipeline", tags=["observability"])
    bus.add_step("quality_pipeline", "circuit", step_record_circuit, "circuit_analyzer")
    bus.add_step("quality_pipeline", "retry", step_apply_retry, "retry_policy")
    bus.add_step("quality_pipeline", "reputation", step_update_reputation, "reputation_tracker")
    bus.add_step("quality_pipeline", "trust", step_update_trust, "trust_network")

    result = bus.execute("quality_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["retry_success"] is True
    assert result["context"]["retry_attempts"] == 2
    assert result["context"]["reputation_score"] > 50.0  # started at 50 + bonus
    assert result["context"]["trust_score"] > 50.0  # started at default + bonus
    print("OK: Chain 3 -- Quality Pipeline (Circuit -> Retry -> Reputation -> Trust)")


# =====================================================================
# Chain 4: Cost Pipeline -- Budget -> Telemetry -> Config
# =====================================================================

def test_chain4_cost_pipeline():
    """Reserve budget, record telemetry, store cost config."""
    bus = PipelineIntegrationBus()
    budgets = AgentBudgetController()
    telemetry = PipelineTelemetryCollector()
    config = PipelineConfigStore()

    # Setup
    budgets.create_budget("project-x", total_budget=1000.0, tags=["production"])
    telemetry.register_metric("api_cost", metric_type="counter", tags=["billing"])
    telemetry.register_metric("active_agents", metric_type="gauge")

    def step_reserve_budget(ctx):
        ok = budgets.reserve(ctx["budget_name"], ctx["amount"])
        assert ok, "Budget reservation failed"
        remaining = budgets.get_budget(ctx["budget_name"])["remaining"]
        ctx["remaining"] = remaining
        return ctx

    def step_record_telemetry(ctx):
        telemetry.increment("api_cost", ctx["amount"])
        telemetry.set_gauge("active_agents", ctx.get("agent_count", 5))
        ctx["total_cost"] = telemetry.get_value("api_cost")
        return ctx

    def step_store_config(ctx):
        config.set_config("costs", "last_reservation", str(ctx["amount"]))
        config.set_config("costs", "total_spent", str(ctx["total_cost"]))
        ctx["config_stored"] = True
        return ctx

    bus.register_chain("cost_pipeline", tags=["billing"])
    bus.add_step("cost_pipeline", "budget", step_reserve_budget, "budget_controller")
    bus.add_step("cost_pipeline", "telemetry", step_record_telemetry, "telemetry_collector")
    bus.add_step("cost_pipeline", "config", step_store_config, "config_store")

    result = bus.execute("cost_pipeline", {
        "budget_name": "project-x",
        "amount": 150.0,
        "purpose": "API calls batch 1",
        "agent_count": 8,
    })
    assert result["success"] is True
    assert result["steps_completed"] == 3
    assert result["context"]["remaining"] == 850.0
    assert result["context"]["total_cost"] == 150.0
    assert result["context"]["config_stored"] is True

    # Verify config was stored
    assert config.get_config("costs", "total_spent") == "150.0"
    print("OK: Chain 4 -- Cost Pipeline (Budget -> Telemetry -> Config)")


# =====================================================================
# Chain 5: Release Pipeline -- FeatureFlag -> ABTest -> Deploy -> Migration
# =====================================================================

def test_chain5_release_pipeline():
    """Enable feature flag, run A/B test, deploy, apply migration."""
    bus = PipelineIntegrationBus()
    flags = PipelineFeatureFlag()
    ab_tests = PipelineABTestManager()
    deploys = PipelineDeploymentManager()
    migrations = PipelineMigrationRunner()

    # Setup
    flags.create_flag("new_search", enabled=False, rollout_pct=100.0)
    ab_tests.create_experiment("search_experiment", variants=["control", "new_search"])
    ab_tests.start_experiment("search_experiment")
    migrations.register(1, "add_search_index",
                        up_fn=lambda: "index_created",
                        down_fn=lambda: "index_dropped")

    def step_enable_flag(ctx):
        flags.enable_flag(ctx["feature_name"])
        enabled = flags.is_enabled(ctx["feature_name"])
        assert enabled, "Flag not enabled"
        ctx["flag_enabled"] = True
        return ctx

    def step_run_ab_test(ctx):
        ab_tests.record_impression(ctx["test_name"], "new_search")
        ab_tests.record_conversion(ctx["test_name"], "new_search")
        ctx["ab_test_running"] = True
        return ctx

    def step_deploy(ctx):
        did = deploys.create_deployment(ctx["target"], "v2.0.0", strategy="blue_green")
        assert did, "Deployment creation failed"
        deploys.deploy(did)
        ctx["deployment_id"] = did
        ctx["deployed"] = True
        return ctx

    def step_migrate(ctx):
        result = migrations.migrate_up()
        ctx["migrations_applied"] = result["applied"]
        ctx["current_version"] = result["current_version"]
        return ctx

    bus.register_chain("release_pipeline", tags=["release"])
    bus.add_step("release_pipeline", "feature_flag", step_enable_flag, "feature_flag")
    bus.add_step("release_pipeline", "ab_test", step_run_ab_test, "ab_test_manager")
    bus.add_step("release_pipeline", "deploy", step_deploy, "deployment_manager")
    bus.add_step("release_pipeline", "migrate", step_migrate, "migration_runner")

    result = bus.execute("release_pipeline", {
        "feature_name": "new_search",
        "test_name": "search_experiment",
        "target": "search-service",
    })
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["flag_enabled"] is True
    assert result["context"]["deployed"] is True
    assert len(result["context"]["migrations_applied"]) == 1
    assert result["context"]["current_version"] == 1
    print("OK: Chain 5 -- Release Pipeline (Flag -> ABTest -> Deploy -> Migration)")


# =====================================================================
# Chain 6: Swarm Pipeline -- Swarm -> Goal -> Communication -> Validator
# =====================================================================

def test_chain6_swarm_pipeline():
    """Create swarm, plan goals, communicate, validate outputs."""
    bus = PipelineIntegrationBus()
    swarms = AgentSwarmCoordinator()
    goals = AgentGoalPlanner()
    comms = AgentCommunicationProtocol()
    validator = PipelineOutputValidator()

    # Setup
    comms.create_channel("swarm_updates", channel_type="topic")
    validator.register_stage("task_output")
    validator.add_rule("task_output", "has_result", rule_type="required_field", config={"field": "result"})
    validator.add_rule("task_output", "result_is_str", rule_type="type_check", config={"field": "result", "expected_type": "str"})

    def step_create_swarm(ctx):
        swarms.create_swarm("build_team", objective="build auth module", max_agents=10)
        swarms.join_swarm("build_team", "agent-alpha", role="leader")
        swarms.join_swarm("build_team", "agent-beta", role="worker")
        leader = swarms.elect_leader("build_team")
        ctx["leader"] = leader
        ctx["swarm_members"] = 2
        return ctx

    def step_plan_goals(ctx):
        goals.create_goal("auth_module", agent_id=ctx["leader"], description="Build auth")
        goals.create_goal("login_form", agent_id="agent-beta")
        goals.create_goal("jwt_handler", agent_id="agent-beta")
        goals.add_subgoal("auth_module", "login_form")
        goals.add_subgoal("auth_module", "jwt_handler")
        goals.start_goal("login_form")
        goals.start_goal("jwt_handler")
        ctx["goal_count"] = 3
        ctx["ready_goals"] = len(goals.get_ready_goals())
        return ctx

    def step_communicate(ctx):
        comms.subscribe("swarm_updates", "agent-alpha")
        comms.subscribe("swarm_updates", "agent-beta")
        comms.send("swarm_updates", sender="agent-alpha", msg_type="broadcast",
                   payload={"action": "goals_assigned", "count": ctx["goal_count"]})
        msgs = comms.receive("swarm_updates", "agent-beta")
        assert len(msgs) >= 1
        ctx["messages_received"] = len(msgs)
        return ctx

    def step_validate_output(ctx):
        output = {"result": "auth module built successfully", "tests_passed": 42}
        validation = validator.validate("task_output", output)
        assert validation["valid"] is True
        ctx["output_valid"] = True
        # Complete goals
        goals.complete_goal("login_form")
        goals.complete_goal("jwt_handler")
        tree = goals.get_goal_tree("auth_module")
        ctx["subgoals_completed"] = sum(1 for sg in tree["subgoals"] if sg["status"] == "completed")
        return ctx

    bus.register_chain("swarm_pipeline", tags=["coordination"])
    bus.add_step("swarm_pipeline", "create_swarm", step_create_swarm, "swarm_coordinator")
    bus.add_step("swarm_pipeline", "plan_goals", step_plan_goals, "goal_planner")
    bus.add_step("swarm_pipeline", "communicate", step_communicate, "communication_protocol")
    bus.add_step("swarm_pipeline", "validate", step_validate_output, "output_validator")

    result = bus.execute("swarm_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["leader"] == "agent-alpha"
    assert result["context"]["goal_count"] == 3
    assert result["context"]["messages_received"] >= 1
    assert result["context"]["output_valid"] is True
    assert result["context"]["subgoals_completed"] == 2
    print("OK: Chain 6 -- Swarm Pipeline (Swarm -> Goal -> Comm -> Validator)")


# =====================================================================
# Chain 7: Resilience Pipeline -- Chaos -> CostOptimizer -> Retry -> Validator
# =====================================================================

def test_chain7_resilience_pipeline():
    """Inject chaos, track costs, retry, validate recovery."""
    bus = PipelineIntegrationBus()
    chaos = PipelineChaosTester()
    costs = PipelineCostOptimizer()
    retries = PipelineRetryPolicy()
    validator = PipelineOutputValidator()

    # Setup
    chaos.register_target("api_service", target_type="service")
    chaos.create_experiment("resilience_test", target="api_service", chaos_type="error", intensity=50.0)
    costs.register_resource("api_calls", unit_cost=0.01, resource_type="api_call")
    costs.set_budget("api_calls", 10.0)
    retries.create_policy("api_retry", max_retries=3, backoff="exponential", initial_delay=0.01)
    validator.register_stage("recovery_check")
    validator.add_rule("recovery_check", "has_recovered", rule_type="required_field", config={"field": "recovered"})

    def step_inject_chaos(ctx):
        chaos.start_experiment("resilience_test")
        fault = chaos.inject_fault("resilience_test")
        assert fault["injected"] is True
        chaos.record_observation("resilience_test", "response_time", 500.0)
        ctx["fault_injected"] = True
        ctx["chaos_type"] = fault["type"]
        return ctx

    def step_track_cost(ctx):
        costs.record_usage("api_calls", 100.0, context="retry_storm")
        budget = costs.check_budget("api_calls")
        ctx["api_cost"] = costs.get_resource("api_calls")["total_cost"]
        ctx["budget_remaining"] = budget["remaining"]
        return ctx

    def step_retry_recovery(ctx):
        attempts = 0
        success = False
        while retries.should_retry("api_retry", attempts + 1):
            attempts += 1
            retries.record_attempt("api_retry", success=(attempts >= 2))
            if attempts >= 2:
                success = True
                break
        ctx["recovered"] = success
        ctx["retry_attempts"] = attempts
        return ctx

    def step_validate_recovery(ctx):
        validation = validator.validate("recovery_check", {"recovered": ctx["recovered"]})
        ctx["validation_passed"] = validation["valid"]
        chaos.stop_experiment("resilience_test")
        report = chaos.get_experiment_report("resilience_test")
        ctx["resilience_score"] = report["resilience_score"]
        return ctx

    bus.register_chain("resilience_pipeline", tags=["reliability"])
    bus.add_step("resilience_pipeline", "chaos", step_inject_chaos, "chaos_tester")
    bus.add_step("resilience_pipeline", "cost", step_track_cost, "cost_optimizer")
    bus.add_step("resilience_pipeline", "retry", step_retry_recovery, "retry_policy")
    bus.add_step("resilience_pipeline", "validate", step_validate_recovery, "output_validator")

    result = bus.execute("resilience_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["fault_injected"] is True
    assert result["context"]["recovered"] is True
    assert result["context"]["retry_attempts"] == 2
    assert result["context"]["validation_passed"] is True
    assert result["context"]["api_cost"] == 1.0  # 100 * 0.01
    print("OK: Chain 7 -- Resilience Pipeline (Chaos -> Cost -> Retry -> Validator)")


# =====================================================================
# Chain 8: Planning Pipeline -- Decomposer -> Orchestrator -> Workload -> EventMesh
# =====================================================================

def test_chain8_planning_pipeline():
    """Decompose task, orchestrate stages, predict workload, publish events."""
    bus = PipelineIntegrationBus()
    decomposer = AgentTaskDecomposer()
    orchestrator = PipelineStageOrchestrator()
    workload = AgentWorkloadPredictor()
    mesh = PipelineEventMesh()

    # Setup
    mesh.create_topic("planning.events")
    events_received = []
    mesh.subscribe("planning.events", "monitor", handler=lambda d: events_received.append(d))

    def step_decompose(ctx):
        decomposer.create_task("build_feature", complexity=8, estimated_effort=20.0)
        decomposer.decompose("build_feature", [
            {"name": "design", "description": "Design API", "complexity": 3, "estimated_effort": 4.0},
            {"name": "implement", "description": "Code it", "complexity": 6, "estimated_effort": 12.0},
            {"name": "test", "description": "Write tests", "complexity": 4, "estimated_effort": 4.0},
        ])
        leaves = decomposer.get_leaves("build_feature")
        ctx["subtask_count"] = len(leaves)
        ctx["total_effort"] = sum(l["estimated_effort"] for l in leaves)
        return ctx

    def step_orchestrate(ctx):
        orchestrator.create_pipeline("feature_build")
        orchestrator.add_stage("feature_build", "design", handler=lambda c: {**c, "designed": True})
        orchestrator.add_stage("feature_build", "implement", handler=lambda c: {**c, "implemented": True})
        orchestrator.add_stage("feature_build", "test", handler=lambda c: {**c, "tested": True})
        orchestrator.add_dependency("feature_build", "implement", "design")
        orchestrator.add_dependency("feature_build", "test", "implement")
        order = orchestrator.get_execution_order("feature_build")
        ctx["wave_count"] = len(order)
        result = orchestrator.execute("feature_build", {})
        ctx["orchestration_success"] = result["success"]
        ctx["stages_completed"] = result["stages_completed"]
        return ctx

    def step_predict_workload(ctx):
        aid = workload.register_agent("builder-1", capacity=100.0)
        workload.record_task(aid, "prev_design", duration=3.0)
        workload.record_task(aid, "prev_impl", duration=10.0)
        predicted = workload.predict_completion(aid, ctx["subtask_count"])
        ctx["predicted_time"] = predicted
        workload.assign_load(aid, 60.0)
        ctx["bottlenecks"] = len(workload.get_bottlenecks(threshold=50.0))
        return ctx

    def step_publish_events(ctx):
        mesh.publish("planning.events", {
            "type": "planning_complete",
            "subtasks": ctx["subtask_count"],
            "predicted_time": ctx["predicted_time"],
        }, publisher="planner")
        ctx["events_published"] = len(events_received)
        return ctx

    bus.register_chain("planning_pipeline", tags=["planning"])
    bus.add_step("planning_pipeline", "decompose", step_decompose, "task_decomposer")
    bus.add_step("planning_pipeline", "orchestrate", step_orchestrate, "stage_orchestrator")
    bus.add_step("planning_pipeline", "workload", step_predict_workload, "workload_predictor")
    bus.add_step("planning_pipeline", "events", step_publish_events, "event_mesh")

    result = bus.execute("planning_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["subtask_count"] == 3
    assert result["context"]["orchestration_success"] is True
    assert result["context"]["stages_completed"] == 3
    assert result["context"]["predicted_time"] > 0
    assert result["context"]["events_published"] >= 1
    print("OK: Chain 8 -- Planning Pipeline (Decompose -> Orchestrate -> Workload -> EventMesh)")


# =====================================================================
# Chain 9: Full Lifecycle -- Decompose -> Swarm -> Goal -> Comm -> Orchestrate -> Validate
# =====================================================================

def test_chain9_lifecycle_pipeline():
    """End-to-end: decompose task, form swarm, plan goals, communicate, orchestrate, validate."""
    bus = PipelineIntegrationBus()
    decomposer = AgentTaskDecomposer()
    swarms = AgentSwarmCoordinator()
    goals = AgentGoalPlanner()
    comms = AgentCommunicationProtocol()
    orchestrator = PipelineStageOrchestrator()
    validator = PipelineOutputValidator()

    # Setup
    comms.create_channel("lifecycle", channel_type="topic")
    validator.register_stage("final_check")
    validator.add_rule("final_check", "has_output", rule_type="required_field", config={"field": "output"})

    def step_decompose(ctx):
        decomposer.create_task("feature_x", complexity=9, estimated_effort=30.0)
        decomposer.decompose("feature_x", [
            {"name": "backend", "description": "API", "complexity": 7, "estimated_effort": 15.0},
            {"name": "frontend", "description": "UI", "complexity": 5, "estimated_effort": 10.0},
        ])
        decomposer.mark_parallelizable("backend", parallel=True)
        decomposer.mark_parallelizable("frontend", parallel=True)
        ctx["decomposed"] = True
        ctx["leaf_count"] = len(decomposer.get_leaves("feature_x"))
        return ctx

    def step_form_swarm(ctx):
        swarms.create_swarm("feature_team", objective="build feature_x", max_agents=5)
        swarms.join_swarm("feature_team", "dev-1", role="leader")
        swarms.join_swarm("feature_team", "dev-2", role="worker")
        swarms.elect_leader("feature_team")
        ctx["swarm_size"] = swarms.get_swarm("feature_team")["member_count"]
        return ctx

    def step_set_goals(ctx):
        goals.create_goal("deliver_feature_x", agent_id="dev-1")
        goals.create_goal("build_backend", agent_id="dev-1")
        goals.create_goal("build_frontend", agent_id="dev-2")
        goals.add_subgoal("deliver_feature_x", "build_backend")
        goals.add_subgoal("deliver_feature_x", "build_frontend")
        goals.start_goal("build_backend")
        goals.start_goal("build_frontend")
        ctx["goals_active"] = 2
        return ctx

    def step_communicate(ctx):
        comms.subscribe("lifecycle", "dev-1")
        comms.subscribe("lifecycle", "dev-2")
        comms.send("lifecycle", sender="dev-1", msg_type="broadcast",
                   payload={"msg": "starting backend build"})
        msgs = comms.receive("lifecycle", "dev-2")
        ctx["comm_received"] = len(msgs)
        return ctx

    def step_orchestrate(ctx):
        orchestrator.create_pipeline("feature_x_pipeline")
        orchestrator.add_stage("feature_x_pipeline", "backend",
                               handler=lambda c: {**c, "backend_done": True})
        orchestrator.add_stage("feature_x_pipeline", "frontend",
                               handler=lambda c: {**c, "frontend_done": True})
        orchestrator.add_stage("feature_x_pipeline", "integrate",
                               handler=lambda c: {**c, "output": "feature_x complete"})
        orchestrator.add_dependency("feature_x_pipeline", "integrate", "backend")
        orchestrator.add_dependency("feature_x_pipeline", "integrate", "frontend")
        result = orchestrator.execute("feature_x_pipeline", {})
        ctx["pipeline_success"] = result["success"]
        ctx["output"] = result["results"].get("integrate", {}).get("output", "")
        return ctx

    def step_validate(ctx):
        v = validator.validate("final_check", {"output": ctx["output"]})
        ctx["valid"] = v["valid"]
        goals.complete_goal("build_backend")
        goals.complete_goal("build_frontend")
        ctx["completion_pct"] = 100.0
        return ctx

    bus.register_chain("lifecycle_pipeline", tags=["lifecycle"])
    bus.add_step("lifecycle_pipeline", "decompose", step_decompose, "decomposer")
    bus.add_step("lifecycle_pipeline", "swarm", step_form_swarm, "swarm_coordinator")
    bus.add_step("lifecycle_pipeline", "goals", step_set_goals, "goal_planner")
    bus.add_step("lifecycle_pipeline", "communicate", step_communicate, "communication")
    bus.add_step("lifecycle_pipeline", "orchestrate", step_orchestrate, "orchestrator")
    bus.add_step("lifecycle_pipeline", "validate", step_validate, "validator")

    result = bus.execute("lifecycle_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 6
    assert result["context"]["decomposed"] is True
    assert result["context"]["swarm_size"] == 2
    assert result["context"]["pipeline_success"] is True
    assert result["context"]["valid"] is True
    assert result["context"]["completion_pct"] == 100.0
    print("OK: Chain 9 -- Lifecycle Pipeline (Decompose -> Swarm -> Goal -> Comm -> Orchestrate -> Validate)")


