def test_chain16_intelligent_task_pipeline():
    """Chain 16: Intelligent Task Pipeline -- PriorityQueue -> Transform -> Learning -> Audit.

    Flow: Enqueue prioritized task -> transform data -> track learning -> audit log.
    """
    bus = PipelineIntegrationBus()

    pq = AgentPriorityQueue()
    dt = PipelineDataTransformer()
    lt = AgentLearningTracker()
    al = PipelineAuditLogger()

    # Setup
    dt.register_transform("normalize", lambda x: x.strip().lower())
    lt.register_agent("worker-1")

    def step_enqueue(ctx):
        eid = pq.enqueue("worker-1", "task-alpha", priority=10, payload={"data": "  HELLO WORLD  "})
        ctx["entry_id"] = eid
        task = pq.dequeue("worker-1")
        ctx["task_data"] = task["payload"]["data"]
        ctx["task_priority"] = task["priority"]
        return ctx

    def step_transform(ctx):
        result = dt.apply("normalize", ctx["task_data"])
        ctx["transformed"] = result["result"]
        ctx["transform_success"] = result["success"]
        return ctx

    def step_learn(ctx):
        lt.record_learning("worker-1", "text_processing", 0.7)
        lt.record_learning("worker-1", "text_processing", 0.85)
        prog = lt.get_skill_progress("worker-1", "text_processing")
        ctx["learning_trend"] = prog["trend"]
        ctx["improvement_rate"] = prog["improvement_rate"]
        return ctx

    def step_audit(ctx):
        eid = al.log("task_completed", "worker-1", "task-alpha",
                     severity="info",
                     details={"result": ctx["transformed"], "priority": ctx["task_priority"]})
        ctx["audit_id"] = eid
        history = al.get_actor_history("worker-1")
        ctx["audit_count"] = len(history)
        return ctx

    bus.register_chain("intelligent_task", tags=["phase8"])
    bus.add_step("intelligent_task", "enqueue", step_enqueue, "priority_queue")
    bus.add_step("intelligent_task", "transform", step_transform, "data_transformer")
    bus.add_step("intelligent_task", "learn", step_learn, "learning_tracker")
    bus.add_step("intelligent_task", "audit", step_audit, "audit_logger")

    result = bus.execute("intelligent_task", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["transformed"] == "hello world"
    assert result["context"]["transform_success"] is True
    assert result["context"]["improvement_rate"] > 0
    assert result["context"]["audit_count"] >= 1
    print("OK: Chain 16 - Intelligent task (PriorityQueue->Transform->Learning->Audit)")


def test_chain17_audited_learning_pipeline():
    """Chain 17: Audited Learning Pipeline -- 8 steps across 8 modules.

    Flow: Match skill -> Enqueue task -> Rate limit -> Transform -> Execute & learn ->
          Store memory -> Audit -> Health report.
    """
    bus = PipelineIntegrationBus()

    sm = AgentSkillMatcher()
    pq = AgentPriorityQueue()
    rl = PipelineRateLimiter()
    dt = PipelineDataTransformer()
    lt = AgentLearningTracker()
    ms = AgentMemoryStore()
    al = PipelineAuditLogger()
    ha = PipelineHealthAggregator()

    # Setup
    sm.register_agent("ml-agent-1", tags=["ml"])
    sm.add_skill("ml-agent-1", "data_analysis", proficiency=90.0)
    sm.create_task_profile("analyze_data", required_skills=["data_analysis"])
    dt.register_transform("double", lambda x: x * 2)
    lt.register_agent("ml-agent-1")

    def step1_match(ctx):
        best = sm.get_best_match("analyze_data")
        ctx["agent"] = best["agent_id"]
        ctx["match_score"] = best["match_score"]
        return ctx

    def step2_enqueue(ctx):
        eid = pq.enqueue(ctx["agent"], "analysis-job", priority=8, payload={"value": 42})
        ctx["queue_entry"] = eid
        task = pq.dequeue(ctx["agent"])
        ctx["input_value"] = task["payload"]["value"]
        return ctx

    def step3_rate_check(ctx):
        rl.create_limiter("analysis_limiter", strategy="token_bucket", max_rate=20.0, burst=20)
        result = rl.acquire("analysis_limiter")
        ctx["rate_ok"] = result["allowed"]
        return ctx

    def step4_transform(ctx):
        result = dt.apply("double", ctx["input_value"])
        ctx["doubled_value"] = result["result"]
        return ctx

    def step5_learn(ctx):
        lt.record_learning(ctx["agent"], "data_analysis", 0.75)
        lt.record_learning(ctx["agent"], "data_analysis", 0.90)
        prog = lt.get_skill_progress(ctx["agent"], "data_analysis")
        ctx["skill_improvement"] = prog["improvement_rate"]
        return ctx

    def step6_memory(ctx):
        ms.store_memory(ctx["agent"], "last_job", {
            "input": ctx["input_value"],
            "output": ctx["doubled_value"],
            "improvement": ctx["skill_improvement"],
        })
        ctx["memory_saved"] = ms.recall(ctx["agent"], "last_job") is not None
        return ctx

    def step7_audit(ctx):
        al.log("analysis_completed", ctx["agent"], "analysis-job",
               severity="info",
               details={"input": ctx["input_value"], "output": ctx["doubled_value"]})
        summary = al.get_summary()
        ctx["total_audits"] = summary["total_entries"]
        return ctx

    def step8_health(ctx):
        ha.register_component("learning_pipeline", component_type="pipeline")
        ha.report_health("learning_pipeline", status="healthy", latency=12.0)
        health = ha.get_system_health()
        ctx["system_health"] = health["health_score"]
        return ctx

    bus.register_chain("audited_learning", tags=["phase8"])
    bus.add_step("audited_learning", "match", step1_match, "skill_matcher")
    bus.add_step("audited_learning", "enqueue", step2_enqueue, "priority_queue")
    bus.add_step("audited_learning", "rate_check", step3_rate_check, "rate_limiter")
    bus.add_step("audited_learning", "transform", step4_transform, "data_transformer")
    bus.add_step("audited_learning", "learn", step5_learn, "learning_tracker")
    bus.add_step("audited_learning", "memory", step6_memory, "memory_store")
    bus.add_step("audited_learning", "audit", step7_audit, "audit_logger")
    bus.add_step("audited_learning", "health", step8_health, "health_agg")

    result = bus.execute("audited_learning", {})
    assert result["success"] is True
    assert result["steps_completed"] == 8
    assert result["context"]["agent"] == "ml-agent-1"
    assert result["context"]["doubled_value"] == 84
    assert result["context"]["rate_ok"] is True
    assert result["context"]["memory_saved"] is True
    assert result["context"]["total_audits"] >= 1
    assert result["context"]["system_health"] == 100.0
    print("OK: Chain 17 - Audited learning pipeline (8 steps across 8 modules)")


def test_chain18_schema_validated_workflow():
    """Chain 18: Schema-Validated Workflow -- Schema -> Allocate -> Workflow -> EventLog.

    Flow: Validate input schema -> allocate agent -> run workflow -> log events.
    """
    bus = PipelineIntegrationBus()

    sr = PipelineSchemaRegistry()
    ta = AgentTaskAllocator()
    we = AgentWorkflowEngine()
    el = PipelineEventLogger()

    # Setup
    sr.register_schema("task_input", {
        "name": {"type": "str", "required": True},
        "priority": {"type": "int", "required": True},
    }, tags=["core"])
    ta.register_agent("worker-1", capacity=10)
    ta.register_agent("worker-2", capacity=10)
    wid = we.create_workflow("process_task")
    we.add_step(wid, "process", lambda ctx: {**ctx, "processed": True})

    def step_validate(ctx):
        result = sr.validate("task_input", {"name": "build_feature", "priority": 5})
        ctx["schema_valid"] = result["valid"]
        ctx["validation_errors"] = result["errors"]
        return ctx

    def step_allocate(ctx):
        aid = ta.allocate("feature-build", priority=8)
        assignment = ta.get_assignment(aid)
        ctx["assigned_agent"] = assignment["agent_id"]
        ctx["assignment_id"] = aid
        return ctx

    def step_run_workflow(ctx):
        result = we.execute_workflow(wid, {"agent": ctx["assigned_agent"]})
        ctx["workflow_success"] = result["success"]
        ctx["workflow_steps"] = result["steps_completed"]
        return ctx

    def step_log_event(ctx):
        el.log_event("task_assigned", ctx["assigned_agent"],
                     data={"task": "feature-build", "workflow_success": ctx["workflow_success"]},
                     severity="info")
        ta.complete_task(ctx["assignment_id"])
        el.log_event("task_completed", ctx["assigned_agent"],
                     data={"task": "feature-build"},
                     severity="info")
        summary = el.get_summary()
        ctx["total_events"] = summary["total_events"]
        return ctx

    bus.register_chain("schema_validated_workflow", tags=["phase9"])
    bus.add_step("schema_validated_workflow", "validate", step_validate, "schema_registry")
    bus.add_step("schema_validated_workflow", "allocate", step_allocate, "task_allocator")
    bus.add_step("schema_validated_workflow", "workflow", step_run_workflow, "workflow_engine")
    bus.add_step("schema_validated_workflow", "log", step_log_event, "event_logger")

    result = bus.execute("schema_validated_workflow", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["schema_valid"] is True
    assert result["context"]["workflow_success"] is True
    assert result["context"]["total_events"] >= 2
    print("OK: Chain 18 - Schema-validated workflow (Schema->Allocate->Workflow->EventLog)")


def test_chain19_full_orchestrated_pipeline():
    """Chain 19: Full Orchestrated Pipeline -- 10 steps across Phase 8+9 modules.

    Flow: Validate -> Enqueue -> Allocate -> Transform -> Workflow -> Learn ->
          Audit -> EventLog -> Schema check -> Health.
    """
    bus = PipelineIntegrationBus()

    sr = PipelineSchemaRegistry()
    pq = AgentPriorityQueue()
    ta = AgentTaskAllocator()
    dt = PipelineDataTransformer()
    we = AgentWorkflowEngine()
    lt = AgentLearningTracker()
    al = PipelineAuditLogger()
    el = PipelineEventLogger()
    ha = PipelineHealthAggregator()

    # Setup
    sr.register_schema("job_input", {
        "value": {"type": "int", "required": True},
    })
    ta.register_agent("processor-1", capacity=20)
    dt.register_transform("triple", lambda x: x * 3)
    wid = we.create_workflow("compute")
    we.add_step(wid, "compute", lambda ctx: {**ctx, "computed": True})
    lt.register_agent("processor-1")

    def step1_validate(ctx):
        r = sr.validate("job_input", {"value": 7})
        ctx["valid"] = r["valid"]
        return ctx

    def step2_enqueue(ctx):
        eid = pq.enqueue("processor-1", "compute-job", priority=9, payload={"value": 7})
        task = pq.dequeue("processor-1")
        ctx["input_value"] = task["payload"]["value"]
        return ctx

    def step3_allocate(ctx):
        aid = ta.allocate("compute-job", priority=9)
        ctx["assignment"] = ta.get_assignment(aid)["agent_id"]
        ctx["assignment_id"] = aid
        return ctx

    def step4_transform(ctx):
        r = dt.apply("triple", ctx["input_value"])
        ctx["transformed"] = r["result"]
        return ctx

    def step5_workflow(ctx):
        r = we.execute_workflow(wid, {"val": ctx["transformed"]})
        ctx["workflow_ok"] = r["success"]
        return ctx

    def step6_learn(ctx):
        lt.record_learning("processor-1", "computation", 0.8)
        lt.record_learning("processor-1", "computation", 0.95)
        prog = lt.get_skill_progress("processor-1", "computation")
        ctx["learning_rate"] = prog["improvement_rate"]
        return ctx

    def step7_audit(ctx):
        al.log("computation_done", "processor-1", "compute-job",
               severity="info", details={"result": ctx["transformed"]})
        ctx["audited"] = True
        return ctx

    def step8_event_log(ctx):
        el.log_event("computation_completed", "processor-1",
                     data={"result": ctx["transformed"]}, severity="info")
        ctx["events_logged"] = el.get_summary()["total_events"]
        return ctx

    def step9_complete(ctx):
        ta.complete_task(ctx["assignment_id"])
        wl = ta.get_agent_workload("processor-1")
        ctx["agent_utilization"] = wl["utilization"]
        return ctx

    def step10_health(ctx):
        ha.register_component("orchestrated_pipeline", component_type="pipeline")
        ha.report_health("orchestrated_pipeline", status="healthy")
        ctx["health"] = ha.get_system_health()["health_score"]
        return ctx

    bus.register_chain("full_orchestrated", tags=["phase9"])
    bus.add_step("full_orchestrated", "validate", step1_validate, "schema")
    bus.add_step("full_orchestrated", "enqueue", step2_enqueue, "priority_queue")
    bus.add_step("full_orchestrated", "allocate", step3_allocate, "allocator")
    bus.add_step("full_orchestrated", "transform", step4_transform, "transformer")
    bus.add_step("full_orchestrated", "workflow", step5_workflow, "workflow_engine")
    bus.add_step("full_orchestrated", "learn", step6_learn, "learning")
    bus.add_step("full_orchestrated", "audit", step7_audit, "audit_logger")
    bus.add_step("full_orchestrated", "event_log", step8_event_log, "event_logger")
    bus.add_step("full_orchestrated", "complete", step9_complete, "allocator")
    bus.add_step("full_orchestrated", "health", step10_health, "health_agg")

    result = bus.execute("full_orchestrated", {})
    assert result["success"] is True
    assert result["steps_completed"] == 10
    assert result["context"]["valid"] is True
    assert result["context"]["transformed"] == 21  # 7 * 3
    assert result["context"]["workflow_ok"] is True
    assert result["context"]["learning_rate"] > 0
    assert result["context"]["audited"] is True
    assert result["context"]["events_logged"] >= 1
    assert result["context"]["health"] == 100.0
    print("OK: Chain 19 - Full orchestrated pipeline (10 steps across 9 modules)")


def test_chain20_capability_tracked_pipeline():
    """Chain 20: Capability-Tracked Pipeline -- Capability -> Config -> StageTracker -> ExecRecord -> EventLog."""
    bus = PipelineIntegrationBus()

    caps = AgentCapabilityStore()
    cs = AgentConfigStore()
    st = PipelineStageTracker()
    er = PipelineExecutionRecord()
    el = PipelineEventLogger()

    caps.register_agent("expert-1", tags=["ml"])
    caps.add_capability("expert-1", "data_science", level=0.95)
    caps.register_agent("junior-1")
    caps.add_capability("junior-1", "data_science", level=0.4)
    cs.set("expert-1", "runtime", "max_memory", 8192)
    pid = st.create_pipeline("analysis", stages=["prepare", "analyze", "report"])

    def step_find_agent(ctx):
        best = caps.get_best_agent("data_science")
        ctx["agent"] = best["agent_id"]
        ctx["capability_level"] = best["level"]
        return ctx

    def step_load_config(ctx):
        ctx["max_memory"] = cs.get(ctx["agent"], "runtime", "max_memory", default=4096)
        return ctx

    def step_track_stages(ctx):
        eid = st.start_stage(pid, "prepare")
        st.complete_stage(eid)
        eid2 = st.start_stage(pid, "analyze")
        st.complete_stage(eid2)
        prog = st.get_pipeline_progress(pid)
        ctx["stages_completed"] = prog["completed"]
        return ctx

    def step_record(ctx):
        eid = er.start_execution("analysis_pipeline", context={"agent": ctx["agent"]})
        er.complete_execution(eid, result={"stages": ctx["stages_completed"]})
        ctx["exec_recorded"] = True
        return ctx

    def step_log(ctx):
        el.log_event("pipeline_completed", ctx["agent"],
                     data={"stages": ctx["stages_completed"]}, severity="info")
        ctx["events_total"] = el.get_summary()["total_events"]
        return ctx

    bus.register_chain("capability_tracked", tags=["phase10"])
    bus.add_step("capability_tracked", "find_agent", step_find_agent, "capability_store")
    bus.add_step("capability_tracked", "load_config", step_load_config, "config_store")
    bus.add_step("capability_tracked", "track_stages", step_track_stages, "stage_tracker")
    bus.add_step("capability_tracked", "record", step_record, "exec_record")
    bus.add_step("capability_tracked", "log", step_log, "event_logger")

    result = bus.execute("capability_tracked", {})
    assert result["success"] is True
    assert result["steps_completed"] == 5
    assert result["context"]["agent"] == "expert-1"
    assert result["context"]["capability_level"] == 0.95
    assert result["context"]["max_memory"] == 8192
    assert result["context"]["stages_completed"] >= 2
    assert result["context"]["exec_recorded"] is True
    print("OK: Chain 20 - Capability-tracked pipeline (5 steps across 5 modules)")


def test_chain21_grand_pipeline():
    """Chain 21: Grand Pipeline -- 12 steps across 12 Phase 8-10 modules."""
    bus = PipelineIntegrationBus()

    sr = PipelineSchemaRegistry()
    pq = AgentPriorityQueue()
    ta = AgentTaskAllocator()
    dt = PipelineDataTransformer()
    we = AgentWorkflowEngine()
    lt = AgentLearningTracker()
    al = PipelineAuditLogger()
    el = PipelineEventLogger()
    caps = AgentCapabilityStore()
    cs = AgentConfigStore()
    st = PipelineStageTracker()
    er = PipelineExecutionRecord()

    sr.register_schema("job", {"value": {"type": "int", "required": True}})
    caps.register_agent("super-agent")
    caps.add_capability("super-agent", "compute", level=0.99)
    ta.register_agent("super-agent", capacity=50)
    cs.set("super-agent", "limits", "max_ops", 1000)
    dt.register_transform("square", lambda x: x ** 2)
    wid = we.create_workflow("compute_job")
    we.add_step(wid, "run", lambda ctx: {**ctx, "ran": True})
    lt.register_agent("super-agent")
    gpid = st.create_pipeline("grand", stages=["init", "compute", "finalize"])

    def s1(ctx):
        ctx["valid"] = sr.validate("job", {"value": 5})["valid"]
        ctx["input_value"] = 5
        return ctx

    def s2(ctx):
        ctx["agent"] = caps.get_best_agent("compute")["agent_id"]
        return ctx

    def s3(ctx):
        ctx["max_ops"] = cs.get(ctx["agent"], "limits", "max_ops", default=100)
        return ctx

    def s4(ctx):
        pq.enqueue(ctx["agent"], "grand-job", priority=10, payload={"value": ctx["input_value"]})
        ctx["queued_value"] = pq.dequeue(ctx["agent"])["payload"]["value"]
        return ctx

    def s5(ctx):
        ctx["assignment_id"] = ta.allocate("grand-job", agent_id=ctx["agent"], priority=10)
        return ctx

    def s6(ctx):
        ctx["squared"] = dt.apply("square", ctx["queued_value"])["result"]
        return ctx

    def s7(ctx):
        ctx["workflow_ok"] = we.execute_workflow(wid, {"val": ctx["squared"]})["success"]
        return ctx

    def s8(ctx):
        lt.record_learning(ctx["agent"], "computation", 0.85)
        lt.record_learning(ctx["agent"], "computation", 0.95)
        ctx["improvement"] = lt.get_skill_progress(ctx["agent"], "computation")["improvement_rate"]
        return ctx

    def s9(ctx):
        eid = st.start_stage(gpid, "init")
        st.complete_stage(eid)
        eid2 = st.start_stage(gpid, "compute")
        st.complete_stage(eid2)
        ctx["stages_done"] = st.get_pipeline_progress(gpid)["completed"]
        return ctx

    def s10(ctx):
        eid = er.start_execution("grand_pipeline", context={"agent": ctx["agent"]})
        er.complete_execution(eid, result={"squared": ctx["squared"]})
        ctx["exec_recorded"] = True
        return ctx

    def s11(ctx):
        al.log("grand_completed", ctx["agent"], "grand-job",
               severity="info", details={"result": ctx["squared"]})
        ctx["audited"] = True
        return ctx

    def s12(ctx):
        el.log_event("grand_done", ctx["agent"],
                     data={"result": ctx["squared"]}, severity="info")
        ta.complete_task(ctx["assignment_id"])
        ctx["final_events"] = el.get_summary()["total_events"]
        return ctx

    bus.register_chain("grand_pipeline", tags=["phase10"])
    bus.add_step("grand_pipeline", "schema", s1, "schema_registry")
    bus.add_step("grand_pipeline", "capability", s2, "capability_store")
    bus.add_step("grand_pipeline", "config", s3, "config_store")
    bus.add_step("grand_pipeline", "enqueue", s4, "priority_queue")
    bus.add_step("grand_pipeline", "allocate", s5, "task_allocator")
    bus.add_step("grand_pipeline", "transform", s6, "data_transformer")
    bus.add_step("grand_pipeline", "workflow", s7, "workflow_engine")
    bus.add_step("grand_pipeline", "learn", s8, "learning_tracker")
    bus.add_step("grand_pipeline", "stage_track", s9, "stage_tracker")
    bus.add_step("grand_pipeline", "exec_record", s10, "exec_record")
    bus.add_step("grand_pipeline", "audit", s11, "audit_logger")
    bus.add_step("grand_pipeline", "event_log", s12, "event_logger")

    result = bus.execute("grand_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 12
    assert result["context"]["valid"] is True
    assert result["context"]["agent"] == "super-agent"
    assert result["context"]["squared"] == 25
    assert result["context"]["workflow_ok"] is True
    assert result["context"]["improvement"] > 0
    assert result["context"]["stages_done"] >= 2
    assert result["context"]["exec_recorded"] is True
    assert result["context"]["audited"] is True
    assert result["context"]["final_events"] >= 1
    print("OK: Chain 21 - Grand pipeline (12 steps across 12 modules!)")


def test_chain22_cached_health_pipeline():
    """Chain 22: Cached Health Pipeline -- InputSchema -> Cache -> EventStore -> HealthStore.

    Flow: Validate+coerce input -> cache result -> record events -> report health.
    """
    bus = PipelineIntegrationBus()

    pis = PipelineInputSchema()
    rc = PipelineResultCache()
    aes = AgentEventStore()
    ahs = AgentHealthStore()

    pis.define_input("health_check", {
        "agent_id": {"type": "str", "required": True},
        "cpu": {"type": "float", "required": True},
        "healthy": {"type": "bool", "required": False, "default": True},
    })
    ahs.register_agent("monitor-1")

    def step_validate(ctx):
        r = pis.validate_input("health_check", {"agent_id": "monitor-1", "cpu": "45.5"})
        ctx["valid"] = r["valid"]
        ctx["coerced"] = r["coerced"]
        return ctx

    def step_cache(ctx):
        rc.put("last_health", ctx["coerced"], ttl_seconds=60)
        cached = rc.get("last_health")
        ctx["cached"] = cached is not None
        return ctx

    def step_record_event(ctx):
        aes.record(ctx["coerced"]["agent_id"], "health_check",
                   data={"cpu": ctx["coerced"]["cpu"]}, severity="info")
        ctx["event_count"] = aes.get_event_count(agent_id=ctx["coerced"]["agent_id"])
        return ctx

    def step_health(ctx):
        ahs.record_heartbeat("monitor-1")
        ahs.report_health("monitor-1", status="healthy", details={"cpu": ctx["coerced"]["cpu"]})
        sys_h = ahs.get_system_health()
        ctx["system_healthy"] = sys_h["health_pct"] == 100.0
        return ctx

    bus.register_chain("cached_health", tags=["phase11"])
    bus.add_step("cached_health", "validate", step_validate, "input_schema")
    bus.add_step("cached_health", "cache", step_cache, "result_cache")
    bus.add_step("cached_health", "record", step_record_event, "event_store")
    bus.add_step("cached_health", "health", step_health, "health_store")

    result = bus.execute("cached_health", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["valid"] is True
    assert result["context"]["cached"] is True
    assert result["context"]["event_count"] >= 1
    assert result["context"]["system_healthy"] is True
    print("OK: Chain 22 - Cached health pipeline (InputSchema->Cache->EventStore->HealthStore)")


def test_chain23_full_observable_pipeline():
    """Chain 23: Full Observable Pipeline -- 8 steps across Phase 11 + earlier modules.

    Combines event store, result cache, health store, input schema with earlier modules.
    """
    bus = PipelineIntegrationBus()

    pis = PipelineInputSchema()
    rc = PipelineResultCache()
    aes = AgentEventStore()
    ahs = AgentHealthStore()
    dt = PipelineDataTransformer()
    el = PipelineEventLogger()
    er = PipelineExecutionRecord()
    ha = PipelineHealthAggregator()

    pis.define_input("compute", {"value": {"type": "int", "required": True}})
    dt.register_transform("double", lambda x: x * 2)
    ahs.register_agent("compute-agent")

    def s1(ctx):
        r = pis.validate_input("compute", {"value": "10"})
        ctx["input_value"] = r["coerced"]["value"]
        return ctx

    def s2(ctx):
        cached = rc.get("compute_10")
        if cached is not None:
            ctx["result"] = cached
            ctx["cache_hit"] = True
        else:
            r = dt.apply("double", ctx["input_value"])
            ctx["result"] = r["result"]
            rc.put("compute_10", ctx["result"], ttl_seconds=60)
            ctx["cache_hit"] = False
        return ctx

    def s3(ctx):
        aes.record("compute-agent", "computation",
                   data={"input": ctx["input_value"], "result": ctx["result"]},
                   severity="info")
        ctx["events"] = aes.get_event_count(agent_id="compute-agent")
        return ctx

    def s4(ctx):
        exec_id = er.start_execution("observable_pipeline", context={"value": ctx["input_value"]})
        er.complete_execution(exec_id, result={"output": ctx["result"]})
        ctx["exec_recorded"] = True
        return ctx

    def s5(ctx):
        el.log_event("computation_done", "compute-agent",
                     data={"result": ctx["result"]}, severity="info")
        ctx["pipeline_events"] = el.get_summary()["total_events"]
        return ctx

    def s6(ctx):
        ahs.record_heartbeat("compute-agent")
        ahs.report_health("compute-agent", status="healthy")
        ctx["agent_healthy"] = ahs.get_health("compute-agent")["status"] == "healthy"
        return ctx

    def s7(ctx):
        ha.register_component("observable_pipeline", component_type="pipeline")
        ha.report_health("observable_pipeline", status="healthy")
        ctx["system_health"] = ha.get_system_health()["health_score"]
        return ctx

    def s8(ctx):
        cache_stats = rc.get_cache_stats()
        ctx["cache_entries"] = cache_stats["total_entries"]
        ctx["agent_events"] = aes.get_agent_summary("compute-agent")["total_events"]
        return ctx

    bus.register_chain("full_observable", tags=["phase11"])
    bus.add_step("full_observable", "validate", s1, "input_schema")
    bus.add_step("full_observable", "compute_cache", s2, "result_cache")
    bus.add_step("full_observable", "record_event", s3, "event_store")
    bus.add_step("full_observable", "exec_record", s4, "exec_record")
    bus.add_step("full_observable", "pipeline_log", s5, "event_logger")
    bus.add_step("full_observable", "agent_health", s6, "health_store")
    bus.add_step("full_observable", "system_health", s7, "health_agg")
    bus.add_step("full_observable", "summary", s8, "summary")

    result = bus.execute("full_observable", {})
    assert result["success"] is True
