def test_chain24_quota_rate_pipeline():
    """Chain 24: Quota & Rate Pipeline -- Quota -> Rate -> Steps -> Output.

    Flow: Check quota -> track rate -> execute step -> store output.
    """
    bus = PipelineIntegrationBus()

    qm = AgentQuotaManager()
    art = AgentRateTracker()
    psr = PipelineStepRegistry()
    pos = PipelineOutputStore()

    qm.set_quota("worker-1", "compute", 100)
    art.register_agent("worker-1")
    psr.register_step("compute", lambda ctx: {**ctx, "computed": ctx.get("value", 0) * 3})

    def step_quota(ctx):
        r = qm.use_quota("worker-1", "compute", amount=1)
        ctx["quota_allowed"] = r["allowed"]
        ctx["quota_remaining"] = r["remaining"]
        return ctx

    def step_rate(ctx):
        art.record_operation("worker-1", "compute", success=True)
        rate = art.get_rate("worker-1", "compute")
        ctx["ops_total"] = rate["total_ops"]
        return ctx

    def step_execute(ctx):
        r = psr.execute_step("compute", {"value": 7})
        ctx["step_result"] = r["result"]["computed"]
        ctx["step_success"] = r["success"]
        return ctx

    def step_store(ctx):
        oid = pos.store("compute_pipeline", "exec-quota-1", {"result": ctx["step_result"]})
        ctx["output_stored"] = len(oid) > 0
        latest = pos.get_latest("compute_pipeline")
        ctx["latest_result"] = latest["output"]["result"]
        return ctx

    bus.register_chain("quota_rate", tags=["phase12"])
    bus.add_step("quota_rate", "quota", step_quota, "quota_manager")
    bus.add_step("quota_rate", "rate", step_rate, "rate_tracker")
    bus.add_step("quota_rate", "execute", step_execute, "step_registry")
    bus.add_step("quota_rate", "store", step_store, "output_store")

    result = bus.execute("quota_rate", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["quota_allowed"] is True
    assert result["context"]["step_result"] == 21
    assert result["context"]["output_stored"] is True
    assert result["context"]["latest_result"] == 21
    print("OK: Chain 24 - Quota & rate pipeline (Quota->Rate->Steps->Output)")


def test_chain25_ultimate_pipeline():
    """Chain 25: Ultimate Pipeline -- 14 steps across 14 modules.

    The biggest chain yet, combining Phase 8-12 modules.
    """
    bus = PipelineIntegrationBus()

    sr = PipelineSchemaRegistry()
    pq = AgentPriorityQueue()
    ta = AgentTaskAllocator()
    dt = PipelineDataTransformer()
    we = AgentWorkflowEngine()
    lt = AgentLearningTracker()
    al = PipelineAuditLogger()
    el = PipelineEventLogger()
    caps = AgentCapabilityStore()
    qm = AgentQuotaManager()
    art = AgentRateTracker()
    psr = PipelineStepRegistry()
    pos = PipelineOutputStore()
    ha = PipelineHealthAggregator()

    # Setup
    sr.register_schema("ultimate", {"value": {"type": "int", "required": True}})
    caps.register_agent("ultimate-agent")
    caps.add_capability("ultimate-agent", "everything", level=1.0)
    ta.register_agent("ultimate-agent", capacity=100)
    qm.set_quota("ultimate-agent", "ops", 1000)
    art.register_agent("ultimate-agent")
    dt.register_transform("cube", lambda x: x ** 3)
    psr.register_step("finalize", lambda ctx: {**ctx, "finalized": True})
    wid = we.create_workflow("ultimate")
    we.add_step(wid, "run", lambda ctx: {**ctx, "ran": True})
    lt.register_agent("ultimate-agent")

    steps = []
    def s1(ctx): ctx["valid"] = sr.validate("ultimate", {"value": 3})["valid"]; ctx["v"] = 3; return ctx
    def s2(ctx): ctx["agent"] = caps.get_best_agent("everything")["agent_id"]; return ctx
    def s3(ctx): ctx["quota_ok"] = qm.use_quota(ctx["agent"], "ops")["allowed"]; return ctx
    def s4(ctx): art.record_operation(ctx["agent"], "compute"); ctx["rated"] = True; return ctx
    def s5(ctx): pq.enqueue(ctx["agent"], "ult-job", priority=10, payload={"v": ctx["v"]}); ctx["queued"] = pq.dequeue(ctx["agent"])["payload"]["v"]; return ctx
    def s6(ctx): ctx["assign_id"] = ta.allocate("ult-job", agent_id=ctx["agent"]); return ctx
    def s7(ctx): ctx["cubed"] = dt.apply("cube", ctx["queued"])["result"]; return ctx
    def s8(ctx): ctx["wf_ok"] = we.execute_workflow(wid, {"val": ctx["cubed"]})["success"]; return ctx
    def s9(ctx): lt.record_learning(ctx["agent"], "compute", 0.9); lt.record_learning(ctx["agent"], "compute", 0.98); ctx["improved"] = lt.get_skill_progress(ctx["agent"], "compute")["improvement_rate"] > 0; return ctx
    def s10(ctx): ctx["step_ok"] = psr.execute_step("finalize", ctx)["success"]; return ctx
    def s11(ctx): al.log("ultimate_done", ctx["agent"], "ult-job", severity="info", details={"result": ctx["cubed"]}); ctx["audited"] = True; return ctx
    def s12(ctx): el.log_event("ultimate_complete", ctx["agent"], data={"result": ctx["cubed"]}, severity="info"); ctx["logged"] = True; return ctx
    def s13(ctx): pos.store("ultimate", "ult-exec", {"result": ctx["cubed"]}); ta.complete_task(ctx["assign_id"]); ctx["stored"] = True; return ctx
    def s14(ctx): ha.register_component("ultimate_pipeline", component_type="pipeline"); ha.report_health("ultimate_pipeline", status="healthy"); ctx["health"] = ha.get_system_health()["health_score"]; return ctx

    bus.register_chain("ultimate_pipeline", tags=["phase12"])
    for i, (name, fn) in enumerate([
        ("validate", s1), ("capability", s2), ("quota", s3), ("rate", s4),
        ("enqueue", s5), ("allocate", s6), ("transform", s7), ("workflow", s8),
        ("learn", s9), ("step_exec", s10), ("audit", s11), ("event_log", s12),
        ("store_output", s13), ("health", s14)
    ]):
        bus.add_step("ultimate_pipeline", name, fn, f"module_{i}")

    result = bus.execute("ultimate_pipeline", {})
    assert result["success"] is True
    assert result["steps_completed"] == 14
    assert result["context"]["valid"] is True
    assert result["context"]["agent"] == "ultimate-agent"
    assert result["context"]["cubed"] == 27
    assert result["context"]["wf_ok"] is True
    assert result["context"]["improved"] is True
    assert result["context"]["audited"] is True
    assert result["context"]["stored"] is True
    assert result["context"]["health"] == 100.0
    print("OK: Chain 25 - Ultimate pipeline (14 steps across 14 modules!)")


