# Chain 26: Permission-gated notification pipeline
#   PermissionStore -> NotificationStore -> MetricStore -> DependencyStore
# =====================================================================

def test_chain26_permission_notification_pipeline():
    """Permission check gates notification sending with metric tracking."""
    bus = PipelineIntegrationBus()
    perm_store = AgentPermissionStore()
    notif_store = PipelineNotificationStore()
    metric_store = AgentMetricStore()
    dep_store = PipelineDependencyStore()

    # Setup
    perm_store.create_role("notifier", permissions=["send", "read"])
    perm_store.assign_role("agent-1", "notifier")
    notif_store.create_channel("alerts")
    dep_store.register_stage("notify_pipe", "check_perm")
    dep_store.register_stage("notify_pipe", "send_notif")
    dep_store.add_dependency("notify_pipe", "send_notif", "check_perm")

    bus.register_chain("perm_notification")

    def s1(ctx):
        ctx["has_perm"] = perm_store.check_permission("agent-1", "send")
        return ctx

    def s2(ctx):
        if ctx["has_perm"]:
            nid = notif_store.send("alerts", "Deployment complete", severity="info")
            ctx["notification_id"] = nid
        return ctx

    def s3(ctx):
        metric_store.record("agent-1", "notifications_sent", 1.0, tags=["ops"])
        latest = metric_store.get_latest("agent-1", "notifications_sent")
        ctx["metric_recorded"] = latest is not None
        return ctx

    def s4(ctx):
        order = dep_store.get_execution_order("notify_pipe")
        ctx["dep_order"] = order
        ctx["deps_valid"] = order.index("check_perm") < order.index("send_notif")
        return ctx

    for i, (name, fn) in enumerate([
        ("check_perm", s1), ("send_notif", s2),
        ("track_metric", s3), ("verify_deps", s4)
    ]):
        bus.add_step("perm_notification", name, fn, f"module_{i}")

    result = bus.execute("perm_notification", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["has_perm"] is True
    assert len(result["context"]["notification_id"]) > 0
    assert result["context"]["metric_recorded"] is True
    assert result["context"]["deps_valid"] is True
    print("OK: Chain 26 - Permission-gated notification pipeline")


