    event_logger = PipelineEventLogger()
    config_store = AgentConfigStore()
    cap_store = AgentCapabilityStore()
    health_store = AgentHealthStore()
    output_store = PipelineOutputStore()

    # Setup
    perm_store.create_role("executor", permissions=["execute", "read", "write"])
    perm_store.assign_role("mega-agent", "executor")
    notif_store.create_channel("pipeline-events")
    dep_store.register_stage("mega", "init")
    dep_store.register_stage("mega", "process")
    dep_store.add_dependency("mega", "process", "init")
    allocator.register_agent("mega-agent", capacity=10)
    health_store.register_agent("mega-agent")
    cap_store.register_agent("mega-agent")
    cap_store.add_capability("mega-agent", "execution")
    learner.register_agent("mega-agent")

    bus.register_chain("mega_governed")

    def s1(ctx):
        ctx["permitted"] = perm_store.check_permission("mega-agent", "execute")
        return ctx

    def s2(ctx):
        metric_store.record("mega-agent", "pipeline_runs", 1.0)
        ctx["metric_ok"] = True
        return ctx

    def s3(ctx):
        nid = notif_store.send("pipeline-events", "Mega pipeline started", severity="info")
        ctx["notif_id"] = nid
        return ctx

    def s4(ctx):
        order = dep_store.get_execution_order("mega")
        ctx["dep_stages"] = len(order)
        return ctx

    def s5(ctx):
        pq.enqueue("mega-agent", "mega-task", priority=1, payload={"type": "mega"})
        item = pq.dequeue("mega-agent")
        ctx["dequeued"] = item is not None
        return ctx

    transformer.register_transform("double", lambda d: {"v": d.get("v", 1) * 2})

    def s6(ctx):
        r = transformer.apply("double", {"v": 5})
        ctx["transformed"] = r.get("result", {}).get("v", r.get("v", 0))
        return ctx

    def s7(ctx):
        learner.record_learning("mega-agent", "pipeline", score=0.9)
        ctx["learned"] = True
        return ctx

    def s8(ctx):
        auditor.log("mega-agent", "execute", "mega-pipeline", severity="info")
        ctx["audited"] = True
        return ctx

    schema_reg.register_schema("mega_input", {"fields": {"action": {"type": "string", "required": True}}})

    def s9(ctx):
        vr = schema_reg.validate("mega_input", {"action": "run"})
        ctx["schema_valid"] = vr.get("valid", False)
        return ctx

    def s10(ctx):
        tid = allocator.allocate("mega-task-2", agent_id="mega-agent")
        ctx["allocated"] = len(tid) > 0
        return ctx

    wf_id = workflow.create_workflow("mega_wf")
    workflow.add_step(wf_id, "init_step", lambda c: c)

    def s11(ctx):
        wr = workflow.execute_workflow(wf_id)
        ctx["wf_success"] = wr.get("success", False)
        return ctx

    def s12(ctx):
        event_logger.log_event("step_12", "mega", severity="info")
        ctx["event_logged"] = True
        return ctx

    def s13(ctx):
        config_store.set("mega-agent", "runtime", "mode", "production")
        val = config_store.get("mega-agent", "runtime", "mode")
        ctx["config_set"] = val == "production"
        return ctx

    def s14(ctx):
        ctx["has_capability"] = cap_store.has_capability("mega-agent", "execution")
        return ctx

    def s15(ctx):
        health_store.report_health("mega-agent", "healthy")
        sh = health_store.get_system_health()
        ctx["health_pct"] = sh.get("health_pct", 0)
        return ctx

    def s16(ctx):
        oid = output_store.store("mega_governed", "mega-exec-1", {"result": "success"}, tags=["mega"])
        ctx["output_stored"] = len(oid) > 0
        return ctx

    for i, (name, fn) in enumerate([
        ("check_perm", s1), ("record_metric", s2), ("notify", s3),
        ("check_deps", s4), ("enqueue", s5), ("transform", s6),
        ("learn", s7), ("audit", s8), ("validate_schema", s9),
        ("allocate", s10), ("workflow", s11), ("log_event", s12),
        ("configure", s13), ("check_capability", s14),
        ("health_check", s15), ("store_output", s16)
    ]):
        bus.add_step("mega_governed", name, fn, f"phase_module_{i}")

    result = bus.execute("mega_governed", {})
    assert result["success"] is True
    assert result["steps_completed"] == 16
    ctx = result["context"]
    assert ctx["permitted"] is True
    assert ctx["metric_ok"] is True
    assert len(ctx["notif_id"]) > 0
    assert ctx["dep_stages"] == 2
    assert ctx["dequeued"] is True
    assert ctx["transformed"] == 10
    assert ctx["learned"] is True
    assert ctx["audited"] is True
    assert ctx["schema_valid"] is True
    assert ctx["allocated"] is True
    assert ctx["wf_success"] is True
    assert ctx["event_logged"] is True
    assert ctx["config_set"] is True
    assert ctx["health_pct"] == 100.0
    assert ctx["output_stored"] is True
    print("OK: Chain 27 - Mega governed pipeline (16 steps across 16 modules!)")


