def test_chain28_session_versioned_pipeline():
    """Agent session gates template instantiation with version tracking and resource monitoring."""
    bus = PipelineIntegrationBus()
    session_store = AgentSessionStore()
    template_store = PipelineTemplateStore()
    version_store = PipelineVersionStore()
    resource_monitor = AgentResourceMonitor()

    # Setup
    template_store.create_template("deploy_v2", steps=["build", "test", "release"], tags=["ci"])

    bus.register_chain("session_versioned")

    def s1(ctx):
        sid = session_store.create_session("deploy-agent", metadata={"pipeline": "deploy_v2"})
        ctx["session_id"] = sid
        ctx["session_active"] = len(sid) > 0
        return ctx

    def s2(ctx):
        t = template_store.get_template_by_name("deploy_v2")
        if t:
            instance = template_store.instantiate(t["template_id"])
            ctx["template_name"] = instance["name"]
            ctx["template_steps"] = len(instance["steps"])
        return ctx

    def s3(ctx):
        vid = version_store.create_version("deploy_v2", config={"steps": ["build", "test", "release"]}, description="v1 deploy")
        version_store.activate_version("deploy_v2", vid)
        active = version_store.get_active_version("deploy_v2")
        ctx["version_active"] = active is not None
        ctx["version_id"] = vid
        return ctx

    def s4(ctx):
        resource_monitor.record_usage("deploy-agent", "cpu", 35.0, unit="%")
        resource_monitor.record_usage("deploy-agent", "memory", 512.0, unit="MB")
        resource_monitor.set_threshold("deploy-agent", "cpu", 90.0)
        check = resource_monitor.check_threshold("deploy-agent", "cpu")
        ctx["resource_ok"] = not check["exceeded"]
        return ctx

    for i, (name, fn) in enumerate([
        ("create_session", s1), ("load_template", s2),
        ("track_version", s3), ("monitor_resources", s4)
    ]):
        bus.add_step("session_versioned", name, fn, f"module_{i}")

    result = bus.execute("session_versioned", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["session_active"] is True
    assert result["context"]["template_name"] == "deploy_v2"
    assert result["context"]["template_steps"] == 3
    assert result["context"]["version_active"] is True
    assert result["context"]["resource_ok"] is True
    print("OK: Chain 28 - Session-managed versioned pipeline")


