# =====================================================================
# Chain 30: Feedback-driven scheduled pipeline
#   FeedbackStore -> ScheduleStore -> CacheStore -> AlertStore
# =====================================================================

def test_chain30_feedback_scheduled_pipeline():
    """Feedback triggers schedule check, caches result, alerts on issues."""
    bus = PipelineIntegrationBus()
    feedback_store = AgentFeedbackStore()
    schedule_store = PipelineScheduleStore()
    cache_store = AgentCacheStore()
    alert_store = PipelineAlertStore()

    # Setup
    schedule_store.create_schedule("quality_check", interval_seconds=0)

    bus.register_chain("feedback_scheduled")

    def s1(ctx):
        fid = feedback_store.submit_feedback("agent-1", "system", 2, comment="Poor performance", category="quality")
        ctx["feedback_id"] = fid
        ctx["low_rating"] = True
        return ctx

    def s2(ctx):
        due = schedule_store.get_due_schedules()
        ctx["schedules_due"] = len(due)
        if due:
            schedule_store.mark_run(due[0]["schedule_id"])
        return ctx

    def s3(ctx):
        cache_store.put("agent-1", "last_feedback", ctx["feedback_id"], namespace="feedback")
        cached = cache_store.get("agent-1", "last_feedback", namespace="feedback")
        ctx["cached"] = cached == ctx["feedback_id"]
        return ctx

    def s4(ctx):
        if ctx["low_rating"]:
            aid = alert_store.create_alert("quality_check", "low_rating", "warning", "Agent rated below threshold")
            ctx["alert_id"] = aid
            ctx["alert_created"] = len(aid) > 0
        return ctx

    for i, (name, fn) in enumerate([
        ("collect_feedback", s1), ("check_schedule", s2),
        ("cache_result", s3), ("raise_alert", s4)
    ]):
        bus.add_step("feedback_scheduled", name, fn, f"module_{i}")

    result = bus.execute("feedback_scheduled", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert len(result["context"]["feedback_id"]) > 0
    assert result["context"]["schedules_due"] >= 1
    assert result["context"]["cached"] is True
    assert result["context"]["alert_created"] is True
    print("OK: Chain 30 - Feedback-driven scheduled pipeline")


