# =====================================================================
# Chain 32: Logged locked tagged pipeline
#   LogStore -> LockStore -> TagStore -> WebhookStore
# =====================================================================

def test_chain32_logged_locked_pipeline():
    """Logs action, acquires lock, tags agent, fires webhook."""
    bus = PipelineIntegrationBus()
    log_store = AgentLogStore()
    lock_store = PipelineLockStore()
    tag_store = AgentTagStore()
    webhook_store = PipelineWebhookStore()

    # Setup
    webhook_store.register_webhook("tagged_pipeline", "https://hooks.example.com/tagged", events=["complete"])

    bus.register_chain("logged_locked")

    def s1(ctx):
        lid = log_store.log("agent-1", "info", "Pipeline started", context={"chain": "logged_locked"})
        ctx["log_id"] = lid
        return ctx

    def s2(ctx):
        lock_id = lock_store.acquire("deploy-resource", "agent-1", ttl=60)
        ctx["lock_acquired"] = len(lock_id) > 0
        ctx["lock_id"] = lock_id
        return ctx

    def s3(ctx):
        tag_store.add_tag("agent-1", "active-pipeline")
        ctx["tagged"] = tag_store.has_tag("agent-1", "active-pipeline")
        return ctx

    def s4(ctx):
        count = webhook_store.fire_event("tagged_pipeline", "complete", payload={"status": "ok"})
        ctx["webhooks_fired"] = count
        lock_store.release("deploy-resource", "agent-1")
        return ctx

    for i, (name, fn) in enumerate([
        ("log_start", s1), ("acquire_lock", s2),
        ("tag_agent", s3), ("fire_webhook", s4)
    ]):
        bus.add_step("logged_locked", name, fn, f"module_{i}")

    result = bus.execute("logged_locked", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert len(result["context"]["log_id"]) > 0
    assert result["context"]["lock_acquired"] is True
    assert result["context"]["tagged"] is True
    assert result["context"]["webhooks_fired"] == 1
    print("OK: Chain 32 - Logged locked tagged pipeline")


