# Chain 34: Heartbeat-checkpoint-group pipeline
#   HeartbeatStore -> CheckpointStore -> GroupStore -> VariableStore
# =====================================================================

def test_chain34_heartbeat_checkpoint_pipeline():
    """Agent heartbeats, saves checkpoint, joins group, reads variables."""
    bus = PipelineIntegrationBus()
    hb_store = AgentHeartbeatStore()
    cp_store = PipelineCheckpointStore()
    group_store = AgentGroupStore()
    var_store = PipelineVariableStore()

    # Setup
    hb_store.register("worker-1", interval_seconds=300)
    gid = group_store.create_group("workers", description="Worker pool")
    var_store.set_variable("deploy", "env", "production")

    bus.register_chain("heartbeat_checkpoint")

    def s1(ctx):
        hb_store.beat("worker-1")
        ctx["alive"] = hb_store.check_alive("worker-1")
        return ctx

    def s2(ctx):
        cid = cp_store.save_checkpoint("deploy", "exec-1", "step1", {"progress": 50})
        ctx["checkpoint_id"] = cid
        return ctx

    def s3(ctx):
        group_store.add_member(gid, "worker-1")
        ctx["in_group"] = "worker-1" in group_store.get_members(gid)
        return ctx

    def s4(ctx):
        ctx["env"] = var_store.get_variable("deploy", "env")
        return ctx

    for i, (name, fn) in enumerate([
        ("heartbeat", s1), ("checkpoint", s2),
        ("join_group", s3), ("read_vars", s4)
    ]):
        bus.add_step("heartbeat_checkpoint", name, fn, f"module_{i}")

    result = bus.execute("heartbeat_checkpoint", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["alive"] is True
    assert len(result["context"]["checkpoint_id"]) > 0
    assert result["context"]["in_group"] is True
    assert result["context"]["env"] == "production"
    print("OK: Chain 34 - Heartbeat-checkpoint-group pipeline")


