# =====================================================================
# Chain 36: Delegation-trigger-skill pipeline (Phase 18 core)
#   DelegationStore -> TriggerStore -> SkillStore -> ArtifactStore
# =====================================================================

def test_chain36_delegation_trigger_pipeline():
    """Agent delegates task, trigger fires, skill matched, artifact stored."""
    bus = PipelineIntegrationBus()
    deleg_store = AgentDelegationStore()
    trigger_store = PipelineTriggerStore()
    skill_store = AgentSkillStore()
    artifact_store = PipelineArtifactStore()

    # Setup
    skill_store.add_skill("worker-1", "python", proficiency=0.9)
    tid = trigger_store.create_trigger("build", "delegation_complete")

    bus.register_chain("delegation_trigger")

    def s1(ctx):
        did = deleg_store.delegate("manager", "worker-1", "build module", priority="high")
        ctx["delegation_id"] = did
        deleg_store.accept(did)
        return ctx

    def s2(ctx):
        fr = trigger_store.fire_trigger(tid, context={"delegation": ctx["delegation_id"]})
        ctx["fired"] = fr is not None
        return ctx

    def s3(ctx):
        agents = skill_store.find_agents_with_skill("python", min_proficiency=0.5)
        ctx["skilled_agent"] = agents[0]["agent_id"] if agents else None
        return ctx

    def s4(ctx):
        deleg_store.complete(ctx["delegation_id"], result={"output": "module built"})
        aid = artifact_store.store_artifact("build", "exec-1", "module.py", "print('hello')", artifact_type="source")
        ctx["artifact_id"] = aid
        return ctx

    for i, (name, fn) in enumerate([
        ("delegate", s1), ("fire_trigger", s2),
        ("match_skill", s3), ("store_artifact", s4)
    ]):
        bus.add_step("delegation_trigger", name, fn, f"module_{i}")

    result = bus.execute("delegation_trigger", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["fired"] is True
    assert result["context"]["skilled_agent"] == "worker-1"
    assert len(result["context"]["artifact_id"]) > 0
    d = deleg_store.get_delegation(result["context"]["delegation_id"])
    assert d["status"] == "completed"
    print("OK: Chain 36 - Delegation-trigger-skill pipeline")


