# =====================================================================
# Chain 38: Profile-queue-context pipeline (Phase 19 core)
#   ProfileStore -> QueueStore -> ContextCache -> RoutingStore
# =====================================================================

def test_chain38_profile_queue_pipeline():
    """Agent creates profile, queues work, stores context, routes pipeline."""
    bus = PipelineIntegrationBus()
    profile_store = AgentProfileStore()
    queue_store = PipelineQueueStore()
    context_cache = AgentContextCache()
    routing_store = PipelineRoutingStore()

    # Setup routing
    routing_store.add_rule("deploy", "default", "us-east-cluster", priority=5)
    routing_store.add_rule("deploy", "priority", "fast-cluster", priority=10)

    bus.register_chain("profile_queue")

    def s1(ctx):
        pid = profile_store.create_profile("worker-1", display_name="Worker One", role="deployer")
        ctx["profile_id"] = pid
        return ctx

    def s2(ctx):
        eid = queue_store.enqueue("deploy", params={"version": "2.0"}, priority=1)
        ctx["queue_entry"] = eid
        return ctx

    def s3(ctx):
        cid = context_cache.store_context("worker-1", "task", {"action": "deploy", "entry": ctx["queue_entry"]})
        ctx["context_id"] = cid
        return ctx

    def s4(ctx):
        target = routing_store.resolve_route("deploy")
        ctx["route_target"] = target
        item = queue_store.dequeue()
        if item:
            queue_store.complete(item["entry_id"] if "entry_id" in item else ctx["queue_entry"])
        ctx["dequeued"] = item is not None
        return ctx

    for i, (name, fn) in enumerate([
        ("create_profile", s1), ("enqueue_work", s2),
        ("store_context", s3), ("route_and_process", s4)
    ]):
        bus.add_step("profile_queue", name, fn, f"module_{i}")

    result = bus.execute("profile_queue", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert len(result["context"]["profile_id"]) > 0
    assert result["context"]["route_target"] == "fast-cluster"
    assert result["context"]["dequeued"] is True
    print("OK: Chain 38 - Profile-queue-context pipeline")


