# =====================================================================
# Chain 40: Audit-batch-preference pipeline (Phase 20 core)
#   AuditStore -> BatchStore -> PreferenceStore -> MetricDashboard
# =====================================================================

def test_chain40_audit_batch_pipeline():
    """Agent audits actions, runs batch, sets preferences, records metrics."""
    bus = PipelineIntegrationBus()
    audit_store = AgentAuditStore()
    batch_store = PipelineBatchStore()
    pref_store = AgentPreferenceStore()
    metric_dash = PipelineMetricDashboard()

    bus.register_chain("audit_batch")

    def s1(ctx):
        eid = audit_store.record("worker-1", "batch_start", resource="deploy-batch")
        ctx["audit_id"] = eid
        return ctx

    def s2(ctx):
        bid = batch_store.create_batch("deploy-all", ["svc-a", "svc-b"])
        batch_store.start_batch(bid)
        ctx["batch_id"] = bid
        return ctx

    def s3(ctx):
        pref_store.set_preference("worker-1", "batch", "parallelism", 4)
        ctx["pref_val"] = pref_store.get_preference("worker-1", "batch", "parallelism")
        return ctx

    def s4(ctx):
        batch_store.add_pipeline_result(ctx["batch_id"], "svc-a", True)
        batch_store.add_pipeline_result(ctx["batch_id"], "svc-b", True)
        batch_store.complete_batch(ctx["batch_id"])
        mid = metric_dash.record_metric("deploy-all", "duration", 42.5)
        ctx["metric_id"] = mid
        ctx["batch_done"] = batch_store.get_batch(ctx["batch_id"])["status"] == "completed"
        return ctx

    for i, (name, fn) in enumerate([
        ("audit", s1), ("create_batch", s2),
        ("set_prefs", s3), ("complete_and_metric", s4)
    ]):
        bus.add_step("audit_batch", name, fn, f"module_{i}")

    result = bus.execute("audit_batch", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert len(result["context"]["audit_id"]) > 0
    assert result["context"]["pref_val"] == 4
    assert result["context"]["batch_done"] is True
    assert len(result["context"]["metric_id"]) > 0
    print("OK: Chain 40 - Audit-batch-preference pipeline")


