    def s44(ctx):
        retry_store.record_attempt("olympus", "ex1", True)
        ctx["retry_rate"] = retry_store.get_success_rate("olympus")
        return ctx
    steps.append(("retry", s44))

    # Phase 23 steps
    def s45(ctx):
        consume_result = token_bucket.consume("oly-agent", tokens=10)
        ctx["token_ok"] = consume_result["success"] is True
        ctx["token_remaining"] = consume_result["remaining"]
        return ctx
    steps.append(("token", s45))
    def s46(ctx):
        order = dep_graph_pipe.get_execution_order()
        ctx["dep_order"] = order.index("oly-build") < order.index("oly-test") < order.index("oly-deploy")
        return ctx
    steps.append(("dep_graph", s46))
    def s47(ctx):
        cid = cmd_store.send_command("oly-agent", "deploy", payload={"env": "prod"}, priority=10)
        cmd_store.acknowledge(cid)
