def test_chain55_snapshot_throttle_reward_dep():
    """Chain 55: StateSnapshot -> ThrottleController -> RewardTracker -> DependencyValidator."""
    bus = PipelineIntegrationBus()
    bus.register_chain("snap_throttle_reward_dep", tags=["phase28"])

    snap_store = AgentStateSnapshot()
    throttle_ctrl = PipelineThrottleController()
    reward_track = AgentRewardTracker()
    dep_valid = PipelineDependencyValidator()

    def step_create_snapshot(ctx):
        sid = snap_store.create_snapshot("p28-agent", {"status": "running", "memory": 1024})
        ctx["snapshot_id"] = sid
        ctx["snapshot_created"] = len(sid) > 0
        return ctx

    def step_get_snapshot(ctx):
        snap = snap_store.get_snapshot(ctx["snapshot_id"])
        ctx["snap_agent"] = snap["agent_id"]
        ctx["snap_status"] = snap["state_data"]["status"]
        return ctx

    def step_set_throttle(ctx):
        tid = throttle_ctrl.set_throttle("p28-pipeline", 5, window_seconds=60)
        ctx["throttle_id"] = tid
        ctx["throttle_set"] = len(tid) > 0
        return ctx

    def step_check_throttle(ctx):
        ctx["allow1"] = throttle_ctrl.allow_request("p28-pipeline")
        ctx["allow2"] = throttle_ctrl.allow_request("p28-pipeline")
        ctx["current_rate"] = throttle_ctrl.get_current_rate("p28-pipeline")
        ctx["remaining"] = throttle_ctrl.get_remaining("p28-pipeline")
        return ctx

    def step_grant_rewards(ctx):
        r1 = reward_track.grant_reward("p28-agent", "completion", 10.0, reason="task done")
        r2 = reward_track.grant_reward("p28-agent", "bonus", 5.0, reason="quality")
        ctx["reward1"] = len(r1) > 0
        ctx["reward2"] = len(r2) > 0
        ctx["total_rewards"] = reward_track.get_total_rewards("p28-agent")
        return ctx

    def step_leaderboard(ctx):
        reward_track.grant_reward("p28-agent2", "completion", 20.0)
        board = reward_track.get_leaderboard(top_n=2)
        ctx["leader"] = board[0]["agent_id"]
        ctx["leader_total"] = board[0]["total"]
        return ctx

    def step_register_deps(ctx):
        dep_valid.register_pipeline("p28-a")
        dep_valid.register_pipeline("p28-b")
        dep_valid.add_dependency("p28-b", "p28-a")
        result = dep_valid.validate("p28-b")
        ctx["deps_valid"] = result["valid"]
        ctx["has_cycle"] = dep_valid.has_cycle()
        return ctx

    def step_check_missing_dep(ctx):
        dep_valid.add_dependency("p28-b", "p28-x")
        result = dep_valid.validate("p28-b")
        ctx["missing_dep_valid"] = result["valid"]
        ctx["missing"] = result["missing"]
        return ctx

    def step_finalize(ctx):
        snap_store.reset()
        throttle_ctrl.reset()
        reward_track.reset()
        dep_valid.reset()
        ctx["finalized"] = True
        return ctx

    bus.add_step("snap_throttle_reward_dep", "create_snapshot", step_create_snapshot, "AgentStateSnapshot")
    bus.add_step("snap_throttle_reward_dep", "get_snapshot", step_get_snapshot, "AgentStateSnapshot")
    bus.add_step("snap_throttle_reward_dep", "set_throttle", step_set_throttle, "PipelineThrottleController")
    bus.add_step("snap_throttle_reward_dep", "check_throttle", step_check_throttle, "PipelineThrottleController")
    bus.add_step("snap_throttle_reward_dep", "grant_rewards", step_grant_rewards, "AgentRewardTracker")
    bus.add_step("snap_throttle_reward_dep", "leaderboard", step_leaderboard, "AgentRewardTracker")
    bus.add_step("snap_throttle_reward_dep", "register_deps", step_register_deps, "PipelineDependencyValidator")
    bus.add_step("snap_throttle_reward_dep", "check_missing_dep", step_check_missing_dep, "PipelineDependencyValidator")
    bus.add_step("snap_throttle_reward_dep", "finalize", step_finalize, "cleanup")

    result = bus.execute("snap_throttle_reward_dep", {})
    ctx = result["context"]
    assert result["success"] is True
    assert ctx["snapshot_created"] is True
    assert ctx["snap_agent"] == "p28-agent"
    assert ctx["snap_status"] == "running"
    assert ctx["throttle_set"] is True
    assert ctx["allow1"] is True
    assert ctx["allow2"] is True
    assert ctx["current_rate"] == 2
    assert ctx["remaining"] == 3
    assert ctx["reward1"] is True
    assert ctx["reward2"] is True
    assert ctx["total_rewards"] == 15.0
    assert ctx["leader"] == "p28-agent2"
    assert ctx["leader_total"] == 20.0
    assert ctx["deps_valid"] is True
    assert ctx["has_cycle"] is False
    assert ctx["missing_dep_valid"] is False
    assert "p28-x" in ctx["missing"]
    assert ctx["finalized"] is True
    print("OK: Chain 55 - Snapshot-Throttle-Reward-Dependency pipeline (9 steps)")


