def test_chain56_skill_retry_comms_gate():
    """Chain 56: SkillRegistry -> RetryPolicy -> CommunicationHub -> StageGate."""
    bus = PipelineIntegrationBus()
    bus.register_chain("skill_retry_comms_gate", tags=["phase29"])

    skill_reg = AgentSkillRegistry()
    retry_pol = PipelineRetryPolicy()
    comm_hub = AgentCommunicationHub()
    stage_gate = PipelineStageGate()

    def step_register_skills(ctx):
        s1 = skill_reg.register_skill("p29-agent", "python", proficiency=0.9)
        s2 = skill_reg.register_skill("p29-agent", "testing", proficiency=0.8)
        ctx["skill1"] = len(s1) > 0
        ctx["skill2"] = len(s2) > 0
        ctx["agent_skills"] = len(skill_reg.get_agent_skills("p29-agent"))
        return ctx

    def step_find_skilled_agents(ctx):
        skill_reg.register_skill("p29-agent2", "python", proficiency=0.7)
        agents = skill_reg.find_agents_by_skill("python")
        ctx["best_agent"] = agents[0]
        ctx["python_agents"] = len(agents)
        return ctx

    def step_create_retry_policy(ctx):
        pid = retry_pol.create_policy("p29-pipeline", max_retries=3, backoff="exponential", initial_delay=1.0)
        ctx["policy_created"] = len(pid) > 0
        ctx["should_retry_1"] = retry_pol.should_retry("p29-pipeline", 1)
        ctx["delay_1"] = retry_pol.get_delay("p29-pipeline", 1)
        ctx["delay_2"] = retry_pol.get_delay("p29-pipeline", 2)
        return ctx

    def step_record_attempts(ctx):
        retry_pol.record_attempt("p29-pipeline", success=False)
        retry_pol.record_attempt("p29-pipeline", success=True)
        history = retry_pol.get_attempt_history("p29-pipeline")
        ctx["attempt_count"] = len(history)
        return ctx

    def step_send_messages(ctx):
        m1 = comm_hub.send_message("p29-agent", "p29-agent2", "task assigned")
        m2 = comm_hub.send_message("p29-agent2", "p29-agent", "acknowledged")
        ctx["msg1"] = len(m1) > 0
        ctx["msg2"] = len(m2) > 0
        ctx["inbox_count"] = len(comm_hub.get_inbox("p29-agent"))
        ctx["unread"] = comm_hub.get_unread_count("p29-agent")
        return ctx

    def step_broadcast(ctx):
        bid = comm_hub.broadcast("p29-agent", "deployment starting")
        ctx["broadcast_sent"] = len(bid) > 0
        return ctx

    def step_create_gate(ctx):
        gid = stage_gate.create_gate("p29-pipeline", "deploy", required_approvals=2)
        ctx["gate_id"] = gid
        ctx["gate_created"] = len(gid) > 0
        stage_gate.approve_gate(gid, "p29-agent")
        ctx["after_one_approval"] = stage_gate.is_approved(gid)
        stage_gate.approve_gate(gid, "p29-agent2")
        ctx["after_two_approvals"] = stage_gate.is_approved(gid)
        ctx["gate_status"] = stage_gate.get_gate_status(gid)
        return ctx

    def step_finalize(ctx):
        skill_reg.reset()
        retry_pol.reset()
        comm_hub.reset()
        stage_gate.reset()
        ctx["finalized"] = True
        return ctx

    bus.add_step("skill_retry_comms_gate", "register_skills", step_register_skills, "AgentSkillRegistry")
    bus.add_step("skill_retry_comms_gate", "find_skilled", step_find_skilled_agents, "AgentSkillRegistry")
    bus.add_step("skill_retry_comms_gate", "create_retry", step_create_retry_policy, "PipelineRetryPolicy")
    bus.add_step("skill_retry_comms_gate", "record_attempts", step_record_attempts, "PipelineRetryPolicy")
    bus.add_step("skill_retry_comms_gate", "send_messages", step_send_messages, "AgentCommunicationHub")
    bus.add_step("skill_retry_comms_gate", "broadcast", step_broadcast, "AgentCommunicationHub")
    bus.add_step("skill_retry_comms_gate", "create_gate", step_create_gate, "PipelineStageGate")
    bus.add_step("skill_retry_comms_gate", "finalize", step_finalize, "cleanup")

    result = bus.execute("skill_retry_comms_gate", {})
    ctx = result["context"]
    assert result["success"] is True
    assert ctx["skill1"] is True
    assert ctx["skill2"] is True
    assert ctx["agent_skills"] == 2
    assert ctx["best_agent"] == "p29-agent"
    assert ctx["python_agents"] == 2
    assert ctx["policy_created"] is True
    assert ctx["should_retry_1"] is True
    assert ctx["delay_1"] == 1.0
    assert ctx["delay_2"] == 2.0
    assert ctx["attempt_count"] == 2
    assert ctx["msg1"] is True
    assert ctx["msg2"] is True
    assert ctx["inbox_count"] == 1
    assert ctx["unread"] == 1
    assert ctx["broadcast_sent"] is True
    assert ctx["gate_created"] is True
    assert ctx["after_one_approval"] is False
    assert ctx["after_two_approvals"] is True
    assert ctx["gate_status"] == "approved"
    assert ctx["finalized"] is True
    print("OK: Chain 56 - Skill-Retry-Comms-Gate pipeline (8 steps)")


