def test_chain57_memory_loadbal_goal_config():
    """Chain 57: MemoryStore -> LoadBalancer -> GoalTracker -> ConfigStore."""
    bus = PipelineIntegrationBus()
    bus.register_chain("mem_lb_goal_config", tags=["phase30"])

    mem_store = AgentMemoryStore()
    load_bal = PipelineLoadBalancer()
    goal_track = AgentGoalTracker()
    config_store = PipelineConfigStore()

    def step_store_memories(ctx):
        m1 = mem_store.store_memory("p30-agent", "last_task", "deploy-v2", memory_type="episodic")
        m2 = mem_store.store_memory("p30-agent", "preference", "blue-green", memory_type="semantic")
        ctx["mem1"] = len(m1) > 0
        ctx["mem2"] = len(m2) > 0
        ctx["recalled"] = mem_store.recall("p30-agent", "last_task")
        return ctx

    def step_register_lb(ctx):
        r1 = load_bal.register_instance("p30-pipeline", "inst-a", capacity=100)
        r2 = load_bal.register_instance("p30-pipeline", "inst-b", capacity=100)
        ctx["lb_registered"] = len(r1) > 0 and len(r2) > 0
        load_bal.record_load("p30-pipeline", "inst-a", 80)
        load_bal.record_load("p30-pipeline", "inst-b", 20)
        ctx["routed_to"] = load_bal.route_request("p30-pipeline")
        return ctx

    def step_create_goals(ctx):
        g1 = goal_track.create_goal("p30-agent", "deploy application", priority=1)
        g2 = goal_track.create_goal("p30-agent", "run tests", priority=2)
        ctx["goal1"] = len(g1) > 0
        ctx["goal2"] = len(g2) > 0
        goal_track.complete_goal(g1)
        ctx["active_goals"] = len(goal_track.get_active_goals("p30-agent"))
        return ctx

    def step_set_configs(ctx):
        config_store.set_config("p30-pipeline", "timeout", 30)
        config_store.set_config("p30-pipeline", "max_retries", 3)
        ctx["timeout"] = config_store.get_config("p30-pipeline", "timeout")
        ctx["has_retries"] = config_store.has_config("p30-pipeline", "max_retries")
        all_conf = config_store.get_all_config("p30-pipeline")
        ctx["config_count"] = len(all_conf)
        return ctx

    def step_finalize(ctx):
        mem_store.reset()
        load_bal.reset()
        goal_track.reset()
        config_store.reset()
        ctx["finalized"] = True
        return ctx

    bus.add_step("mem_lb_goal_config", "store_memories", step_store_memories, "AgentMemoryStore")
    bus.add_step("mem_lb_goal_config", "register_lb", step_register_lb, "PipelineLoadBalancer")
    bus.add_step("mem_lb_goal_config", "create_goals", step_create_goals, "AgentGoalTracker")
    bus.add_step("mem_lb_goal_config", "set_configs", step_set_configs, "PipelineConfigStore")
    bus.add_step("mem_lb_goal_config", "finalize", step_finalize, "cleanup")

    result = bus.execute("mem_lb_goal_config", {})
    ctx = result["context"]
    assert result["success"] is True
    assert ctx["mem1"] is True
    assert ctx["mem2"] is True
    assert ctx["recalled"] == "deploy-v2"
    assert ctx["lb_registered"] is True
    assert ctx["routed_to"] == "inst-b"
    assert ctx["goal1"] is True
    assert ctx["goal2"] is True
    assert ctx["active_goals"] == 1
    assert ctx["timeout"] == 30
    assert ctx["has_retries"] is True
    assert ctx["config_count"] == 2
    assert ctx["finalized"] is True
    print("OK: Chain 57 - Memory-LoadBal-Goal-Config pipeline (5 steps)")


