# =====================================================================
# Chain 58: Priority-Health-Context-Version Pipeline (Phase 31)
# =====================================================================

def test_chain58_priority_health_context_version():
    """Agent enqueues task, probes health, manages context, versions pipeline."""
    bus = PipelineIntegrationBus()
    pq = AgentPriorityQueue()
    hp = PipelineHealthProbe()
    cm = AgentContextManager()
    vc = PipelineVersionControl()

    bus.register_chain("priority_health_context_version", tags=["phase31"])

    # Step 1: Enqueue a high-priority task
    def step_enqueue(ctx):
        tid = pq.enqueue("agent-1", "deploy-task", priority=10, payload={"target": "prod"})
        ctx["task_id"] = tid
        return ctx
    bus.add_step("priority_health_context_version", "enqueue_task", step_enqueue, "agent_priority_queue")

    # Step 2: Register and check pipeline health
    def step_health(ctx):
        pid = hp.register_probe("deploy-pipeline", check_interval=30)
        ctx["probe_id"] = pid
        hp.record_check("deploy-pipeline", healthy=True, latency=25.0)
        ctx["health_status"] = hp.get_health_status("deploy-pipeline")
        return ctx
    bus.add_step("priority_health_context_version", "probe_health", step_health, "pipeline_health_probe")

    # Step 3: Create execution context
    def step_context(ctx):
        cid = cm.create_context("agent-1", context_data={"env": "prod", "task": ctx["task_id"]})
        ctx["context_id"] = cid
        cm.update_context(cid, "health", ctx["health_status"])
        return ctx
    bus.add_step("priority_health_context_version", "create_context", step_context, "agent_context_manager")

    # Step 4: Create pipeline version
    def step_version(ctx):
        vid = vc.create_version("deploy-pipeline", {"workers": 8, "env": "prod"}, version_tag="v1.0")
        ctx["version_id"] = vid
        return ctx
    bus.add_step("priority_health_context_version", "create_version", step_version, "pipeline_version_control")

    # Step 5: Dequeue and verify
    def step_dequeue(ctx):
        item = pq.dequeue("agent-1")
        assert item is not None
        assert item["task_name"] == "deploy-task"
        ctx["dequeued"] = True
        return ctx
    bus.add_step("priority_health_context_version", "dequeue_task", step_dequeue, "agent_priority_queue")

    # Step 6: Verify all components
    def step_verify(ctx):
        assert ctx["health_status"] == "healthy"
        assert cm.get_context_value(ctx["context_id"], "health") == "healthy"
        ver = vc.get_version(ctx["version_id"])
        assert ver is not None
        assert ver["version_tag"] == "v1.0"
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("priority_health_context_version", "verify_all", step_verify, "integration")

    result = bus.execute("priority_health_context_version", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    assert result["context"]["dequeued"] is True
    print("OK: chain 58 -- priority-health-context-version pipeline")


