# =====================================================================
# Chain 59: Scheduler-Circuit-DepGraph-Journal Pipeline (Phase 32)
# =====================================================================

def test_chain59_scheduler_circuit_depgraph_journal():
    """Schedule tasks, check circuit, resolve deps, journal events."""
    bus = PipelineIntegrationBus()
    ts = AgentTaskScheduler()
    cm = PipelineCircuitManager()
    dg = AgentDependencyGraph()
    ej = PipelineEventJournal()

    bus.register_chain("scheduler_circuit_depgraph_journal", tags=["phase32"])

    # Step 1: Add agents to dependency graph
    def step_deps(ctx):
        dg.add_agent("orchestrator")
        dg.add_agent("worker-1")
        dg.add_agent("worker-2")
        dg.add_dependency("worker-1", "orchestrator")
        dg.add_dependency("worker-2", "orchestrator")
        ctx["topo"] = dg.get_topological_order()
        return ctx
    bus.add_step("scheduler_circuit_depgraph_journal", "setup_deps", step_deps, "agent_dependency_graph")

    # Step 2: Create circuit breaker for pipeline
    def step_circuit(ctx):
        cm.create_circuit("main-pipeline", failure_threshold=3)
        ctx["circuit_allowed"] = cm.is_allowed("main-pipeline")
        ctx["circuit_state"] = cm.get_state("main-pipeline")
        return ctx
    bus.add_step("scheduler_circuit_depgraph_journal", "create_circuit", step_circuit, "pipeline_circuit_manager")

    # Step 3: Schedule tasks for workers
    def step_schedule(ctx):
        t1 = ts.schedule_task("worker-1", "process-data", schedule_type="recurring", interval=60.0)
        t2 = ts.schedule_task("worker-2", "sync-data", schedule_type="once", delay=5.0)
        ctx["task1"] = t1
        ctx["task2"] = t2
        ts.mark_running(t1)
        return ctx
    bus.add_step("scheduler_circuit_depgraph_journal", "schedule_tasks", step_schedule, "agent_task_scheduler")

    # Step 4: Journal events
    def step_journal(ctx):
        ej.record_event("main-pipeline", "tasks_scheduled", data={"count": 2}, severity="info")
        ej.record_event("main-pipeline", "circuit_created", data={"state": ctx["circuit_state"]})
        ctx["event_count"] = ej.get_event_count()
        return ctx
    bus.add_step("scheduler_circuit_depgraph_journal", "journal_events", step_journal, "pipeline_event_journal")

    # Step 5: Verify integration
    def step_verify(ctx):
        assert ctx["circuit_allowed"] is True
        assert ctx["circuit_state"] == "closed"
        assert len(ctx["topo"]) == 3
        assert ctx["topo"][0] == "orchestrator"  # no deps, comes first
        assert ctx["event_count"] == 2
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("scheduler_circuit_depgraph_journal", "verify", step_verify, "integration")

    result = bus.execute("scheduler_circuit_depgraph_journal", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 59 -- scheduler-circuit-depgraph-journal pipeline")


