# =====================================================================
# Chain 60: Resource-Snapshot-Capability-Flow Pipeline (Phase 33)
# =====================================================================

def test_chain60_resource_snapshot_capability_flow():
    """Manage resources, snapshot state, index capabilities, control flow."""
    bus = PipelineIntegrationBus()
    rp = AgentResourcePool()
    ss = PipelineSnapshotStore()
    ci = AgentCapabilityIndex()
    fc = PipelineFlowController()

    bus.register_chain("resource_snapshot_capability_flow", tags=["phase33"])

    # Step 1: Register capabilities
    def step_caps(ctx):
        ci.register_capability("worker-1", "python")
        ci.register_capability("worker-1", "data-processing")
        ci.register_capability("worker-2", "python")
        ctx["python_agents"] = ci.find_agents_with_capability("python")
        return ctx
    bus.add_step("resource_snapshot_capability_flow", "register_caps", step_caps, "agent_capability_index")

    # Step 2: Create resource pool and acquire
    def step_pool(ctx):
        rp.create_pool("compute", capacity=20, resource_type="cpu")
        rp.acquire("compute", "worker-1", amount=8)
        rp.acquire("compute", "worker-2", amount=5)
        ctx["available"] = rp.get_available("compute")
        return ctx
    bus.add_step("resource_snapshot_capability_flow", "manage_pool", step_pool, "agent_resource_pool")

    # Step 3: Register and control pipeline flow
    def step_flow(ctx):
        fc.register_pipeline("data-pipeline", max_throughput=100.0)
        ctx["flow_running"] = fc.is_running("data-pipeline")
        return ctx
    bus.add_step("resource_snapshot_capability_flow", "control_flow", step_flow, "pipeline_flow_controller")

    # Step 4: Take snapshot
    def step_snapshot(ctx):
        sid = ss.save_snapshot("data-pipeline", {
            "available_compute": ctx["available"],
            "python_agents": ctx["python_agents"],
            "running": ctx["flow_running"]
        }, label="pre-processing")
        ctx["snapshot_id"] = sid
        return ctx
    bus.add_step("resource_snapshot_capability_flow", "take_snapshot", step_snapshot, "pipeline_snapshot_store")

    # Step 5: Verify
    def step_verify(ctx):
        assert len(ctx["python_agents"]) == 2
        assert ctx["available"] == 7  # 20 - 8 - 5
        assert ctx["flow_running"] is True
        restored = ss.restore_snapshot(ctx["snapshot_id"])
        assert restored is not None
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("resource_snapshot_capability_flow", "verify", step_verify, "integration")

    result = bus.execute("resource_snapshot_capability_flow", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 60 -- resource-snapshot-capability-flow pipeline")


