# =====================================================================
# Chain 61: Session-Quota-MsgQueue-Metrics Pipeline (Phase 34)
# =====================================================================

def test_chain61_session_quota_msgqueue_metrics():
    """Agent starts session, enforces quota, sends messages, aggregates metrics."""
    bus = PipelineIntegrationBus()
    st = AgentSessionTracker()
    qe = PipelineQuotaEnforcer()
    mq = AgentMessageQueue()
    ma = PipelineMetricAggregator()

    bus.register_chain("session_quota_msgqueue_metrics", tags=["phase34"])

    # Step 1: Start agent session
    def step_session(ctx):
        sid = st.start_session("worker-1", session_type="execution", metadata={"task": "data-processing"})
        ctx["session_id"] = sid
        active = st.get_active_sessions("worker-1")
        ctx["active_count"] = len(active)
        return ctx
    bus.add_step("session_quota_msgqueue_metrics", "start_session", step_session, "agent_session_tracker")

    # Step 2: Enforce quota before processing
    def step_quota(ctx):
        qe.create_quota("data-pipeline", "api_calls", limit=10, period="hour")
        assert qe.check_quota("data-pipeline", "api_calls") is True
        qe.consume_quota("data-pipeline", "api_calls", amount=3)
        ctx["remaining"] = qe.get_remaining("data-pipeline", "api_calls")
        return ctx
    bus.add_step("session_quota_msgqueue_metrics", "enforce_quota", step_quota, "pipeline_quota_enforcer")

    # Step 3: Send messages between agents
    def step_messages(ctx):
        mq.create_queue("worker-1")
        mq.create_queue("worker-2")
        mq.enqueue("worker-2", "process batch A", priority=5, sender="worker-1")
        mq.enqueue("worker-2", "process batch B", priority=10, sender="worker-1")
        msg = mq.dequeue("worker-2")
        ctx["top_message"] = msg["message"]
        ctx["queue_size"] = mq.get_queue_size("worker-2")
        return ctx
    bus.add_step("session_quota_msgqueue_metrics", "send_messages", step_messages, "agent_message_queue")

    # Step 4: Record metrics
    def step_metrics(ctx):
        ma.record_metric("data-pipeline", "latency_ms", 45.2)
        ma.record_metric("data-pipeline", "latency_ms", 52.8)
        ma.record_metric("data-pipeline", "latency_ms", 38.1)
        summary = ma.get_summary("data-pipeline", "latency_ms")
        ctx["metric_count"] = summary["count"]
        ctx["metric_avg"] = summary["avg"]
        return ctx
    bus.add_step("session_quota_msgqueue_metrics", "record_metrics", step_metrics, "pipeline_metric_aggregator")

    # Step 5: Verify and end session
    def step_verify(ctx):
        assert ctx["active_count"] == 1
        assert ctx["remaining"] == 7  # 10 - 3
        assert ctx["top_message"] == "process batch B"  # higher priority first
        assert ctx["queue_size"] == 1  # one message left
        assert ctx["metric_count"] == 3
        st.end_session(ctx["session_id"])
        active = st.get_active_sessions("worker-1")
        ctx["final_active"] = len(active)
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("session_quota_msgqueue_metrics", "verify", step_verify, "integration")

    result = bus.execute("session_quota_msgqueue_metrics", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    assert result["context"]["final_active"] == 0
    print("OK: chain 61 -- session-quota-msgqueue-metrics pipeline")


