# =====================================================================
# Chain 62: LoadBalancer-StateMachine-Retry-Scheduler Pipeline (Phase 35)
# =====================================================================

def test_chain62_loadbal_statemachine_retry_scheduler():
    """Load balance tasks, manage state transitions, handle retries, schedule pipelines."""
    bus = PipelineIntegrationBus()
    lb = AgentLoadBalancer()
    sm = PipelineStateMachine()
    rh = AgentRetryHandler()
    ps = PipelinePriorityScheduler()

    bus.register_chain("loadbal_statemachine_retry_scheduler", tags=["phase35"])

    # Step 1: Register agents and assign tasks via load balancer
    def step_loadbal(ctx):
        lb.register_agent("worker-1", capacity=5)
        lb.register_agent("worker-2", capacity=5)
        assigned1 = lb.assign_task("data-transform", strategy="least_loaded")
        assigned2 = lb.assign_task("data-validate", strategy="least_loaded")
        ctx["assigned_agents"] = [assigned1, assigned2]
        ctx["worker1_load"] = lb.get_agent_load("worker-1")
        ctx["worker2_load"] = lb.get_agent_load("worker-2")
        return ctx
    bus.add_step("loadbal_statemachine_retry_scheduler", "balance_load", step_loadbal, "agent_load_balancer")

    # Step 2: Create pipeline state machine and transition
    def step_state(ctx):
        sm.create_machine("etl-pipeline")
        sm.transition("etl-pipeline", "running")
        ctx["pipeline_state"] = sm.get_state("etl-pipeline")
        ctx["is_terminal"] = sm.is_terminal("etl-pipeline")
        return ctx
    bus.add_step("loadbal_statemachine_retry_scheduler", "manage_state", step_state, "pipeline_state_machine")

    # Step 3: Set up retry policies and simulate failure
    def step_retry(ctx):
        rh.create_policy("worker-1", max_retries=3, backoff="exponential", base_delay=1.0)
        rh.record_attempt("worker-1", "data-transform", success=False)
        rh.record_attempt("worker-1", "data-transform", success=False)
        ctx["should_retry"] = rh.should_retry("worker-1", "data-transform")
        ctx["attempt_count"] = rh.get_attempt_count("worker-1", "data-transform")
        ctx["next_delay"] = rh.get_next_delay("worker-1", "data-transform")
        return ctx
    bus.add_step("loadbal_statemachine_retry_scheduler", "handle_retries", step_retry, "agent_retry_handler")

    # Step 4: Schedule pipeline executions with priorities
    def step_schedule(ctx):
        s1 = ps.schedule("etl-pipeline", priority=10)
        s2 = ps.schedule("backup-pipeline", priority=3)
        nxt = ps.get_next()
        ctx["next_pipeline"] = nxt["pipeline_id"]
        ctx["pending_count"] = ps.get_pending_count()
        return ctx
    bus.add_step("loadbal_statemachine_retry_scheduler", "schedule_pipelines", step_schedule, "pipeline_priority_scheduler")

    # Step 5: Verify
    def step_verify(ctx):
        assert len(ctx["assigned_agents"]) == 2
        assert ctx["pipeline_state"] == "running"
        assert ctx["is_terminal"] is False
        assert ctx["should_retry"] is True  # 2 failures < 3 max
        assert ctx["attempt_count"] == 2
        assert ctx["next_pipeline"] == "etl-pipeline"  # higher priority
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("loadbal_statemachine_retry_scheduler", "verify", step_verify, "integration")

    result = bus.execute("loadbal_statemachine_retry_scheduler", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 62 -- loadbal-statemachine-retry-scheduler pipeline")


