# =====================================================================
# Chain 63: Heartbeat-Backpressure-Router-Checkpoint Pipeline (Phase 36)
# =====================================================================

def test_chain63_heartbeat_backpressure_router_checkpoint():
    """Monitor heartbeats, manage backpressure, route tasks, save checkpoints."""
    bus = PipelineIntegrationBus()
    hm = AgentHeartbeatMonitor()
    bp = PipelineBackpressureHandler()
    tr = AgentTaskRouter()
    cm = PipelineCheckpointManager()

    bus.register_chain("heartbeat_backpressure_router_checkpoint", tags=["phase36"])

    # Step 1: Register and heartbeat agents
    def step_heartbeat(ctx):
        hm.register_agent("builder-1", timeout=60.0)
        hm.register_agent("tester-1", timeout=60.0)
        hm.heartbeat("builder-1")
        hm.heartbeat("tester-1")
        ctx["alive_count"] = len(hm.get_alive_agents())
        ctx["builder_alive"] = hm.is_alive("builder-1")
        return ctx
    bus.add_step("heartbeat_backpressure_router_checkpoint", "check_heartbeats", step_heartbeat, "agent_heartbeat_monitor")

    # Step 2: Monitor backpressure
    def step_backpressure(ctx):
        bp.register_pipeline("build-pipeline", max_queue_depth=200, throttle_threshold=0.75)
        bp.record_depth("build-pipeline", 120)
        ctx["pressure"] = bp.get_pressure("build-pipeline")
        ctx["throttled"] = bp.is_throttled("build-pipeline")
        return ctx
    bus.add_step("heartbeat_backpressure_router_checkpoint", "check_backpressure", step_backpressure, "pipeline_backpressure_handler")

    # Step 3: Route tasks to appropriate agents
    def step_route(ctx):
        tr.add_route("build", "builder-1", priority=10)
        tr.add_route("test", "tester-1", priority=10)
        tr.add_route("build", "tester-1", priority=3)  # fallback
        ctx["build_agent"] = tr.route_task("build")
        ctx["test_agent"] = tr.route_task("test")
        return ctx
    bus.add_step("heartbeat_backpressure_router_checkpoint", "route_tasks", step_route, "agent_task_router")

    # Step 4: Save checkpoint
    def step_checkpoint(ctx):
        cid = cm.create_checkpoint("build-pipeline", "routing-complete", {
            "alive_agents": ctx["alive_count"],
            "pressure": ctx["pressure"],
            "build_agent": ctx["build_agent"],
        }, label="post-routing")
        ctx["checkpoint_id"] = cid
        return ctx
    bus.add_step("heartbeat_backpressure_router_checkpoint", "save_checkpoint", step_checkpoint, "pipeline_checkpoint_manager")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["alive_count"] == 2
        assert ctx["builder_alive"] is True
        assert abs(ctx["pressure"] - 0.6) < 0.01  # 120/200
        assert ctx["throttled"] is False  # 0.6 < 0.75
        assert ctx["build_agent"] == "builder-1"
        assert ctx["test_agent"] == "tester-1"
        assert ctx["checkpoint_id"].startswith("pcpm-")
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("heartbeat_backpressure_router_checkpoint", "verify", step_verify, "integration")

    result = bus.execute("heartbeat_backpressure_router_checkpoint", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 63 -- heartbeat-backpressure-router-checkpoint pipeline")


