# =====================================================================
# Chain 64: WorkQueue-ExecTracker-Credentials-Timeout Pipeline (Phase 37)
# =====================================================================

def test_chain64_workqueue_exectracker_creds_timeout():
    """Queue work, track execution, manage credentials, enforce timeouts."""
    bus = PipelineIntegrationBus()
    wq = AgentWorkQueue()
    et = PipelineExecutionTracker()
    cv = AgentCredentialVault()
    tm = PipelineTimeoutManager()

    bus.register_chain("workqueue_exectracker_creds_timeout", tags=["phase37"])

    # Step 1: Queue work items
    def step_queue(ctx):
        wq.create_queue("worker-1")
        wq.push("worker-1", "compile-code", priority=10)
        wq.push("worker-1", "run-tests", priority=5)
        wq.push("worker-1", "deploy", priority=8)
        item = wq.pop("worker-1")
        ctx["top_work"] = item["work_item"]
        ctx["remaining"] = wq.get_queue_length("worker-1")
        return ctx
    bus.add_step("workqueue_exectracker_creds_timeout", "queue_work", step_queue, "agent_work_queue")

    # Step 2: Start tracking execution
    def step_track(ctx):
        eid = et.start_execution("build-pipeline", total_steps=4)
        et.complete_step(eid, "init")
        et.complete_step(eid, "compile")
        ctx["exec_id"] = eid
        ctx["progress"] = et.get_progress(eid)
        return ctx
    bus.add_step("workqueue_exectracker_creds_timeout", "track_exec", step_track, "pipeline_execution_tracker")

    # Step 3: Store and retrieve credentials
    def step_creds(ctx):
        cv.store_credential("worker-1", "deploy_key", "ssh-rsa-AAAAB3...")
        cv.store_credential("worker-1", "api_token", "tok-xyz789")
        ctx["has_key"] = cv.has_credential("worker-1", "deploy_key")
        ctx["cred_count"] = len(cv.list_credentials("worker-1"))
        return ctx
    bus.add_step("workqueue_exectracker_creds_timeout", "manage_creds", step_creds, "agent_credential_vault")

    # Step 4: Set execution timeout
    def step_timeout(ctx):
        tm.set_timeout("build-pipeline", timeout_seconds=300.0, label="build-timeout")
        ctx["timed_out"] = tm.check_timeout("build-pipeline")
        ctx["time_left"] = tm.get_remaining("build-pipeline")
        return ctx
    bus.add_step("workqueue_exectracker_creds_timeout", "set_timeout", step_timeout, "pipeline_timeout_manager")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["top_work"] == "compile-code"  # highest priority
        assert ctx["remaining"] == 2
        assert abs(ctx["progress"] - 0.5) < 0.01  # 2/4 steps
        assert ctx["has_key"] is True
        assert ctx["cred_count"] == 2
        assert ctx["timed_out"] is False
        assert ctx["time_left"] > 290.0
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("workqueue_exectracker_creds_timeout", "verify", step_verify, "integration")

    result = bus.execute("workqueue_exectracker_creds_timeout", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 64 -- workqueue-exectracker-creds-timeout pipeline")


