def test_chain65_output_validator_env_progress():
    """Collect outputs, validate inputs, manage environments, report progress."""
    bus = PipelineIntegrationBus()
    oc = AgentOutputCollector()
    iv = PipelineInputValidator()
    em = AgentEnvironmentManager()
    pr = PipelineProgressReporter()

    bus.register_chain("output_validator_env_progress", tags=["phase38"])

    # Step 1: Set up validation rules
    def step_validate(ctx):
        iv.add_rule("data-pipeline", "source", rule_type="required")
        iv.add_rule("data-pipeline", "batch_size", rule_type="min", value=1)
        iv.add_rule("data-pipeline", "batch_size", rule_type="max", value=1000)
        result = iv.validate("data-pipeline", {"source": "s3://data", "batch_size": 100})
        ctx["validation_ok"] = result["valid"]
        return ctx
    bus.add_step("output_validator_env_progress", "validate_input", step_validate, "pipeline_input_validator")

    # Step 2: Create agent environment
    def step_env(ctx):
        eid = em.create_environment("processor-1", env_type="python", variables={"BATCH_SIZE": "100"})
        em.set_variable(eid, "SOURCE", "s3://data")
        ctx["env_id"] = eid
        ctx["env_vars"] = len(em.get_all_variables(eid))
        return ctx
    bus.add_step("output_validator_env_progress", "setup_env", step_env, "agent_environment_manager")

    # Step 3: Start progress reporting
    def step_progress(ctx):
        rid = pr.start_report("data-pipeline", total_steps=5)
        pr.update_progress(rid, completed_steps=2, message="processing")
        prog = pr.get_progress(rid)
        ctx["report_id"] = rid
        ctx["percentage"] = prog["percentage"]
        return ctx
    bus.add_step("output_validator_env_progress", "report_progress", step_progress, "pipeline_progress_reporter")

    # Step 4: Collect agent output
    def step_output(ctx):
        oc.collect("processor-1", "result", {"records_processed": 500, "errors": 0})
        oc.collect("processor-1", "metrics", {"throughput": 250.5})
        ctx["output_count"] = len(oc.get_outputs("processor-1"))
        latest = oc.get_latest_output("processor-1")
        ctx["latest_type"] = latest["output_type"]
        return ctx
    bus.add_step("output_validator_env_progress", "collect_output", step_output, "agent_output_collector")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["validation_ok"] is True
        assert ctx["env_vars"] == 2
        assert abs(ctx["percentage"] - 40.0) < 0.1  # 2/5 = 40%
        assert ctx["output_count"] == 2
        assert ctx["latest_type"] == "metrics"
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("output_validator_env_progress", "verify", step_verify, "integration")

    result = bus.execute("output_validator_env_progress", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 65 -- output-validator-env-progress pipeline")


