# =====================================================================
# Chain 66: Scheduling-Partition-Fault-Completion Pipeline (Phase 39)
# =====================================================================

def test_chain66_scheduling_partition_fault_completion():
    """Schedule agents, partition data, detect faults, track completion."""
    bus = PipelineIntegrationBus()
    sp = AgentSchedulingPolicy()
    dp = PipelineDataPartitioner()
    fd = AgentFaultDetector()
    ct = PipelineCompletionTracker()

    bus.register_chain("scheduling_partition_fault_completion", tags=["phase39"])

    # Step 1: Set scheduling policies
    def step_schedule(ctx):
        sp.create_policy("worker-1", policy_type="priority", max_concurrent=4)
        sp.create_policy("worker-2", policy_type="fifo", max_concurrent=2)
        ctx["w1_can_schedule"] = sp.can_schedule("worker-1", current_running=3)
        ctx["w2_can_schedule"] = sp.can_schedule("worker-2", current_running=2)
        return ctx
    bus.add_step("scheduling_partition_fault_completion", "set_policies", step_schedule, "agent_scheduling_policy")

    # Step 2: Partition data
    def step_partition(ctx):
        pid = dp.create_partition("etl-pipeline", total_items=1000, partition_count=4)
        ranges = dp.get_partition_ranges(pid)
        dp.mark_partition_complete(pid, 0)
        dp.mark_partition_complete(pid, 1)
        status = dp.get_completion_status(pid)
        ctx["partition_id"] = pid
        ctx["partition_count"] = len(ranges)
        ctx["partitions_done"] = status["completed"]
        return ctx
    bus.add_step("scheduling_partition_fault_completion", "partition_data", step_partition, "pipeline_data_partitioner")

    # Step 3: Monitor agent faults
    def step_faults(ctx):
        fd.register_agent("worker-1", error_threshold=0.5, max_consecutive_failures=5)
        fd.record_success("worker-1")
        fd.record_success("worker-1")
        fd.record_failure("worker-1")
        ctx["error_rate"] = fd.get_error_rate("worker-1")
        ctx["is_faulty"] = fd.is_faulty("worker-1")
        return ctx
    bus.add_step("scheduling_partition_fault_completion", "check_faults", step_faults, "agent_fault_detector")

    # Step 4: Track completion
    def step_complete(ctx):
        tid = ct.start_tracking("etl-pipeline", expected_steps=4)
        ct.mark_step_done(tid, "partition")
        ct.mark_step_done(tid, "process")
        status = ct.get_status(tid)
        ctx["tracking_id"] = tid
        ctx["steps_done"] = status["steps_done"]
        ctx["is_complete"] = ct.is_complete(tid)
        return ctx
    bus.add_step("scheduling_partition_fault_completion", "track_completion", step_complete, "pipeline_completion_tracker")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["w1_can_schedule"] is True  # 3 < 4
        assert ctx["w2_can_schedule"] is False  # 2 >= 2
        assert ctx["partition_count"] == 4
        assert ctx["partitions_done"] == 2
        assert abs(ctx["error_rate"] - 1/3) < 0.01  # 1 fail / 3 total
        assert ctx["is_faulty"] is False
        assert ctx["steps_done"] == 2
        assert ctx["is_complete"] is False
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("scheduling_partition_fault_completion", "verify", step_verify, "integration")

    result = bus.execute("scheduling_partition_fault_completion", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 66 -- scheduling-partition-fault-completion pipeline")


