# =====================================================================
# Chain 67: Profiler-Workflow-TokenRefresh-FailureHandler Pipeline (Phase 40)
# =====================================================================

def test_chain67_profiler_workflow_token_failure():
    """Profile agent ops, orchestrate workflows, refresh tokens, handle failures."""
    bus = PipelineIntegrationBus()
    pp = AgentPerformanceProfiler()
    wo = PipelineWorkflowOrchestrator()
    tr = AgentTokenRefresh()
    fh = PipelineFailureHandler()

    bus.register_chain("profiler_workflow_token_failure", tags=["phase40"])

    # Step 1: Profile agent performance
    def step_profile(ctx):
        pid1 = pp.start_profile("worker-1", "build")
        elapsed = pp.end_profile(pid1)
        pid2 = pp.start_profile("worker-1", "build")
        pp.end_profile(pid2)
        avg = pp.get_average_time("worker-1", "build")
        ctx["profile_count"] = pp.get_profile_count("worker-1")
        ctx["avg_time"] = avg
        return ctx
    bus.add_step("profiler_workflow_token_failure", "profile_ops", step_profile, "agent_performance_profiler")

    # Step 2: Orchestrate workflow
    def step_workflow(ctx):
        wid = wo.create_workflow("etl-pipeline", name="main-flow")
        wo.add_step(wid, "extract", step_order=1)
        wo.add_step(wid, "transform", step_order=2)
        wo.add_step(wid, "load", step_order=3)
        wo.start_workflow(wid)
        wo.complete_step(wid, "extract")
        ctx["workflow_id"] = wid
        ctx["current_step"] = wo.get_current_step(wid)
        ctx["is_complete"] = wo.is_workflow_complete(wid)
        return ctx
    bus.add_step("profiler_workflow_token_failure", "orchestrate", step_workflow, "pipeline_workflow_orchestrator")

    # Step 3: Manage tokens
    def step_tokens(ctx):
        tr.register_token("worker-1", "tok-abc123", ttl_seconds=3600.0)
        ctx["token_valid"] = not tr.is_expired("worker-1")
        ctx["remaining_ttl"] = tr.get_remaining_ttl("worker-1")
        tr.refresh_token("worker-1", "tok-new456")
        ctx["refreshed_token"] = tr.get_token("worker-1")
        return ctx
    bus.add_step("profiler_workflow_token_failure", "manage_tokens", step_tokens, "agent_token_refresh")

    # Step 4: Handle failures
    def step_failures(ctx):
        fh.register_handler("etl-pipeline", strategy="retry", max_retries=3)
        fh.record_failure("etl-pipeline", "transform", error="timeout")
        ctx["recovery_action"] = fh.get_recovery_action("etl-pipeline")
        ctx["failure_count"] = fh.get_failure_count("etl-pipeline")
        return ctx
    bus.add_step("profiler_workflow_token_failure", "handle_failures", step_failures, "pipeline_failure_handler")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["profile_count"] == 2
        assert ctx["avg_time"] >= 0.0
        assert ctx["current_step"] == "transform"
        assert ctx["is_complete"] is False
        assert ctx["token_valid"] is True
        assert ctx["remaining_ttl"] > 3500.0
        assert ctx["refreshed_token"] == "tok-new456"
        assert ctx["recovery_action"] == "retry"
        assert ctx["failure_count"] == 1
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("profiler_workflow_token_failure", "verify", step_verify, "integration")

    result = bus.execute("profiler_workflow_token_failure", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 67 -- profiler-workflow-token-failure pipeline")


