def test_chain70_step_validator_router_events():
    """Validate step schemas, route outputs, aggregate events."""
    bus = PipelineIntegrationBus()
    sv = PipelineStepValidator()
    pr = PipelineOutputRouter()
    ea = PipelineEventAggregator()

    bus.register_chain("step_validator_router_events", tags=["phase43"])

    # Step 1: Define schemas
    def step_define(ctx):
        sv.define_schema("etl", "extract",
                         input_fields={"url": "str", "timeout": "int"},
                         output_fields={"data": "list"})
        sv.define_schema("etl", "transform",
                         input_fields={"data": "list"},
                         output_fields={"result": "dict"})
        ctx["schema_count"] = sv.get_schema_count()
        return ctx
    bus.add_step("step_validator_router_events", "define_schemas", step_define, "pipeline_step_validator")

    # Step 2: Validate inputs
    def step_validate(ctx):
        r1 = sv.validate_input("etl", "extract", {"url": "http://api.com", "timeout": 30})
        r2 = sv.validate_input("etl", "extract", {"url": "http://api.com"})
        ctx["valid_input"] = r1["valid"]
        ctx["invalid_input"] = r2["valid"]
        ctx["error_count"] = len(r2["errors"])
        return ctx
    bus.add_step("step_validator_router_events", "validate", step_validate, "pipeline_step_validator")

    # Step 3: Route outputs
    def step_route(ctx):
        pr.add_route("etl", "results", "database")
        pr.add_route("etl", "results", "cache")
        dests = pr.route_output("etl", "results", {"data": [1, 2, 3]})
        ctx["routed_to"] = dests
        return ctx
    bus.add_step("step_validator_router_events", "route_outputs", step_route, "pipeline_output_router")

    # Step 4: Record events
    def step_events(ctx):
        ea.record_event("etl", "schema_defined")
        ea.record_event("etl", "validation_passed")
        ea.record_event("etl", "output_routed")
        ctx["event_total"] = ea.get_event_count("etl")
        return ctx
    bus.add_step("step_validator_router_events", "events", step_events, "pipeline_event_aggregator")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["schema_count"] == 2
        assert ctx["valid_input"] is True
        assert ctx["invalid_input"] is False
        assert ctx["error_count"] >= 1
        assert len(ctx["routed_to"]) == 2
        assert ctx["event_total"] == 3
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("step_validator_router_events", "verify", step_verify, "integration")

    result = bus.execute("step_validator_router_events", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 70 -- step-validator-router-events pipeline")


