# =====================================================================
# Chain 71: Cache-Alerts-Logs-Heartbeat Pipeline (Phase 44)
# =====================================================================

def test_chain71_cache_alerts_logs_heartbeat():
    """Invalidate caches, dispatch alerts, collect logs, track heartbeats."""
    bus = PipelineIntegrationBus()
    ci = PipelineCacheInvalidator()
    ad = AgentAlertDispatcher()
    lc = PipelineLogCollector()
    ht = AgentHeartbeatTracker()

    bus.register_chain("cache_alerts_logs_heartbeat", tags=["phase44"])

    # Step 1: Register and invalidate caches
    def step_cache(ctx):
        ci.register_cache("etl", "transform_cache", ttl_seconds=600.0)
        ci.register_cache("etl", "lookup_cache", ttl_seconds=300.0)
        ctx["valid_before"] = ci.is_valid("etl", "transform_cache")
        ci.invalidate("etl", "transform_cache")
        ctx["valid_after"] = ci.is_valid("etl", "transform_cache")
        ctx["cache_count"] = ci.get_cache_count()
        return ctx
    bus.add_step("cache_alerts_logs_heartbeat", "manage_cache", step_cache, "pipeline_cache_invalidator")

    # Step 2: Dispatch alerts
    def step_alerts(ctx):
        ad.send_alert("worker-1", "info", "Cache invalidated")
        aid = ad.send_alert("worker-1", "warning", "High memory usage", alert_type="resource")
        ad.acknowledge_alert(aid)
        ctx["unacked"] = ad.get_unacknowledged_count("worker-1")
        ctx["total_alerts"] = ad.get_alert_count()
        return ctx
    bus.add_step("cache_alerts_logs_heartbeat", "dispatch_alerts", step_alerts, "agent_alert_dispatcher")

    # Step 3: Collect logs
    def step_logs(ctx):
        lc.log("etl", "info", "Pipeline started", step_name="init")
        lc.log("etl", "info", "Cache invalidated", step_name="cache")
        lc.log("etl", "warning", "Slow query detected", step_name="transform")
        ctx["log_count"] = lc.get_log_count("etl")
        latest = lc.get_latest_log("etl")
        ctx["latest_log_level"] = latest["level"]
        return ctx
    bus.add_step("cache_alerts_logs_heartbeat", "collect_logs", step_logs, "pipeline_log_collector")

    # Step 4: Track heartbeats
    def step_heartbeat(ctx):
        ht.register_agent("worker-1", interval_seconds=3600.0)
        ht.record_heartbeat("worker-1")
        ctx["responsive"] = ht.is_responsive("worker-1")
        ctx["agent_count"] = ht.get_agent_count()
        return ctx
    bus.add_step("cache_alerts_logs_heartbeat", "track_heartbeat", step_heartbeat, "agent_heartbeat_tracker")

    # Step 5: Verify
    def step_verify(ctx):
        assert ctx["valid_before"] is True
        assert ctx["valid_after"] is False
        assert ctx["cache_count"] == 2
        assert ctx["unacked"] == 1
        assert ctx["total_alerts"] == 2
        assert ctx["log_count"] == 3
        assert ctx["latest_log_level"] == "warning"
        assert ctx["responsive"] is True
        assert ctx["agent_count"] >= 1
        ctx["chain_complete"] = True
        return ctx
    bus.add_step("cache_alerts_logs_heartbeat", "verify", step_verify, "integration")

    result = bus.execute("cache_alerts_logs_heartbeat", {})
    assert result["success"] is True
    assert result["context"]["chain_complete"] is True
    print("OK: chain 71 -- cache-alerts-logs-heartbeat pipeline")


