# =====================================================================
# Chain 72: Workload-Results-ConnPool-NotifQueue Pipeline (Phase 45)
# =====================================================================
def test_chain72_workload_results_connpool_notifqueue():
    bus = PipelineIntegrationBus()
    wt = AgentWorkloadTracker()
    rs = PipelineResultStore()
    cp = AgentConnectionPool()
    nq = PipelineNotificationQueue()

    bus.register_chain("workload_results_connpool_notifqueue", tags=["phase45"])

    def step_workload(ctx):
        wt.assign_task("agent-72", "extract")
        ctx["active_tasks"] = len(wt.get_active_tasks("agent-72"))
        return ctx
    bus.add_step("workload_results_connpool_notifqueue", "assign_workload", step_workload, "agent_workload_tracker")

    def step_results(ctx):
        rid = rs.store_result("pipe-72", "extract", {"rows": ctx["active_tasks"] * 50})
        result = rs.get_result(rid)
        ctx["result_rows"] = result["result_data"]["rows"]
        return ctx
    bus.add_step("workload_results_connpool_notifqueue", "store_result", step_results, "pipeline_result_store")

    def step_connpool(ctx):
        cp.create_pool("agent-72", max_connections=5)
        cp.acquire("agent-72")
        ctx["available"] = cp.get_available("agent-72")
        return ctx
    bus.add_step("workload_results_connpool_notifqueue", "manage_pool", step_connpool, "agent_connection_pool")

    def step_notifqueue(ctx):
        nq.enqueue("pipe-72", "info", f"Processed {ctx['result_rows']} rows", priority=1)
        nq.enqueue("pipe-72", "alert", "High priority alert", priority=10)
        item = nq.dequeue("pipe-72")
        ctx["top_message"] = item["message"]
        return ctx
    bus.add_step("workload_results_connpool_notifqueue", "queue_notifications", step_notifqueue, "pipeline_notification_queue")

    def step_complete(ctx):
        wt.complete_task("agent-72", "extract")
        cp.release("agent-72")
        ctx["completed"] = wt.get_completed_count("agent-72")
        ctx["pool_available"] = cp.get_available("agent-72")
        return ctx
    bus.add_step("workload_results_connpool_notifqueue", "cleanup", step_complete, "agent_workload_tracker")

    result = bus.execute("workload_results_connpool_notifqueue", {})
    assert result["success"] is True
    assert result["context"]["active_tasks"] == 1
    assert result["context"]["result_rows"] == 50
    assert result["context"]["available"] == 4
    assert result["context"]["top_message"] == "High priority alert"
    assert result["context"]["completed"] == 1
    assert result["context"]["pool_available"] == 5
    assert result["steps_completed"] == 5
    print("OK: chain 72 -- workload_results_connpool_notifqueue (Phase 45)")


