# =====================================================================
# Chain 73: Prioritizer-Merger-Cooldown-Router Pipeline (Phase 46)
# =====================================================================
def test_chain73_prioritizer_merger_cooldown_router():
    bus = PipelineIntegrationBus()
    tp = AgentTaskPrioritizer()
    dm = PipelineDataMerger()
    cm = AgentCooldownManager()
    br = PipelineBranchRouter()

    bus.register_chain("prioritizer_merger_cooldown_router", tags=["phase46"])

    def step_prioritize(ctx):
        tp.set_priority("agent-73", "extract", priority=10)
        tp.set_priority("agent-73", "transform", priority=5)
        tp.set_priority("agent-73", "load", priority=1)
        top = tp.get_top_tasks("agent-73", limit=1)
        ctx["top_task"] = top[0]["task_name"]
        return ctx
    bus.add_step("prioritizer_merger_cooldown_router", "prioritize", step_prioritize, "agent_task_prioritizer")

    def step_merge(ctx):
        mid = dm.create_merge("pipe-73", ["src_a", "src_b"], strategy="concat")
        result = dm.execute_merge(mid, [[1, 2], [3, 4]])
        ctx["merged_count"] = len(result["result"])
        return ctx
    bus.add_step("prioritizer_merger_cooldown_router", "merge_data", step_merge, "pipeline_data_merger")

    def step_cooldown(ctx):
        cm.start_cooldown("agent-73", "deploy", duration_seconds=3600.0)
        ctx["can_deploy"] = cm.is_cooled_down("agent-73", "deploy")
        ctx["can_build"] = cm.is_cooled_down("agent-73", "build")
        return ctx
    bus.add_step("prioritizer_merger_cooldown_router", "check_cooldown", step_cooldown, "agent_cooldown_manager")

    def step_route(ctx):
        br.add_branch("pipe-73", "top_task", "extract", "run_extract")
        br.add_branch("pipe-73", "top_task", "transform", "run_transform")
        target = br.route("pipe-73", ctx)
        ctx["routed_to"] = target
        return ctx
    bus.add_step("prioritizer_merger_cooldown_router", "route_branch", step_route, "pipeline_branch_router")

    result = bus.execute("prioritizer_merger_cooldown_router", {})
    assert result["success"] is True
    assert result["context"]["top_task"] == "extract"
    assert result["context"]["merged_count"] == 4
    assert result["context"]["can_deploy"] is False  # in cooldown
    assert result["context"]["can_build"] is True    # no cooldown
    assert result["context"]["routed_to"] == "run_extract"
    assert result["steps_completed"] == 4
    print("OK: chain 73 -- prioritizer_merger_cooldown_router (Phase 46)")


