# =====================================================================
# Chain 74: RateLimit-Splitter-Cache-Timer Pipeline (Phase 47)
# =====================================================================
def test_chain74_ratelimit_splitter_cache_timer():
    bus = PipelineIntegrationBus()
    rl = AgentRateLimiter()
    ds = PipelineDataSplitter()
    sc = AgentSessionCache()
    st = PipelineStepTimer()

    bus.register_chain("ratelimit_splitter_cache_timer", tags=["phase47"])

    def step_ratelimit(ctx):
        rl.configure("agent-74", "process", max_requests=10, window_seconds=60.0)
        ctx["allowed"] = rl.is_allowed("agent-74", "process")
        ctx["remaining"] = rl.get_remaining("agent-74", "process")
        return ctx
    bus.add_step("ratelimit_splitter_cache_timer", "check_rate", step_ratelimit, "agent_rate_limiter")

    def step_split(ctx):
        sid = ds.create_splitter("pipe-74", strategy="chunks", chunk_size=3)
        chunks = ds.split(sid, [1, 2, 3, 4, 5, 6, 7, 8])
        ctx["chunk_count"] = len(chunks)
        ctx["first_chunk"] = chunks[0]
        return ctx
    bus.add_step("ratelimit_splitter_cache_timer", "split_data", step_split, "pipeline_data_splitter")

    def step_cache(ctx):
        sc.cache_set("agent-74", "chunk_count", ctx["chunk_count"], ttl_seconds=300.0)
        ctx["cached_count"] = sc.cache_get("agent-74", "chunk_count")
        return ctx
    bus.add_step("ratelimit_splitter_cache_timer", "cache_result", step_cache, "agent_session_cache")

    def step_timer(ctx):
        st.start_timer("pipe-74", "process")
        st.stop_timer("pipe-74", "process")
        ctx["elapsed"] = st.get_elapsed("pipe-74", "process")
        return ctx
    bus.add_step("ratelimit_splitter_cache_timer", "time_step", step_timer, "pipeline_step_timer")

    result = bus.execute("ratelimit_splitter_cache_timer", {})
    assert result["success"] is True
    assert result["context"]["allowed"] is True
    assert result["context"]["remaining"] == 9
    assert result["context"]["chunk_count"] == 3  # [1,2,3], [4,5,6], [7,8]
    assert result["context"]["first_chunk"] == [1, 2, 3]
    assert result["context"]["cached_count"] == 3
    assert result["context"]["elapsed"] >= 0.0
    assert result["steps_completed"] == 4
    print("OK: chain 74 -- ratelimit_splitter_cache_timer (Phase 47)")


