# =====================================================================
# Chain 75: Quota-Enricher-ErrorBuffer-Retry Pipeline (Phase 48)
# =====================================================================
def test_chain75_quota_enricher_errbuf_retry():
    bus = PipelineIntegrationBus()
    qt = AgentQuotaTracker()
    de = PipelineDataEnricher()
    eb = AgentErrorBuffer()
    sr = PipelineStepRetry()

    bus.register_chain("quota_enricher_errbuf_retry", tags=["phase48"])

    def step_quota(ctx):
        qt.set_quota("agent-75", "requests", 100)
        qt.use_quota("agent-75", "requests", 10)
        ctx["remaining"] = qt.get_remaining_quota("agent-75", "requests")
        return ctx
    bus.add_step("quota_enricher_errbuf_retry", "check_quota", step_quota, "agent_quota_tracker")

    def step_enrich(ctx):
        de.register_enricher("pipe-75", "status", default_value="processed")
        de.register_enricher("pipe-75", "region", default_value="us-west", transform="upper")
        enriched = de.enrich("pipe-75", {"data": ctx["remaining"]})
        ctx["enriched_status"] = enriched["status"]
        ctx["enriched_region"] = enriched["region"]
        return ctx
    bus.add_step("quota_enricher_errbuf_retry", "enrich_data", step_enrich, "pipeline_data_enricher")

    def step_errors(ctx):
        eb.record_error("agent-75", "validation", "Field missing", severity="warning")
        eb.record_error("agent-75", "timeout", "Connection lost", severity="error")
        ctx["error_count"] = eb.get_error_count("agent-75")
        ctx["latest_error"] = eb.get_latest_error("agent-75")["error_type"]
        return ctx
    bus.add_step("quota_enricher_errbuf_retry", "buffer_errors", step_errors, "agent_error_buffer")

    def step_retry(ctx):
        sr.configure_retry("pipe-75", "extract", max_retries=3)
        sr.record_attempt("pipe-75", "extract", success=False)
        ctx["should_retry"] = sr.should_retry("pipe-75", "extract")
        ctx["attempts"] = sr.get_attempt_count("pipe-75", "extract")
        return ctx
    bus.add_step("quota_enricher_errbuf_retry", "manage_retry", step_retry, "pipeline_step_retry")

    result = bus.execute("quota_enricher_errbuf_retry", {})
    assert result["success"] is True
    assert result["context"]["remaining"] == 90
    assert result["context"]["enriched_status"] == "processed"
    assert result["context"]["enriched_region"] == "US-WEST"
    assert result["context"]["error_count"] == 2
    assert result["context"]["latest_error"] == "timeout"
    assert result["context"]["should_retry"] is True
    assert result["context"]["attempts"] == 1
    assert result["steps_completed"] == 4
    print("OK: chain 75 -- quota_enricher_errbuf_retry (Phase 48)")


