# =====================================================================
# Chain 78: Lock-Sampler-Replay-Condition Pipeline (Phase 51)
# =====================================================================
def test_chain78_lock_sampler_replay_condition():
    """Agent acquires lock, samples data, replays events, evaluates conditions."""
    bus = PipelineIntegrationBus()
    lm = AgentLockManager()
    ds = PipelineDataSampler()
    er = AgentEventReplay()
    sc = PipelineStepCondition()

    bus.register_chain("chain78_lock_sample_replay_cond", tags=["phase51"])

    def step_lock(ctx):
        lid = lm.acquire_lock("agent-78", "database")
        ctx["lock_acquired"] = len(lid) > 0
        ctx["lock_holder"] = lm.get_lock_holder("database")
        return ctx
    bus.add_step("chain78_lock_sample_replay_cond", "lock", step_lock, "agent_lock_manager")

    def step_sample(ctx):
        sid = ds.create_sampler("pipe-78", strategy="first_n", sample_size=3)
        result = ds.sample(sid, [10, 20, 30, 40, 50])
        ctx["sampled"] = result
        return ctx
    bus.add_step("chain78_lock_sample_replay_cond", "sample", step_sample, "pipeline_data_sampler")

    def step_replay(ctx):
        er.record_event("agent-78", "lock_acquired", {"resource": "database"})
        er.record_event("agent-78", "data_sampled", {"count": len(ctx["sampled"])})
        events = er.replay("agent-78")
        ctx["event_count"] = len(events)
        return ctx
    bus.add_step("chain78_lock_sample_replay_cond", "replay", step_replay, "agent_event_replay")

    def step_condition(ctx):
        sc.add_condition("pipe-78", "deploy", "env", "eq", "prod")
        ctx["cond_pass"] = sc.evaluate("pipe-78", "deploy", {"env": "prod"})
        ctx["cond_fail"] = sc.evaluate("pipe-78", "deploy", {"env": "staging"})
        lm.release_lock("agent-78", "database")
        ctx["lock_released"] = not lm.is_locked("database")
        return ctx
    bus.add_step("chain78_lock_sample_replay_cond", "condition", step_condition, "pipeline_step_condition")

    result = bus.execute("chain78_lock_sample_replay_cond", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["lock_acquired"] is True
    assert ctx["lock_holder"] == "agent-78"
    assert ctx["sampled"] == [10, 20, 30]
    assert ctx["event_count"] == 2
    assert ctx["cond_pass"] is True
    assert ctx["cond_fail"] is False
    assert ctx["lock_released"] is True
    print("OK: chain 78 -- lock_sampler_replay_condition (Phase 51)")


