# =====================================================================
# Chain 79: DepResolver-ExecLog-MsgBroker-OutBuf Pipeline (Phase 52)
# =====================================================================
def test_chain79_depresolver_execlog_msgbroker_outbuf():
    """Resolve dependencies, log execution, broker messages, buffer output."""
    bus = PipelineIntegrationBus()
    dr = AgentDependencyResolver()
    el = PipelineExecutionLog()
    mb = AgentMessageBroker()
    ob = PipelineOutputBuffer()

    bus.register_chain("chain79_dep_log_msg_buf", tags=["phase52"])

    def step_deps(ctx):
        dr.add_dependency("taskB", "taskA")
        dr.add_dependency("taskC", "taskB")
        ctx["taskA_resolved"] = dr.is_resolved("taskA", set())
        ctx["taskB_resolved"] = dr.is_resolved("taskB", {"taskA"})
        ctx["taskC_resolved"] = dr.is_resolved("taskC", {"taskA"})
        ready = dr.resolve_order(["taskA", "taskB", "taskC"], {"taskA"})
        ctx["ready_tasks"] = ready
        return ctx
    bus.add_step("chain79_dep_log_msg_buf", "deps", step_deps, "agent_dependency_resolver")

    def step_log(ctx):
        el.log_entry("pipe-79", "resolve", "start", "resolving deps")
        el.log_entry("pipe-79", "resolve", "complete", "deps resolved")
        ctx["log_count"] = el.get_entry_count("pipe-79")
        return ctx
    bus.add_step("chain79_dep_log_msg_buf", "log", step_log, "pipeline_execution_log")

    def step_broker(ctx):
        mb.subscribe("agent-79", "results")
        mb.publish("agent-79", "results", "deps resolved", {"count": len(ctx["ready_tasks"])})
        msgs = mb.get_messages("results")
        ctx["msg_count"] = len(msgs)
        return ctx
    bus.add_step("chain79_dep_log_msg_buf", "broker", step_broker, "agent_message_broker")

    def step_buffer(ctx):
        bid = ob.create_buffer("pipe-79", "output", max_size=10)
        ob.write(bid, {"ready": ctx["ready_tasks"]})
        ob.write(bid, {"msgs": ctx["msg_count"]})
        items = ob.flush(bid)
        ctx["buffered_count"] = len(items)
        ctx["buffer_empty"] = ob.get_buffer_size(bid) == 0
        return ctx
    bus.add_step("chain79_dep_log_msg_buf", "buffer", step_buffer, "pipeline_output_buffer")

    result = bus.execute("chain79_dep_log_msg_buf", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["taskA_resolved"] is True
    assert ctx["taskB_resolved"] is True
    assert ctx["taskC_resolved"] is False
    assert "taskA" in ctx["ready_tasks"] and "taskB" in ctx["ready_tasks"]
    assert ctx["log_count"] == 2
    assert ctx["msg_count"] == 1
    assert ctx["buffered_count"] == 2
    assert ctx["buffer_empty"] is True
    print("OK: chain 79 -- depresolver_execlog_msgbroker_outbuf (Phase 52)")


