# =====================================================================
# Chain 80: Retry-Snapshot-Alert-Cache Pipeline (Phase 53)
# =====================================================================
def test_chain80_retry_snapshot_alert_cache():
    """Set retry policy, snapshot state, raise alert, cache data."""
    bus = PipelineIntegrationBus()
    rp = AgentRetryPolicy()
    ss = PipelineStateSnapshot()
    am = AgentAlertManager()
    dc = PipelineDataCache()

    bus.register_chain("chain80_retry_snap_alert_cache", tags=["phase53"])

    def step_retry(ctx):
        rp.create_policy("agent-80", "fetch", max_retries=3, backoff_factor=2.0)
        ctx["should_retry_1"] = rp.should_retry("agent-80", "fetch", 1)
        ctx["should_retry_4"] = rp.should_retry("agent-80", "fetch", 4)
        ctx["backoff_2"] = rp.get_backoff("agent-80", "fetch", 2)
        return ctx
    bus.add_step("chain80_retry_snap_alert_cache", "retry", step_retry, "agent_retry_policy")

    def step_snapshot(ctx):
        ss.take_snapshot("pipe-80", {"step": "retry", "done": True}, label="after-retry")
        snap = ss.get_latest_snapshot("pipe-80")
        ctx["snap_label"] = snap["label"] if snap else ""
        ctx["snap_state"] = snap["state_data"] if snap else {}
        return ctx
    bus.add_step("chain80_retry_snap_alert_cache", "snapshot", step_snapshot, "pipeline_state_snapshot")

    def step_alert(ctx):
        aid = am.raise_alert("agent-80", "high_latency", "response slow", severity="warning")
        ctx["alert_raised"] = len(aid) > 0
        ctx["active_alerts"] = len(am.get_active_alerts("agent-80"))
        am.acknowledge_alert(aid)
        ctx["active_after_ack"] = len(am.get_active_alerts("agent-80"))
        return ctx
    bus.add_step("chain80_retry_snap_alert_cache", "alert", step_alert, "agent_alert_manager")

    def step_cache(ctx):
        dc.cache_set("pipe-80", "result", {"status": "ok", "alerts": ctx["active_after_ack"]})
        cached = dc.cache_get("pipe-80", "result")
        ctx["cached_status"] = cached["status"] if cached else ""
        ctx["cache_size"] = dc.get_cache_size("pipe-80")
        return ctx
    bus.add_step("chain80_retry_snap_alert_cache", "cache", step_cache, "pipeline_data_cache")

    result = bus.execute("chain80_retry_snap_alert_cache", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["should_retry_1"] is True
    assert ctx["should_retry_4"] is False
    assert abs(ctx["backoff_2"] - 4.0) < 0.01
    assert ctx["snap_label"] == "after-retry"
    assert ctx["alert_raised"] is True
    assert ctx["active_alerts"] == 1
    assert ctx["active_after_ack"] == 0
    assert ctx["cached_status"] == "ok"
    assert ctx["cache_size"] == 1
    print("OK: chain 80 -- retry_snapshot_alert_cache (Phase 53)")


