# =====================================================================
# Chain 81: ErrHandler-PermCache-Audit-Hook Pipeline (Phase 54)
# =====================================================================
def test_chain81_errhandler_permcache_audit_hook():
    """Handle errors, check permissions, audit actions, run hooks."""
    bus = PipelineIntegrationBus()
    eh = PipelineErrorHandler()
    pc = AgentPermissionCache()
    at = AgentAuditTrail()
    sh = PipelineStepHook()

    bus.register_chain("chain81_err_perm_audit_hook", tags=["phase54"])

    def step_errors(ctx):
        eh.record_error("pipe-81", "validate", "schema_error", "invalid field", severity="warning")
        eh.record_error("pipe-81", "transform", "type_error", "wrong type", severity="error")
        summary = eh.get_error_summary("pipe-81")
        ctx["error_count"] = eh.get_error_count("pipe-81")
        ctx["has_summary"] = len(summary) > 0
        return ctx
    bus.add_step("chain81_err_perm_audit_hook", "errors", step_errors, "pipeline_error_handler")

    def step_perms(ctx):
        pc.grant("agent-81", "database", "write")
        pc.grant("agent-81", "cache", "read")
        ctx["can_write_db"] = pc.is_allowed("agent-81", "database", "write")
        ctx["can_write_cache"] = pc.is_allowed("agent-81", "cache", "write")
        ctx["perm_count"] = pc.get_permission_count("agent-81")
        return ctx
    bus.add_step("chain81_err_perm_audit_hook", "perms", step_perms, "agent_permission_cache")

    def step_audit(ctx):
        at.record("agent-81", "check_perms", "database", {"result": ctx["can_write_db"]})
        at.record("agent-81", "handle_errors", "pipe-81", {"count": ctx["error_count"]})
        ctx["audit_count"] = at.get_entry_count("agent-81")
        return ctx
    bus.add_step("chain81_err_perm_audit_hook", "audit", step_audit, "agent_audit_trail")

    def step_hooks(ctx):
        hook_log = []
        sh.register_hook("pipe-81", "finalize", "pre", lambda c: hook_log.append("pre"), label="pre-final")
        sh.register_hook("pipe-81", "finalize", "post", lambda c: hook_log.append("post"), label="post-final")
        sh.execute_hooks("pipe-81", "finalize", "pre", {})
        sh.execute_hooks("pipe-81", "finalize", "post", {})
        ctx["hooks_fired"] = len(hook_log)
        ctx["hook_count"] = sh.get_hook_count("pipe-81")
        return ctx
    bus.add_step("chain81_err_perm_audit_hook", "hooks", step_hooks, "pipeline_step_hook")

    result = bus.execute("chain81_err_perm_audit_hook", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["error_count"] == 2
    assert ctx["has_summary"] is True
    assert ctx["can_write_db"] is True
    assert ctx["can_write_cache"] is False
    assert ctx["perm_count"] == 2
    assert ctx["audit_count"] == 2
    assert ctx["hooks_fired"] == 2
    assert ctx["hook_count"] == 2
    print("OK: chain 81 -- errhandler_permcache_audit_hook (Phase 54)")


