# Chain 82: Normalizer-Tracker-Counter-Flag Pipeline (Phase 55)
# =====================================================================
def test_chain82_normalizer_tracker_counter_flag():
    """Normalize data, track task, count steps, check feature flags."""
    bus = PipelineIntegrationBus()
    dn = PipelineDataNormalizer()
    tt = AgentTaskTracker()
    sc = PipelineStepCounter()
    ff = AgentFeatureFlag()

    bus.register_chain("chain82_norm_track_count_flag", tags=["phase55"])

    def step_normalize(ctx):
        dn.add_rule("pipe-82", "name", "lowercase")
        dn.add_rule("pipe-82", "code", "uppercase")
        result = dn.normalize("pipe-82", {"name": "HELLO World", "code": "abc"})
        ctx["norm_name"] = result["name"]
        ctx["norm_code"] = result["code"]
        return ctx
    bus.add_step("chain82_norm_track_count_flag", "normalize", step_normalize, "pipeline_data_normalizer")

    def step_track(ctx):
        tid = tt.start_task("agent-82", "process_data", total_steps=4)
        tt.update_progress(tid, 2)
        ctx["progress"] = tt.get_progress(tid)
        tt.complete_task(tid)
        task = tt.get_task(tid)
        ctx["task_status"] = task["status"] if task else ""
        return ctx
    bus.add_step("chain82_norm_track_count_flag", "track", step_track, "agent_task_tracker")

    def step_count(ctx):
        sc.increment("pipe-82", "normalize", 1)
        sc.increment("pipe-82", "track", 1)
        sc.increment("pipe-82", "normalize", 1)
        ctx["norm_count"] = sc.get_count("pipe-82", "normalize")
        ctx["total"] = sc.get_total("pipe-82")
        return ctx
    bus.add_step("chain82_norm_track_count_flag", "count", step_count, "pipeline_step_counter")

    def step_flag(ctx):
        ff.set_flag("agent-82", "advanced_mode", True)
        ff.set_flag("agent-82", "debug_mode", False)
        ctx["advanced"] = ff.is_enabled("agent-82", "advanced_mode")
        ctx["debug"] = ff.is_enabled("agent-82", "debug_mode")
        ctx["unknown"] = ff.is_enabled("agent-82", "nonexistent")
        return ctx
    bus.add_step("chain82_norm_track_count_flag", "flag", step_flag, "agent_feature_flag")

    result = bus.execute("chain82_norm_track_count_flag", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["norm_name"] == "hello world"
    assert ctx["norm_code"] == "ABC"
    assert abs(ctx["progress"] - 0.5) < 0.01
    assert ctx["task_status"] == "completed"
    assert ctx["norm_count"] == 2
    assert ctx["total"] == 3
    assert ctx["advanced"] is True
    assert ctx["debug"] is False
    assert ctx["unknown"] is False
    print("OK: chain 82 -- normalizer_tracker_counter_flag (Phase 55)")


