# =====================================================================
# Chain 83: RespCache-Dedup-Distrib-StepDep Pipeline (Phase 56)
# =====================================================================
def test_chain83_respcache_dedup_distrib_stepdep():
    """Cache responses, deduplicate data, distribute work, manage step deps."""
    bus = PipelineIntegrationBus()
    rc = AgentResponseCache()
    dd = PipelineDataDeduplicator()
    wd = AgentWorkDistributor()
    sd = PipelineStepDependency()

    bus.register_chain("chain83_cache_dedup_dist_dep", tags=["phase56"])

    def step_cache(ctx):
        rc.cache_response("agent-83", "query1", {"answer": 42})
        ctx["cached"] = rc.has_response("agent-83", "query1")
        ctx["cached_val"] = rc.get_response("agent-83", "query1")["answer"]
        return ctx
    bus.add_step("chain83_cache_dedup_dist_dep", "cache", step_cache, "agent_response_cache")

    def step_dedup(ctx):
        dd.configure("pipe-83", "id")
        records = [{"id": 1, "v": "a"}, {"id": 2, "v": "b"}, {"id": 1, "v": "c"}]
        unique = dd.deduplicate("pipe-83", records)
        ctx["unique_count"] = len(unique)
        return ctx
    bus.add_step("chain83_cache_dedup_dist_dep", "dedup", step_dedup, "pipeline_data_deduplicator")

    def step_distribute(ctx):
        wd.register_agents("group-83", ["worker-a", "worker-b", "worker-c"], strategy="round_robin")
        a1 = wd.distribute("group-83", "task1")
        a2 = wd.distribute("group-83", "task2")
        a3 = wd.distribute("group-83", "task3")
        ctx["assignments"] = [a1, a2, a3]
        ctx["all_different"] = len(set([a1, a2, a3])) == 3
        return ctx
    bus.add_step("chain83_cache_dedup_dist_dep", "distribute", step_distribute, "agent_work_distributor")

    def step_deps(ctx):
        sd.add_dependency("pipe-83", "transform", "extract")
        sd.add_dependency("pipe-83", "load", "transform")
        ctx["extract_ready"] = sd.is_ready("pipe-83", "extract", set())
        ctx["transform_ready"] = sd.is_ready("pipe-83", "transform", {"extract"})
        ctx["load_ready"] = sd.is_ready("pipe-83", "load", {"extract"})
        order = sd.get_execution_order("pipe-83")
        ctx["exec_order"] = order
        return ctx
    bus.add_step("chain83_cache_dedup_dist_dep", "deps", step_deps, "pipeline_step_dependency")

    result = bus.execute("chain83_cache_dedup_dist_dep", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["cached"] is True
    assert ctx["cached_val"] == 42
    assert ctx["unique_count"] == 2
    assert ctx["all_different"] is True
    assert ctx["extract_ready"] is True
    assert ctx["transform_ready"] is True
    assert ctx["load_ready"] is False
    assert len(ctx["exec_order"]) == 3
    print("OK: chain 83 -- respcache_dedup_distrib_stepdep (Phase 56)")


