# Chain 84: Scheduler-Decision-Joiner-Label Pipeline (Phase 57)
# =====================================================================
def test_chain84_scheduler_decision_joiner_label():
    """Schedule steps, log decisions, join data, manage labels."""
    bus = PipelineIntegrationBus()
    ss = PipelineStepScheduler()
    dl = AgentDecisionLogger()
    dj = PipelineDataJoiner()
    lm = AgentLabelManager()

    bus.register_chain("chain84_sched_decide_join_label", tags=["phase57"])

    def step_schedule(ctx):
        s1 = ss.schedule_step("pipe-84", "extract", priority=10)
        s2 = ss.schedule_step("pipe-84", "transform", priority=5)
        pending = ss.get_pending("pipe-84")
        ctx["first_pending"] = pending[0]["step_name"] if pending else ""
        ss.mark_running(s1)
        ss.mark_completed(s1)
        ctx["schedule_count"] = ss.get_schedule_count("pipe-84")
        return ctx
    bus.add_step("chain84_sched_decide_join_label", "schedule", step_schedule, "pipeline_step_scheduler")

    def step_decide(ctx):
        dl.log_decision("agent-84", "use_parallel", reasoning="faster", alternatives=["sequential"], outcome="success")
        ctx["decision_count"] = dl.get_decision_count("agent-84")
        return ctx
    bus.add_step("chain84_sched_decide_join_label", "decide", step_decide, "agent_decision_logger")

    def step_join(ctx):
        jid = dj.create_join("pipe-84", "id", join_type="inner")
        left = [{"id": 1, "name": "A"}, {"id": 2, "name": "B"}]
        right = [{"id": 1, "score": 90}, {"id": 3, "score": 70}]
        result = dj.execute_join(jid, left, right)
        ctx["joined_count"] = len(result)
        return ctx
    bus.add_step("chain84_sched_decide_join_label", "join", step_join, "pipeline_data_joiner")

    def step_label(ctx):
        lm.add_label("agent-84", "gpu-capable")
        lm.add_label("agent-84", "production")
        ctx["label_count"] = len(lm.get_labels("agent-84"))
        ctx["has_gpu"] = lm.has_label("agent-84", "gpu-capable")
        return ctx
    bus.add_step("chain84_sched_decide_join_label", "label", step_label, "agent_label_manager")

    result = bus.execute("chain84_sched_decide_join_label", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["first_pending"] == "extract"
    assert ctx["schedule_count"] == 2
    assert ctx["decision_count"] == 1
    assert ctx["joined_count"] == 1
    assert ctx["label_count"] == 2
    assert ctx["has_gpu"] is True
    print("OK: chain 84 -- scheduler_decision_joiner_label (Phase 57)")


