def test_chain85_status_sorter_timeout_steplog():
    """Report status, sort data, manage timeouts, log steps."""
    bus = PipelineIntegrationBus()
    sr = AgentStatusReporter()
    ds = PipelineDataSorter()
    tm = AgentTimeoutManager()
    sl = PipelineStepLogger()

    bus.register_chain("chain85_status_sort_timeout_log", tags=["phase58"])

    def step_status(ctx):
        sr.report_status("agent-85", "busy", {"task": "processing"})
        status = sr.get_status("agent-85")
        ctx["agent_status"] = status["status"] if status else ""
        ctx["report_count"] = sr.get_report_count("agent-85")
        return ctx
    bus.add_step("chain85_status_sort_timeout_log", "status", step_status, "agent_status_reporter")

    def step_sort(ctx):
        ds.configure_sort("pipe-85", "score", ascending=False)
        records = [{"name": "A", "score": 3}, {"name": "B", "score": 7}, {"name": "C", "score": 1}]
        sorted_recs = ds.sort_records("pipe-85", records)
        ctx["first_name"] = sorted_recs[0]["name"] if sorted_recs else ""
        return ctx
    bus.add_step("chain85_status_sort_timeout_log", "sort", step_sort, "pipeline_data_sorter")

    def step_timeout(ctx):
        tm.set_timeout("agent-85", "process", 300.0)
        ctx["timed_out"] = tm.is_timed_out("agent-85", "process")
        ctx["remaining"] = tm.get_remaining("agent-85", "process") > 0
        return ctx
    bus.add_step("chain85_status_sort_timeout_log", "timeout", step_timeout, "agent_timeout_manager")

    def step_log(ctx):
        sl.log_step("pipe-85", "process", status="success", duration_ms=150.0)
        ctx["log_count"] = sl.get_log_count("pipe-85")
        latest = sl.get_latest_log("pipe-85")
        ctx["latest_step"] = latest["step_name"] if latest else ""
        return ctx
    bus.add_step("chain85_status_sort_timeout_log", "log", step_log, "pipeline_step_logger")

    result = bus.execute("chain85_status_sort_timeout_log", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["agent_status"] == "busy"
    assert ctx["report_count"] == 1
    assert ctx["first_name"] == "B"
    assert ctx["timed_out"] is False
    assert ctx["remaining"] is True
    assert ctx["log_count"] == 1
    assert ctx["latest_step"] == "process"
    print("OK: chain 85 -- status_sorter_timeout_steplog (Phase 58)")


