# Chain 86: InputVal-Compress-OutFmt-Metric Pipeline (Phase 59)
# =====================================================================
def test_chain86_inputval_compress_outfmt_metric():
    """Validate input, compress data, format output, record metrics."""
    bus = PipelineIntegrationBus()
    iv = AgentInputValidator()
    dc = PipelineDataCompressor()
    of = AgentOutputFormatter()
    sm = PipelineStepMetric()

    bus.register_chain("chain86_val_comp_fmt_metric", tags=["phase59"])

    def step_validate(ctx):
        iv.add_rule("agent-86", "name", "required")
        iv.add_rule("agent-86", "age", "min", 0)
        result = iv.validate("agent-86", {"name": "test", "age": 5})
        ctx["valid"] = result["valid"]
        ctx["errors"] = result["errors"]
        return ctx
    bus.add_step("chain86_val_comp_fmt_metric", "validate", step_validate, "agent_input_validator")

    def step_compress(ctx):
        dc.configure("pipe-86", strategy="base64")
        compressed = dc.compress("pipe-86", "hello world")
        decompressed = dc.decompress("pipe-86", compressed)
        ctx["roundtrip_ok"] = decompressed == "hello world"
        return ctx
    bus.add_step("chain86_val_comp_fmt_metric", "compress", step_compress, "pipeline_data_compressor")

    def step_format(ctx):
        of.configure_format("agent-86", "summary")
        output = of.format_output("agent-86", {"status": "ok", "count": 42})
        ctx["formatted"] = output
        ctx["has_status"] = "status=ok" in output
        return ctx
    bus.add_step("chain86_val_comp_fmt_metric", "format", step_format, "agent_output_formatter")

    def step_metric(ctx):
        sm.record_metric("pipe-86", "validate", 10.0, success=True)
        sm.record_metric("pipe-86", "compress", 5.0, success=True)
        sm.record_metric("pipe-86", "format", 3.0, success=False)
        ctx["avg_validate"] = sm.get_average_duration("pipe-86", "validate")
        ctx["success_rate"] = sm.get_success_rate("pipe-86", "format")
        ctx["total_metrics"] = sm.get_metric_count("pipe-86")
        return ctx
    bus.add_step("chain86_val_comp_fmt_metric", "metric", step_metric, "pipeline_step_metric")

    result = bus.execute("chain86_val_comp_fmt_metric", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["valid"] is True
    assert len(ctx["errors"]) == 0
    assert ctx["roundtrip_ok"] is True
    assert ctx["has_status"] is True
    assert abs(ctx["avg_validate"] - 10.0) < 0.01
    assert abs(ctx["success_rate"] - 0.0) < 0.01
    assert ctx["total_metrics"] == 3
    print("OK: chain 86 -- inputval_compress_outfmt_metric (Phase 59)")


