# Chain 87: Mapper-EnvConfig-StepResult-Tag Pipeline (Phase 60)
# =====================================================================
def test_chain87_mapper_envconfig_stepresult_tag():
    """Map data fields, configure env, store results, manage tags."""
    bus = PipelineIntegrationBus()
    dm = PipelineDataMapper()
    ec = AgentEnvConfig()
    sr = PipelineStepResult()
    tg = AgentTagManager()

    bus.register_chain("chain87_map_env_result_tag", tags=["phase60"])

    def step_map(ctx):
        dm.add_mapping("pipe-87", "user_name", "name", transform="lowercase")
        dm.add_mapping("pipe-87", "user_email", "email", transform="copy")
        result = dm.apply_mappings("pipe-87", {"user_name": "ALICE", "user_email": "a@b.com"})
        ctx["mapped_name"] = result.get("name", "")
        ctx["mapped_email"] = result.get("email", "")
        return ctx
    bus.add_step("chain87_map_env_result_tag", "map", step_map, "pipeline_data_mapper")

    def step_env(ctx):
        ec.set_config("agent-87", "region", "us-east")
        ec.set_config("agent-87", "debug", True)
        ctx["region"] = ec.get_config("agent-87", "region")
        ctx["debug"] = ec.get_config("agent-87", "debug")
        ctx["missing"] = ec.get_config("agent-87", "nonexistent", "default_val")
        return ctx
    bus.add_step("chain87_map_env_result_tag", "env", step_env, "agent_env_config")

    def step_result(ctx):
        sr.store_result("pipe-87", "map", "success", {"mapped": True})
        sr.store_result("pipe-87", "env", "success", {"configured": True})
        ctx["result_count"] = sr.get_result_count("pipe-87")
        latest = sr.get_latest_result("pipe-87")
        ctx["latest_step"] = latest["step_name"] if latest else ""
        return ctx
    bus.add_step("chain87_map_env_result_tag", "result", step_result, "pipeline_step_result")

    def step_tag(ctx):
        tg.add_tag("agent-87", "environment", "production")
        tg.add_tag("agent-87", "team", "platform")
        ctx["has_env"] = tg.has_tag("agent-87", "environment")
        ctx["env_val"] = tg.get_tag_value("agent-87", "environment")
        ctx["tag_count"] = tg.get_tag_count("agent-87")
        return ctx
    bus.add_step("chain87_map_env_result_tag", "tag", step_tag, "agent_tag_manager")

    result = bus.execute("chain87_map_env_result_tag", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    ctx = result["context"]
    assert ctx["mapped_name"] == "alice"
    assert ctx["mapped_email"] == "a@b.com"
    assert ctx["region"] == "us-east"
    assert ctx["debug"] is True
    assert ctx["missing"] == "default_val"
    assert ctx["result_count"] == 2
    assert ctx["latest_step"] == "env"
    assert ctx["has_env"] is True
    assert ctx["env_val"] == "production"
    assert ctx["tag_count"] == 2
    print("OK: chain 87 -- mapper_envconfig_stepresult_tag (Phase 60)")


