# =====================================================================
# Chain 88: Circuit-Breaker-Flattener-RateCtrl-Fallback (Phase 61)
# =====================================================================

def test_chain88_circuit_flattener_ratectrl_fallback():
    """Agent circuit breaker guards, flattener processes, rate controller limits, fallback recovers."""
    bus = PipelineIntegrationBus()
    cb = AgentCircuitBreaker()
    fl = PipelineDataFlattener()
    rc = AgentRateController()
    fb = PipelineStepFallback()

    bus.register_chain("chain88_circuit_flat_rate_fallback", tags=["phase61"])

    def step_circuit(ctx):
        cb.create_circuit("agent-88", "process", failure_threshold=3)
        cb.record_success("agent-88", "process")
        ctx["circuit_state"] = cb.get_state("agent-88", "process")
        return ctx
    bus.add_step("chain88_circuit_flat_rate_fallback", "circuit", step_circuit, "agent_circuit_breaker")

    def step_flatten(ctx):
        fl.configure("pipe-88", separator=".")
        result = fl.flatten("pipe-88", {"a": {"b": 1, "c": {"d": 2}}})
        ctx["flat_keys"] = sorted(result.keys())
        return ctx
    bus.add_step("chain88_circuit_flat_rate_fallback", "flatten", step_flatten, "pipeline_data_flattener")

    def step_rate(ctx):
        rc.set_limit("agent-88", "api_call", max_requests=10, window_seconds=60.0)
        rc.record_request("agent-88", "api_call")
        usage = rc.get_usage("agent-88", "api_call")
        ctx["rate_remaining"] = usage["remaining"]
        return ctx
    bus.add_step("chain88_circuit_flat_rate_fallback", "rate", step_rate, "agent_rate_controller")

    def step_fallback(ctx):
        fb.register_fallback("pipe-88", "transform", fallback_type="default_value")
        fb.set_default_value("pipe-88", "transform", {"status": "fallback"})
        result = fb.execute_fallback("pipe-88", "transform")
        ctx["fallback_result"] = result["result"]
        return ctx
    bus.add_step("chain88_circuit_flat_rate_fallback", "fallback", step_fallback, "pipeline_step_fallback")

    result = bus.execute("chain88_circuit_flat_rate_fallback", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["circuit_state"] == "closed"
    assert result["context"]["flat_keys"] == ["a.b", "a.c.d"]
    assert result["context"]["rate_remaining"] == 9
    assert result["context"]["fallback_result"] == {"status": "fallback"}
    print("OK: chain 88 -- circuit_flattener_ratectrl_fallback (Phase 61)")


