# Chain 89: Window-BatchSched-Interceptor-ResourceQuota (Phase 62)
# =====================================================================

def test_chain89_window_batchsched_interceptor_quota():
    """Data window collects, batch scheduler organizes, interceptor modifies, quota enforces."""
    bus = PipelineIntegrationBus()
    dw = PipelineDataWindow()
    bs = AgentBatchScheduler()
    si = PipelineStepInterceptor()
    rq = AgentResourceQuota()

    bus.register_chain("chain89_window_batch_intercept_quota", tags=["phase62"])

    def step_window(ctx):
        wid = dw.create_window("pipe-89", window_type="tumbling", size=3)
        dw.add_record(wid, {"v": 1})
        dw.add_record(wid, {"v": 2})
        ctx["window_current"] = len(dw.get_current(wid))
        return ctx
    bus.add_step("chain89_window_batch_intercept_quota", "window", step_window, "pipeline_data_window")

    def step_batch(ctx):
        bid = bs.create_batch("agent-89", [{"task": "a"}, {"task": "b"}], priority=1)
        bs.start_batch(bid)
        bs.complete_task(bid, 0, result="done_a")
        progress = bs.get_progress(bid)
        ctx["batch_completed"] = progress["completed"]
        return ctx
    bus.add_step("chain89_window_batch_intercept_quota", "batch", step_batch, "agent_batch_scheduler")

    def step_intercept(ctx):
        si.register_interceptor("pipe-89", "transform", intercept_type="before", label="log_input")
        interceptors = si.get_interceptors("pipe-89", "transform")
        ctx["interceptor_count"] = len(interceptors)
        return ctx
    bus.add_step("chain89_window_batch_intercept_quota", "intercept", step_intercept, "pipeline_step_interceptor")

    def step_quota(ctx):
        rq.set_quota("agent-89", "api_calls", 100)
        rq.consume("agent-89", "api_calls", 30)
        usage = rq.get_usage("agent-89", "api_calls")
        ctx["quota_remaining"] = usage["remaining"]
        return ctx
    bus.add_step("chain89_window_batch_intercept_quota", "quota", step_quota, "agent_resource_quota")

    result = bus.execute("chain89_window_batch_intercept_quota", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["window_current"] == 2
    assert result["context"]["batch_completed"] == 1
    assert result["context"]["interceptor_count"] == 1
    assert result["context"]["quota_remaining"] == 70
    print("OK: chain 89 -- window_batchsched_interceptor_quota (Phase 62)")


