    bus.add_step("chain90_pivot_health_timeout_trigger", "timeout", step_timeout, "pipeline_step_timeout")

    def step_trigger(ctx):
        wt.register_trigger("agent-90", "on_complete", trigger_type="manual")
        result = wt.evaluate_trigger("agent-90", "on_complete")
        ctx["triggered"] = result["triggered"]
