# =====================================================================
# Chain 93: Histogram-ConnMgr-StepParallel-TaskBuffer (Phase 66)
# =====================================================================

def test_chain93_histogram_connmgr_parallel_taskbuf():
    """Histogram analyzes, connection manager links, parallel groups, task buffer queues."""
    bus = PipelineIntegrationBus()
    dh = PipelineDataHistogram()
    cm = AgentConnectionManager()
    sp = PipelineStepParallel()
    tb = AgentTaskBuffer()

    bus.register_chain("chain93_hist_conn_parallel_buf", tags=["phase66"])

    def step_histogram(ctx):
        hid = dh.create_histogram("pipe-93", "latency", bin_count=5, min_val=0.0, max_val=100.0)
        dh.add_values(hid, [10, 20, 30, 40, 50, 60, 70])
        hist = dh.get_histogram(hid)
        ctx["hist_total"] = hist["total"]
        return ctx
    bus.add_step("chain93_hist_conn_parallel_buf", "histogram", step_histogram, "pipeline_data_histogram")

    def step_conn(ctx):
        cm.connect("agent-93a", "agent-93b", connection_type="data")
        ctx["connected"] = cm.is_connected("agent-93a", "agent-93b")
        ctx["peers"] = cm.get_peers("agent-93a")
        return ctx
    bus.add_step("chain93_hist_conn_parallel_buf", "conn", step_conn, "agent_connection_manager")

    def step_parallel(ctx):
        gid = sp.create_group("pipe-93", "parallel_transform", steps=["step_a", "step_b"])
        result = sp.execute_group(gid, context={"x": 1}, step_fns={
            "step_a": lambda c: {"a": c.get("x", 0) + 1},
            "step_b": lambda c: {"b": c.get("x", 0) * 2},
        })
        ctx["parallel_success"] = result["success"]
        return ctx
    bus.add_step("chain93_hist_conn_parallel_buf", "parallel", step_parallel, "pipeline_step_parallel")

    def step_buffer(ctx):
        bid = tb.create_buffer("agent-93", capacity=50)
        tb.push(bid, {"task": "analyze"})
        tb.push(bid, {"task": "report"})
        ctx["buf_size"] = tb.get_size(bid)
        task = tb.pop(bid)
        ctx["first_task"] = task["task"]
        return ctx
    bus.add_step("chain93_hist_conn_parallel_buf", "buffer", step_buffer, "agent_task_buffer")

    result = bus.execute("chain93_hist_conn_parallel_buf", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["hist_total"] == 7
    assert result["context"]["connected"] is True
    assert "agent-93b" in result["context"]["peers"]
    assert result["context"]["parallel_success"] is True
    assert result["context"]["buf_size"] == 2
    assert result["context"]["first_task"] == "analyze"
    print("OK: chain 93 -- histogram_connmgr_parallel_taskbuf (Phase 66)")


