def test_chain94_samplerv2_correlator_guard_workload():
    """Sampler v2 samples, correlator finds patterns, guard checks preconditions, workload monitors."""
    bus = PipelineIntegrationBus()
    sv = PipelineDataSamplerV2()
    ec = AgentEventCorrelator()
    sg = PipelineStepGuard()
    wm = AgentWorkloadMonitor()

    bus.register_chain("chain94_sampler_corr_guard_workload", tags=["phase67"])

    def step_sampler(ctx):
        sid = sv.create_sampler("pipe-94", strategy="reservoir", sample_size=5)
        for i in range(10):
            sv.add_record(sid, {"val": i})
        sample = sv.get_sample(sid)
        ctx["sample_size"] = len(sample)
        return ctx
    bus.add_step("chain94_sampler_corr_guard_workload", "sampler", step_sampler, "pipeline_data_sampler_v2")

    def step_correlator(ctx):
        ec.add_event("agent-94", "login")
        ec.add_event("agent-94", "action")
        rid = ec.create_rule("login_action", ["login", "action"], time_window_seconds=60.0)
        ctx["rule_count"] = len(ec.get_rules())
        return ctx
    bus.add_step("chain94_sampler_corr_guard_workload", "correlator", step_correlator, "agent_event_correlator")

    def step_guard(ctx):
        sg.add_guard("pipe-94", "transform", guard_type="field_present", config={"field": "data"})
        result = sg.check_guards("pipe-94", "transform", {"data": [1, 2, 3]})
        ctx["guards_passed"] = result["passed"]
        return ctx
    bus.add_step("chain94_sampler_corr_guard_workload", "guard", step_guard, "pipeline_step_guard")

    def step_workload(ctx):
        wm.register_agent("agent-94", max_concurrent=10)
        wm.record_task_start("agent-94")
        wm.record_task_start("agent-94")
        workload = wm.get_workload("agent-94")
        ctx["active_tasks"] = workload["active_tasks"]
        ctx["is_overloaded"] = workload["is_overloaded"]
        return ctx
    bus.add_step("chain94_sampler_corr_guard_workload", "workload", step_workload, "agent_workload_monitor")

    result = bus.execute("chain94_sampler_corr_guard_workload", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["sample_size"] <= 5
    assert result["context"]["rule_count"] >= 1
    assert result["context"]["guards_passed"] is True
    assert result["context"]["active_tasks"] == 2
    assert result["context"]["is_overloaded"] is False
    print("OK: chain 94 -- samplerv2_correlator_guard_workload (Phase 67)")


