def test_chain95_quality_recorder_rollback_configval():
    """Data quality assesses, action recorder logs, rollback saves, config validator checks."""
    bus = PipelineIntegrationBus()
    dq = PipelineDataQuality()
    ar = AgentActionRecorder()
    sr = PipelineStepRollback()
    cv = AgentConfigValidator()

    bus.register_chain("chain95_quality_record_rollback_config", tags=["phase68"])

    def step_quality(ctx):
        dq.add_rule("pipe-95", "name", rule_type="not_null")
        result = dq.assess("pipe-95", [{"name": "Alice"}, {"name": "Bob"}, {"name": "Carol"}])
        ctx["quality_score"] = result["score"]
        ctx["quality_total"] = result["total_records"]
        return ctx
    bus.add_step("chain95_quality_record_rollback_config", "quality", step_quality, "pipeline_data_quality")

    def step_recorder(ctx):
        ar.record_action("agent-95", "analyze", params={"target": "data"}, result="ok")
        ar.record_action("agent-95", "transform", params={"mode": "fast"})
        ctx["action_count"] = ar.get_action_count("agent-95")
        return ctx
    bus.add_step("chain95_quality_record_rollback_config", "recorder", step_recorder, "agent_action_recorder")

    def step_rollback(ctx):
        sr.save_checkpoint("pipe-95", "transform", {"state": "before_transform", "data": [1, 2, 3]})
        restored = sr.rollback("pipe-95", "transform")
        ctx["rollback_state"] = restored["state"] if restored else None
        return ctx
    bus.add_step("chain95_quality_record_rollback_config", "rollback", step_rollback, "pipeline_step_rollback")

    def step_configval(ctx):
        cv.define_schema("agent-95", {
            "name": {"type": "str", "required": True},
            "timeout": {"type": "int", "required": False, "default": 30}
        })
        result = cv.validate("agent-95", {"name": "worker-1"})
        ctx["config_valid"] = result["valid"]
        defaults = cv.get_defaults("agent-95")
        ctx["default_timeout"] = defaults.get("timeout")
        return ctx
    bus.add_step("chain95_quality_record_rollback_config", "configval", step_configval, "agent_config_validator")

    result = bus.execute("chain95_quality_record_rollback_config", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["quality_total"] == 3
    assert result["context"]["action_count"] == 2
    assert result["context"]["rollback_state"] == "before_transform"
    assert result["context"]["config_valid"] is True
    assert result["context"]["default_timeout"] == 30
    print("OK: chain 95 -- quality_recorder_rollback_configval (Phase 68)")


