# Coexistence v121: Phase 70 modules on shared bus

def test_all_chains_on_one_bus_v121():
    bus = PipelineIntegrationBus()
    pa = PipelineDataAccumulator()
    sh = AgentStateHistory()
    sc = PipelineStepCache()
    nl = AgentNotificationLog()

    bus.register_chain("coex_v121_a", tags=["coex"])
    def step_a1(ctx):
        aid = pa.create_accumulator("pipe-A121", flush_size=50)
        pa.add(aid, {"x": 1})
        ctx["accum_count"] = pa.get_accumulator_count("pipe-A121")
        return ctx
    bus.add_step("coex_v121_a", "pa_a", step_a1, "pipeline_data_accumulator")
    def step_a2(ctx):
        sh.record_state("agent-A121", "ready")
        ctx["state_count"] = sh.get_entry_count("agent-A121")
        return ctx
    bus.add_step("coex_v121_a", "sh_a", step_a2, "agent_state_history")

    bus.register_chain("coex_v121_b", tags=["coex"])
    def step_b1(ctx):
        sc.configure("pipe-B121", "load", ttl_seconds=60.0)
        sc.cache_result("pipe-B121", "load", "k1", {"val": 1})
        ctx["has_cached"] = sc.has_cached("pipe-B121", "load", "k1")
        return ctx
    bus.add_step("coex_v121_b", "sc_b", step_b1, "pipeline_step_cache")
    def step_b2(ctx):
        nl.send_notification("agent-B121", "Hello", "Welcome")
        ctx["notif_count"] = nl.get_notification_count("agent-B121")
        return ctx
    bus.add_step("coex_v121_b", "nl_b", step_b2, "agent_notification_log")

    ra = bus.execute("coex_v121_a", {})
    rb = bus.execute("coex_v121_b", {})
    assert ra["success"] is True
    assert ra["context"]["accum_count"] == 1
    assert ra["context"]["state_count"] == 1
    assert rb["success"] is True
    assert rb["context"]["has_cached"] is True
    assert rb["context"]["notif_count"] == 1
    print("OK: coexistence v121 -- Phase 70 modules shared bus")


# =====================================================================
# Chain 98: Differ-ExecTrackerV2-StepThrottle-TaskPriority (Phase 71)
# =====================================================================

def test_chain98_differ_exectracker_throttle_taskprio():
    bus = PipelineIntegrationBus()
    dd = PipelineDataDiffer()
    et = AgentExecutionTrackerV2()
    st = PipelineStepThrottle()
    tp = AgentTaskPriority()

    bus.register_chain("chain98_diff_exec_throttle_prio", tags=["phase71"])

    def step_differ(ctx):
        old = [{"id": 1, "v": "a"}, {"id": 2, "v": "b"}]
        new = [{"id": 1, "v": "a"}, {"id": 2, "v": "c"}, {"id": 3, "v": "d"}]
        result = dd.compare("pipe-98", old, new, key_field="id")
        ctx["added"] = len(result["added"])
        ctx["changed"] = len(result["changed"])
        return ctx
    bus.add_step("chain98_diff_exec_throttle_prio", "differ", step_differ, "pipeline_data_differ")

    def step_exec(ctx):
        eid = et.start_execution("agent-98", "build", phases=["init", "compile", "test"])
        et.advance_phase(eid)
        ctx["current_phase"] = et.get_current_phase(eid)
        return ctx
    bus.add_step("chain98_diff_exec_throttle_prio", "exec", step_exec, "agent_execution_tracker_v2")

    def step_throttle(ctx):
        st.set_throttle("pipe-98", "transform", max_per_second=100.0)
        ctx["can_exec"] = st.can_execute("pipe-98", "transform")
        st.record_execution("pipe-98", "transform")
        return ctx
    bus.add_step("chain98_diff_exec_throttle_prio", "throttle", step_throttle, "pipeline_step_throttle")

    def step_priority(ctx):
        tp.add_task("agent-98", "low_task", priority=1)
        tp.add_task("agent-98", "high_task", priority=10)
        next_task = tp.get_next("agent-98")
        ctx["next_task_name"] = next_task["task_name"] if next_task else None
        return ctx
    bus.add_step("chain98_diff_exec_throttle_prio", "priority", step_priority, "agent_task_priority")

    result = bus.execute("chain98_diff_exec_throttle_prio", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["added"] == 1
    assert result["context"]["changed"] == 1
    assert result["context"]["can_exec"] is True
    assert result["context"]["next_task_name"] == "high_task"
    print("OK: chain 98 -- differ_exectracker_throttle_taskprio (Phase 71)")


