# =====================================================================
# Chain 99: Schema-CmdExecutor-StepMonitor-HealthAgg (Phase 72)
# =====================================================================

def test_chain99_schema_cmdexec_monitor_healthagg():
    bus = PipelineIntegrationBus()
    ds = PipelineDataSchema()
    ce = AgentCommandExecutor()
    sm = PipelineStepMonitor()
    ha = AgentHealthAggregator()

    bus.register_chain("chain99_schema_cmd_monitor_health", tags=["phase72"])

    def step_schema(ctx):
        ds.define_schema("pipe-99", {"name": {"type": "str", "required": True}, "age": {"type": "int", "required": False}})
        result = ds.validate_record("pipe-99", {"name": "Alice", "age": 30})
        ctx["schema_valid"] = result["valid"]
        return ctx
    bus.add_step("chain99_schema_cmd_monitor_health", "schema", step_schema, "pipeline_data_schema")

    def step_cmd(ctx):
        ce.register_command("agent-99", "greet", handler_fn=lambda name="world": f"Hello {name}", params=["name"])
        result = ce.execute_command("agent-99", "greet", args={"name": "Alice"})
        ctx["cmd_result"] = result["result"]
        ctx["cmd_status"] = result["status"]
        return ctx
    bus.add_step("chain99_schema_cmd_monitor_health", "cmd", step_cmd, "agent_command_executor")

    def step_monitor(ctx):
        sm.configure_monitor("pipe-99", "transform", failure_threshold=3)
        sm.record_success("pipe-99", "transform")
        sm.record_success("pipe-99", "transform")
        status = sm.get_status("pipe-99", "transform")
        ctx["step_healthy"] = status["healthy"]
        ctx["success_count"] = status["success_count"]
        return ctx
    bus.add_step("chain99_schema_cmd_monitor_health", "monitor", step_monitor, "pipeline_step_monitor")

    def step_health(ctx):
        ha.report_health("agent-99", "cpu", status="healthy")
        ha.report_health("agent-99", "memory", status="healthy")
        health = ha.get_agent_health("agent-99")
        ctx["agent_overall"] = health["overall"]
        return ctx
    bus.add_step("chain99_schema_cmd_monitor_health", "health", step_health, "agent_health_aggregator")

    result = bus.execute("chain99_schema_cmd_monitor_health", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["schema_valid"] is True
    assert result["context"]["cmd_result"] == "Hello Alice"
    assert result["context"]["cmd_status"] == "success"
    assert result["context"]["step_healthy"] is True
    assert result["context"]["success_count"] == 2
    assert result["context"]["agent_overall"] == "healthy"
    print("OK: chain 99 -- schema_cmdexec_monitor_healthagg (Phase 72)")


