# =====================================================================
# Chain 100: Expression-ContextResolver-StepAudit-ResourceCounter (Phase 73)
# =====================================================================

def test_chain100_expression_context_audit_counter():
    bus = PipelineIntegrationBus()
    pe = PipelineDataExpression()
    cr = AgentContextResolver()
    sa = PipelineStepAudit()
    rc = AgentResourceCounter()

    bus.register_chain("chain100_expr_ctx_audit_counter", tags=["phase73"])

    def step_expr(ctx):
        pe.add_expression("pipe-100", "total", "price", "*", "quantity")
        result = pe.evaluate("pipe-100", {"price": 10.0, "quantity": 3})
        ctx["computed_total"] = result.get("total", 0)
        return ctx
    bus.add_step("chain100_expr_ctx_audit_counter", "expr", step_expr, "pipeline_data_expression")

    def step_context(ctx):
        cr.register_source("agent-100", "env", {"host": "localhost", "port": "8080"})
        ctx["resolved_host"] = cr.resolve("agent-100", "host")
        return ctx
    bus.add_step("chain100_expr_ctx_audit_counter", "context", step_context, "agent_context_resolver")

    def step_audit(ctx):
        sa.log_execution("pipe-100", "transform", executor="agent-100", status="success")
        sa.log_execution("pipe-100", "load", executor="agent-100", status="success")
        summary = sa.get_audit_summary("pipe-100")
        ctx["audit_total"] = summary["total_executions"]
        return ctx
    bus.add_step("chain100_expr_ctx_audit_counter", "audit", step_audit, "pipeline_step_audit")

    def step_counter(ctx):
        rc.increment("agent-100", "api_calls", 5)
        rc.increment("agent-100", "tokens", 1000)
        ctx["api_count"] = rc.get_count("agent-100", "api_calls")
        ctx["token_count"] = rc.get_count("agent-100", "tokens")
        return ctx
    bus.add_step("chain100_expr_ctx_audit_counter", "counter", step_counter, "agent_resource_counter")

    result = bus.execute("chain100_expr_ctx_audit_counter", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["computed_total"] == 30.0
    assert result["context"]["resolved_host"] == "localhost"
    assert result["context"]["audit_total"] == 2
    assert result["context"]["api_count"] == 5
    assert result["context"]["token_count"] == 1000
    print("OK: chain 100 -- expression_context_audit_counter (Phase 73)")


