def test_chain101_zipper_wfsched_splitter_taskdep():
    bus = PipelineIntegrationBus()
    dz = PipelineDataZipper()
    ws = AgentWorkflowScheduler()
    ss = PipelineStepSplitter()
    td = AgentTaskDependency()

    bus.register_chain("chain101_zipper_wfsched_splitter_taskdep", tags=["phase74"])

    def step_zipper(ctx):
        s1 = dz.register_stream("orders", keys=["id"])
        s2 = dz.register_stream("customers", keys=["id"])
        dz.add_records(s1, [{"id": 1, "amount": 100}, {"id": 2, "amount": 200}])
        dz.add_records(s2, [{"id": 1, "name": "Alice"}, {"id": 2, "name": "Bob"}])
        zipped = dz.zip_streams([s1, s2], mode="inner")
        ctx["zipped_count"] = len(zipped["records"])
        return ctx
    bus.add_step("chain101_zipper_wfsched_splitter_taskdep", "zipper", step_zipper, "pipeline_data_zipper")

    def step_wfsched(ctx):
        sid = ws.schedule_workflow("agent-101", "daily_report", interval_seconds=3600)
        ws.trigger_workflow(sid)
        sched = ws.get_schedule(sid)
        ctx["wf_run_count"] = sched["run_count"]
        return ctx
    bus.add_step("chain101_zipper_wfsched_splitter_taskdep", "wfsched", step_wfsched, "agent_workflow_scheduler")

    def step_splitter(ctx):
        sp_id = ss.register_split("transform", ["parse", "validate", "enrich"])
        result = ss.execute_split(sp_id, {"data": "test"})
        ctx["sub_steps_count"] = result["total_sub_steps"]
        return ctx
    bus.add_step("chain101_zipper_wfsched_splitter_taskdep", "splitter", step_splitter, "pipeline_step_splitter")

    def step_taskdep(ctx):
        t1 = td.register_task("agent-101", "fetch_data")
        t2 = td.register_task("agent-101", "process_data", depends_on=[t1])
        td.complete_task(t1)
        ready = td.get_ready_tasks("agent-101")
        ctx["ready_tasks"] = len(ready)
        return ctx
    bus.add_step("chain101_zipper_wfsched_splitter_taskdep", "taskdep", step_taskdep, "agent_task_dependency")

    result = bus.execute("chain101_zipper_wfsched_splitter_taskdep", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["zipped_count"] == 2
    assert result["context"]["wf_run_count"] == 1
    assert result["context"]["sub_steps_count"] == 3
    assert result["context"]["ready_tasks"] == 1
    print("OK: chain 101 -- zipper_wfsched_splitter_taskdep (Phase 74)")


