def test_chain102_tokenizer_wfvalidator_debouncer_tasksched():
    bus = PipelineIntegrationBus()
    tk = PipelineDataTokenizer()
    wv = AgentWorkflowValidator()
    db = PipelineStepDebouncer()
    ts = AgentTaskSchedulerV2()

    bus.register_chain("chain102_tok_wfval_debounce_tasksched", tags=["phase75"])

    def step_tokenizer(ctx):
        tid = tk.register_tokenizer("word_splitter", mode="word")
        result = tk.tokenize(tid, "hello world foo bar")
        ctx["token_count"] = result["token_count"]
        return ctx
    bus.add_step("chain102_tok_wfval_debounce_tasksched", "tokenizer", step_tokenizer, "pipeline_data_tokenizer")

    def step_validator(ctx):
        r1 = wv.register_rule("has_name", "name", check_type="required")
        r2 = wv.register_rule("name_is_str", "name", check_type="type", expected_value="str")
        result = wv.validate({"name": "test_workflow", "steps": 3}, [r1, r2])
        ctx["validation_valid"] = result["valid"]
        ctx["rules_passed"] = result["rules_passed"]
        return ctx
    bus.add_step("chain102_tok_wfval_debounce_tasksched", "validator", step_validator, "agent_workflow_validator")

    def step_debouncer(ctx):
        did = db.register_debounce("transform", window_seconds=0.001)
        exec1 = db.should_execute(did)
        ctx["first_exec"] = exec1
        ctx["debounce_count"] = db.get_debounce_count()
        return ctx
    bus.add_step("chain102_tok_wfval_debounce_tasksched", "debouncer", step_debouncer, "pipeline_step_debouncer")

    def step_tasksched(ctx):
        t1 = ts.schedule_task("agent-102", "build", priority=1)
        t2 = ts.schedule_task("agent-102", "test", priority=5)
        nxt = ts.get_next_task("agent-102")
        ctx["next_task_name"] = nxt["task_name"]
        ts.start_task(t1)
        ts.complete_task(t1)
        ctx["completed_count"] = ts.get_task_count("agent-102", status="completed")
        return ctx
    bus.add_step("chain102_tok_wfval_debounce_tasksched", "tasksched", step_tasksched, "agent_task_scheduler_v2")

    result = bus.execute("chain102_tok_wfval_debounce_tasksched", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["token_count"] == 4
    assert result["context"]["validation_valid"] is True
    assert result["context"]["rules_passed"] == 2
    assert result["context"]["first_exec"] is True
    assert result["context"]["next_task_name"] == "build"
    assert result["context"]["completed_count"] == 1
    print("OK: chain 102 -- tokenizer_wfvalidator_debouncer_tasksched (Phase 75)")


