def test_chain104_redactor_wfhistory_condv2_tasklock():
    bus = PipelineIntegrationBus()
    rd = PipelineDataRedactor()
    wh = AgentWorkflowHistory()
    cv = PipelineStepConditionV2()
    tl = AgentTaskLock()

    bus.register_chain("chain104_redactor_wfhist_cond_lock", tags=["phase77"])

    def step_redactor(ctx):
        r1 = rd.register_rule("mask_ssn", "ssn", replacement="XXX-XX-XXXX")
        r2 = rd.register_rule("mask_email", "email", replacement="[REDACTED]")
        record = {"name": "Alice", "ssn": "123-45-6789", "email": "alice@test.com"}
        redacted = rd.redact(record, [r1, r2])
        ctx["ssn_redacted"] = redacted["ssn"]
        ctx["email_redacted"] = redacted["email"]
        ctx["name_preserved"] = redacted["name"]
        return ctx
    bus.add_step("chain104_redactor_wfhist_cond_lock", "redactor", step_redactor, "pipeline_data_redactor")

    def step_wfhistory(ctx):
        wh.record_execution("agent-104", "deploy", status="success", duration_ms=150)
        wh.record_execution("agent-104", "deploy", status="success", duration_ms=250)
        avg = wh.get_average_duration("agent-104", "deploy")
        ctx["avg_duration"] = avg
        ctx["exec_count"] = wh.get_execution_count("agent-104")
        return ctx
    bus.add_step("chain104_redactor_wfhist_cond_lock", "wfhistory", step_wfhistory, "agent_workflow_history")

    def step_condition(ctx):
        c1 = cv.register_condition("check_count", "exec_count", "gte", 2)
        c2 = cv.register_condition("check_avg", "avg_duration", "gt", 100)
        result = cv.evaluate_all([c1, c2], ctx, mode="all")
        ctx["conditions_passed"] = result["passed"]
        ctx["passed_count"] = result["passed_count"]
        return ctx
    bus.add_step("chain104_redactor_wfhist_cond_lock", "condition", step_condition, "pipeline_step_condition_v2")

    def step_tasklock(ctx):
        lock_id = tl.acquire("agent-104", "deploy_lock", ttl_seconds=300)
        ctx["lock_acquired"] = lock_id != ""
        ctx["is_locked"] = tl.is_locked("deploy_lock")
        ctx["lock_holder"] = tl.get_lock_holder("deploy_lock")
        return ctx
    bus.add_step("chain104_redactor_wfhist_cond_lock", "tasklock", step_tasklock, "agent_task_lock")

    result = bus.execute("chain104_redactor_wfhist_cond_lock", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["ssn_redacted"] == "XXX-XX-XXXX"
    assert result["context"]["email_redacted"] == "[REDACTED]"
    assert result["context"]["name_preserved"] == "Alice"
    assert result["context"]["avg_duration"] == 200.0
    assert result["context"]["exec_count"] == 2
    assert result["context"]["conditions_passed"] is True
    assert result["context"]["passed_count"] == 2
    assert result["context"]["lock_acquired"] is True
    assert result["context"]["is_locked"] is True
    assert result["context"]["lock_holder"] == "agent-104"
    print("OK: chain 104 -- redactor_wfhistory_condv2_tasklock (Phase 77)")


