def test_chain105_encoder_wfretry_ratelimiter_template():
    bus = PipelineIntegrationBus()
    en = PipelineDataEncoder()
    wr = AgentWorkflowRetry()
    rl = PipelineStepRateLimiter()
    tt = AgentTaskTemplate()

    bus.register_chain("chain105_enc_retry_rlimit_template", tags=["phase78"])

    def step_encoder(ctx):
        encoded = en.encode("hello world", encoding="base64")
        decoded = en.decode(encoded, encoding="base64")
        ctx["encode_roundtrip"] = decoded == "hello world"
        ctx["encoded_len"] = len(encoded)
        return ctx
    bus.add_step("chain105_enc_retry_rlimit_template", "encoder", step_encoder, "pipeline_data_encoder")

    def step_wfretry(ctx):
        pid = wr.register_policy("default_retry", max_retries=3, backoff_seconds=0.1)
        rid = wr.start_retry(pid, "agent-105", "deploy")
        r1 = wr.record_attempt(rid, success=False, error="timeout")
        r2 = wr.record_attempt(rid, success=True)
        ctx["retry_status"] = r2["status"]
        ctx["retry_attempts"] = r2["attempt"]
        return ctx
    bus.add_step("chain105_enc_retry_rlimit_template", "wfretry", step_wfretry, "agent_workflow_retry")

    def step_ratelimiter(ctx):
        lid = rl.register_limiter("transform", max_per_second=100, burst=50)
        allowed = rl.allow(lid)
        ctx["rate_allowed"] = allowed
        ctx["limiter_count"] = rl.get_limiter_count()
        return ctx
    bus.add_step("chain105_enc_retry_rlimit_template", "ratelimiter", step_ratelimiter, "pipeline_step_rate_limiter")

    def step_template(ctx):
        tid = tt.register_template("build_task", "build", default_params={"target": "release", "threads": 4})
        instance = tt.instantiate(tid, overrides={"threads": 8})
        ctx["task_type"] = instance["task_type"]
        ctx["threads"] = instance["params"]["threads"]
        ctx["target"] = instance["params"]["target"]
        return ctx
    bus.add_step("chain105_enc_retry_rlimit_template", "template", step_template, "agent_task_template")

    result = bus.execute("chain105_enc_retry_rlimit_template", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["encode_roundtrip"] is True
    assert result["context"]["retry_status"] == "succeeded"
    assert result["context"]["retry_attempts"] == 2
    assert result["context"]["rate_allowed"] is True
    assert result["context"]["task_type"] == "build"
    assert result["context"]["threads"] == 8
    assert result["context"]["target"] == "release"
    print("OK: chain 105 -- encoder_wfretry_ratelimiter_template (Phase 78)")


