def test_chain106_projector_wfmonitor_reporter_cancel():
    bus = PipelineIntegrationBus()
    pj = PipelineDataProjector()
    wm = AgentWorkflowMonitor()
    rp = PipelineStepReporter()
    tc = AgentTaskCancellation()

    bus.register_chain("chain106_proj_wfmon_report_cancel", tags=["phase79"])

    def step_projector(ctx):
        pid = pj.register_projection("user_view", fields=["name", "email"], rename={"email": "contact"})
        record = {"name": "Alice", "email": "alice@test.com", "ssn": "123", "password": "secret"}
        projected = pj.project(pid, record)
        ctx["projected_keys"] = sorted(projected.keys())
        ctx["contact"] = projected.get("contact", "")
        return ctx
    bus.add_step("chain106_proj_wfmon_report_cancel", "projector", step_projector, "pipeline_data_projector")

    def step_wfmonitor(ctx):
        mid = wm.start_monitoring("agent-106", "deploy", timeout_seconds=300)
        wm.heartbeat(mid)
        ctx["active_count"] = wm.get_active_count("agent-106")
        wm.complete_monitoring(mid, status="success")
        ctx["monitor_count"] = wm.get_monitor_count("agent-106")
        return ctx
    bus.add_step("chain106_proj_wfmon_report_cancel", "wfmonitor", step_wfmonitor, "agent_workflow_monitor")

    def step_reporter(ctx):
        rp.record_execution("pipe-106", "extract", duration_ms=100, status="success")
        rp.record_execution("pipe-106", "transform", duration_ms=200, status="success")
        rp.record_execution("pipe-106", "load", duration_ms=150, status="success")
        report = rp.get_report("pipe-106")
        ctx["total_execs"] = report["total_executions"]
        ctx["avg_duration"] = report["avg_duration_ms"]
        return ctx
    bus.add_step("chain106_proj_wfmon_report_cancel", "reporter", step_reporter, "pipeline_step_reporter")

    def step_cancel(ctx):
        cid = tc.request_cancellation("agent-106", "old_task", reason="replaced")
        tc.confirm_cancellation(cid)
        ctx["is_cancelled"] = tc.is_cancelled("agent-106", "old_task")
        ctx["cancel_count"] = tc.get_cancellation_count("agent-106")
        return ctx
    bus.add_step("chain106_proj_wfmon_report_cancel", "cancel", step_cancel, "agent_task_cancellation")

    result = bus.execute("chain106_proj_wfmon_report_cancel", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["projected_keys"] == ["contact", "name"]
    assert result["context"]["contact"] == "alice@test.com"
    assert result["context"]["active_count"] == 1
    assert result["context"]["total_execs"] == 3
    assert result["context"]["avg_duration"] == 150.0
    assert result["context"]["is_cancelled"] is True
    print("OK: chain 106 -- projector_wfmonitor_reporter_cancel (Phase 79)")


