    ta = AgentTaskAssignment()

    bus.register_chain("chain108_fmt_rollback_seq_assign", tags=["phase81"])

    def step_formatter(ctx):
        fid = fm.register_format("price_format", "price", "${value}")
        record = {"item": "widget", "price": "9.99"}
        formatted = fm.format_record(fid, record)
        ctx["formatted_price"] = formatted["price"]
        return ctx
    bus.add_step("chain108_fmt_rollback_seq_assign", "formatter", step_formatter, "pipeline_data_formatter")

    def step_rollback(ctx):
        cp1 = rb.create_checkpoint("agent-108", "deploy", {"version": "1.0"}, label="pre-deploy")
        cp2 = rb.create_checkpoint("agent-108", "deploy", {"version": "2.0"}, label="post-deploy")
        rolled = rb.rollback(cp1)
        ctx["rollback_version"] = rolled["state"]["version"]
        ctx["checkpoint_count"] = rb.get_checkpoint_count("agent-108")
        return ctx
    bus.add_step("chain108_fmt_rollback_seq_assign", "rollback", step_rollback, "agent_workflow_rollback")

    def step_sequencer(ctx):
        sid = sq.register_sequence("etl", ["extract", "transform", "load"])
        first = sq.get_next_step(sid)
        second = sq.get_next_step(sid, "extract")
        valid = sq.is_valid_transition(sid, "extract", "transform")
        ctx["first_step"] = first
        ctx["second_step"] = second
        ctx["valid_transition"] = valid
        return ctx
    bus.add_step("chain108_fmt_rollback_seq_assign", "sequencer", step_sequencer, "pipeline_step_sequencer")

    def step_assign(ctx):
        a1 = ta.assign_task("agent-108", "build", priority=1)
        a2 = ta.assign_task("agent-108", "test", priority=3)
        pending = ta.get_pending_assignments("agent-108")
        ctx["pending_count"] = len(pending)
        ta.complete_assignment(a1)
        workload = ta.get_agent_workload()
        ctx["workload"] = workload.get("agent-108", 0)
        return ctx
    bus.add_step("chain108_fmt_rollback_seq_assign", "assign", step_assign, "agent_task_assignment")

    result = bus.execute("chain108_fmt_rollback_seq_assign", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert result["context"]["formatted_price"] == "$9.99"
    assert result["context"]["rollback_version"] == "1.0"
    assert result["context"]["first_step"] == "extract"
    assert result["context"]["second_step"] == "transform"
    assert result["context"]["valid_transition"] is True
    assert result["context"]["pending_count"] == 2
    assert result["context"]["workload"] == 1
    print("OK: chain 108 -- formatter_wfrollback_sequencer_assign (Phase 81)")


