def test_chain110_sanitizer_wfdispatcher_correlator_archive():
    """Sanitize data, dispatch workflow, correlate steps, archive tasks."""
    bus = PipelineIntegrationBus()
    sa = PipelineDataSanitizer()
    di = AgentWorkflowDispatcher()
    co = PipelineStepCorrelator()
    ar = AgentTaskArchive()

    bus.register_chain("sanitizer_wfdispatcher_correlator_archive", tags=["phase83"])

    def step_sanitize(ctx):
        rid = sa.sanitize({"name": "  Alice  ", "email": None}, rules=["strip_whitespace", "remove_nulls"])
        rec = sa.get_record(rid)
        assert rec is not None
        ctx["sanitize_id"] = rid
        ctx["san_stats"] = sa.get_stats()
        return ctx

    def step_dispatch(ctx):
        did = di.dispatch("wf-83", "agent-83", "compile", priority="high")
        d = di.get_dispatch(did)
        assert d is not None
        di.complete_dispatch(did, "success")
        ctx["dispatch_id"] = did
        ctx["disp_stats"] = di.get_stats()
        return ctx

    def step_correlate(ctx):
        cid = co.correlate("pipe-83", ["step_a", "step_b"], correlation_key="build-83")
        co.add_step_to_correlation(cid, "step_c")
        c = co.get_correlation(cid)
        assert c is not None
        ctx["correlation_id"] = cid
        ctx["corr_count"] = co.get_correlation_count("pipe-83")
        return ctx

    def step_archive(ctx):
        aid = ar.archive("task-83", "agent-83", result="completed", metadata={"phase": 83})
        a = ar.get_archive(aid)
        assert a is not None
        ctx["archive_id"] = aid
        ctx["arch_stats"] = ar.get_stats()
        return ctx

    bus.add_step("sanitizer_wfdispatcher_correlator_archive", "sanitize", step_sanitize, "pipeline_data_sanitizer")
    bus.add_step("sanitizer_wfdispatcher_correlator_archive", "dispatch", step_dispatch, "agent_workflow_dispatcher")
    bus.add_step("sanitizer_wfdispatcher_correlator_archive", "correlate", step_correlate, "pipeline_step_correlator")
    bus.add_step("sanitizer_wfdispatcher_correlator_archive", "archive", step_archive, "agent_task_archive")

    result = bus.execute("sanitizer_wfdispatcher_correlator_archive", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert "sanitize_id" in result["context"]
    assert "dispatch_id" in result["context"]
    assert result["context"]["corr_count"] >= 1
    assert "archive_id" in result["context"]
    print("OK: chain 110 -- sanitizer_wfdispatcher_correlator_archive (Phase 83)")


