# =====================================================================

def test_chain111_cloner_wfnotifier_aggregator_retry():
    """Clone data, notify workflow, aggregate steps, retry tasks."""
    bus = PipelineIntegrationBus()
    cl = PipelineDataCloner()
    no = AgentWorkflowNotifier()
    ag = PipelineStepAggregator()
    rt = AgentTaskRetry()

    bus.register_chain("cloner_wfnotifier_aggregator_retry", tags=["phase84"])

    def step_clone(ctx):
        cid = cl.clone({"key": "value", "nested": {"a": 1}}, label="backup")
        data = cl.retrieve_data(cid)
        assert data is not None
        assert data["key"] == "value"
        ctx["clone_id"] = cid
        ctx["clone_stats"] = cl.get_stats()
        return ctx

    def step_notify(ctx):
        nid = no.notify("agent-84", "build", "started", message="Build beginning")
        n = no.get_notification(nid)
        assert n is not None
        no.mark_read(nid)
        ctx["notify_id"] = nid
        ctx["notify_stats"] = no.get_stats()
        return ctx

    def step_aggregate(ctx):
        aid = ag.create_aggregation("pipe-84", ["compile", "test", "deploy"])
        ag.add_result(aid, "compile", {"status": "ok"})
        ag.add_result(aid, "test", {"status": "ok"})
        a = ag.get_aggregation(aid)
        assert a is not None
        ctx["agg_id"] = aid
        ctx["agg_stats"] = ag.get_stats()
        return ctx

    def step_retry(ctx):
        pid = rt.register_policy("task-84", max_retries=3, backoff="fixed")
        rt.record_attempt(pid, success=False, error="timeout")
        assert rt.should_retry(pid) is True
        rt.record_attempt(pid, success=True)
        assert rt.should_retry(pid) is False
        ctx["policy_id"] = pid
        ctx["retry_stats"] = rt.get_stats()
        return ctx

    bus.add_step("cloner_wfnotifier_aggregator_retry", "clone", step_clone, "pipeline_data_cloner")
    bus.add_step("cloner_wfnotifier_aggregator_retry", "notify", step_notify, "agent_workflow_notifier")
    bus.add_step("cloner_wfnotifier_aggregator_retry", "aggregate", step_aggregate, "pipeline_step_aggregator")
    bus.add_step("cloner_wfnotifier_aggregator_retry", "retry", step_retry, "agent_task_retry")

    result = bus.execute("cloner_wfnotifier_aggregator_retry", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert "clone_id" in result["context"]
    assert "notify_id" in result["context"]
    assert "agg_id" in result["context"]
    assert "policy_id" in result["context"]
    print("OK: chain 111 -- cloner_wfnotifier_aggregator_retry (Phase 84)")


