def test_chain112_inspector_wftimer_decorator_budget():
    """Inspect data, time workflow, decorate steps, manage budgets."""
    bus = PipelineIntegrationBus()
    ins = PipelineDataInspector()
    tm = AgentWorkflowTimer()
    dc = PipelineStepDecorator()
    bu = AgentTaskBudget()

    bus.register_chain("inspector_wftimer_decorator_budget", tags=["phase85"])

    def step_inspect(ctx):
        iid = ins.inspect({"name": "test", "count": 42, "nested": {"a": 1}}, label="check")
        r = ins.get_inspection(iid)
        assert r is not None
        ctx["inspect_id"] = iid
        ctx["inspect_stats"] = ins.get_stats()
        return ctx

    def step_timer(ctx):
        tid = tm.start_timer("agent-85", "build", label="compile")
        tm.stop_timer(tid)
        t = tm.get_timer(tid)
        assert t is not None
        ctx["timer_id"] = tid
        ctx["timer_stats"] = tm.get_stats()
        return ctx

    def step_decorate(ctx):
        did = dc.decorate("pipe-85", "compile", tags=["fast", "critical"])
        dc.add_tag(did, "verified")
        d = dc.get_decoration(did)
        assert d is not None
        ctx["decor_id"] = did
        ctx["decor_count"] = dc.get_decoration_count("pipe-85")
        return ctx

    def step_budget(ctx):
        bid = bu.create_budget("task-85", "agent-85", limit=100.0, unit="credits")
        bu.spend(bid, 25.0, "compile")
        bu.spend(bid, 15.0, "test")
        rem = bu.get_remaining(bid)
        assert rem == 60.0
        ctx["budget_id"] = bid
        ctx["budget_stats"] = bu.get_stats()
        return ctx

    bus.add_step("inspector_wftimer_decorator_budget", "inspect", step_inspect, "pipeline_data_inspector")
    bus.add_step("inspector_wftimer_decorator_budget", "timer", step_timer, "agent_workflow_timer")
    bus.add_step("inspector_wftimer_decorator_budget", "decorate", step_decorate, "pipeline_step_decorator")
    bus.add_step("inspector_wftimer_decorator_budget", "budget", step_budget, "agent_task_budget")

    result = bus.execute("inspector_wftimer_decorator_budget", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert "inspect_id" in result["context"]
    assert "timer_id" in result["context"]
    assert result["context"]["decor_count"] >= 1
    assert "budget_id" in result["context"]
    print("OK: chain 112 -- inspector_wftimer_decorator_budget (Phase 85)")


