# Chain 113: Streamer-WfResolver-Isolator-Classifier Pipeline (Phase 86)
# =====================================================================

def test_chain113_streamer_wfresolver_isolator_classifier():
    """Stream data, resolve deps, isolate steps, classify tasks."""
    bus = PipelineIntegrationBus()
    st = PipelineDataStreamer()
    re = AgentWorkflowResolver()
    iso = PipelineStepIsolator()
    cl = AgentTaskClassifier()

    bus.register_chain("streamer_wfresolver_isolator_classifier", tags=["phase86"])

    def step_stream(ctx):
        sid = st.create_stream("pipe-86", list(range(25)), chunk_size=10)
        chunk1 = st.get_next_chunk(sid)
        assert chunk1 is not None
        assert len(chunk1) == 10
        ctx["stream_id"] = sid
        ctx["stream_stats"] = st.get_stats()
        return ctx

    def step_resolve(ctx):
        re.add_dependency("wf-86", "compile", depends_on=[])
        re.add_dependency("wf-86", "test", depends_on=["compile"])
        re.add_dependency("wf-86", "deploy", depends_on=["test"])
        order = re.resolve_order("wf-86")
        assert len(order) >= 3
        ctx["resolve_order"] = order
        ctx["dep_count"] = re.get_dependency_count("wf-86")
        return ctx

    def step_isolate(ctx):
        iid = iso.create_isolation("pipe-86", "compile", context={"env": "test"})
        iso.update_context(iid, {"status": "running"})
        ic = iso.get_context(iid)
        assert ic is not None
        assert ic["status"] == "running"
        ctx["isolation_id"] = iid
        ctx["iso_stats"] = iso.get_stats()
        return ctx

    def step_classify(ctx):
        cid = cl.classify("task-86", task_type="build", priority="high", tags=["ci"])
        c = cl.get_classification(cid)
        assert c is not None
        ctx["class_id"] = cid
