def test_chain114_annotator_wflogger_selector_estimator():
    """Annotate data, log workflow, select steps, estimate tasks."""
    bus = PipelineIntegrationBus()
    an = PipelineDataAnnotator()
    wl = AgentWorkflowLogger()
    se = PipelineStepSelector()
    es = AgentTaskEstimator()

    bus.register_chain("annotator_wflogger_selector_estimator", tags=["phase87"])

    def step_annotate(ctx):
        aid = an.annotate({"key": "value"}, {"author": "system", "version": "1.0"}, label="build")
        an.add_annotation(aid, "status", "verified")
        a = an.get_annotation(aid)
        assert a is not None
        ctx["annotate_id"] = aid
        ctx["ann_stats"] = an.get_stats()
        return ctx

    def step_log(ctx):
        lid = wl.log("agent-87", "build", level="info", message="Build started")
        wl.log("agent-87", "build", level="warning", message="Slow step")
        l = wl.get_log(lid)
