# Chain 115: Patcher-WfGraph-Limiter-Reporter Pipeline (Phase 88)
# =====================================================================

def test_chain115_patcher_wfgraph_limiter_reporter():
    """Patch data, build graph, limit steps, report tasks."""
    bus = PipelineIntegrationBus()
    pa = PipelineDataPatcher()
    gr = AgentWorkflowGraph()
    li = PipelineStepLimiter()
    rp = AgentTaskReporter()

    bus.register_chain("patcher_wfgraph_limiter_reporter", tags=["phase88"])

    def step_patch(ctx):
        pid = pa.apply_patch({"name": "old", "ver": 1}, {"name": "new", "ver": 2}, label="upgrade")
        p = pa.get_patch(pid)
        assert p is not None
        orig = pa.revert_patch(pid)
        assert orig is not None
        assert orig["name"] == "old"
        ctx["patch_id"] = pid
        ctx["patch_stats"] = pa.get_stats()
        return ctx

    def step_graph(ctx):
        gid = gr.create_graph("wf-88", label="build")
        gr.add_node(gid, "compile")
        gr.add_node(gid, "test")
        gr.add_edge(gid, "compile", "test")
        g = gr.get_graph(gid)
        assert g is not None
        ctx["graph_id"] = gid
        ctx["graph_stats"] = gr.get_stats()
        return ctx

    def step_limit(ctx):
        lid = li.set_limit("pipe-88", "deploy", max_executions=3)
        li.record_execution(lid)
        li.record_execution(lid)
        assert li.is_allowed(lid) is True
        li.record_execution(lid)
        assert li.is_allowed(lid) is False
        ctx["limit_id"] = lid
        ctx["limit_stats"] = li.get_stats()
        return ctx

    def step_report(ctx):
        rid = rp.create_report("task-88", "agent-88", status="in_progress", progress=0.5, summary="Halfway")
        rp.update_report(rid, status="completed", progress=1.0)
        r = rp.get_report(rid)
        assert r is not None
        ctx["report_id"] = rid
        ctx["report_stats"] = rp.get_stats()
        return ctx

    bus.add_step("patcher_wfgraph_limiter_reporter", "patch", step_patch, "pipeline_data_patcher")
    bus.add_step("patcher_wfgraph_limiter_reporter", "graph", step_graph, "agent_workflow_graph")
    bus.add_step("patcher_wfgraph_limiter_reporter", "limit", step_limit, "pipeline_step_limiter")
    bus.add_step("patcher_wfgraph_limiter_reporter", "report", step_report, "agent_task_reporter")

    result = bus.execute("patcher_wfgraph_limiter_reporter", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert "patch_id" in result["context"]
    assert "graph_id" in result["context"]
    assert "limit_id" in result["context"]
    assert "report_id" in result["context"]
    print("OK: chain 115 -- patcher_wfgraph_limiter_reporter (Phase 88)")


