def test_chain116_indexer_wfscope_mapper_scorer():
    """Index data, scope workflow, map steps, score tasks."""
    bus = PipelineIntegrationBus()
    ix = PipelineDataIndexer()
    sc = AgentWorkflowScope()
    mp = PipelineStepMapper()
    sr = AgentTaskScorer()

    bus.register_chain("indexer_wfscope_mapper_scorer", tags=["phase89"])

    def step_index(ctx):
        iid = ix.index("pipe-89", {"name": "Alice", "age": 30}, ["name", "age"])
        r = ix.lookup(iid, "name", "Alice")
        assert r is not None
        ctx["index_id"] = iid
        ctx["idx_stats"] = ix.get_stats()
        return ctx

    def step_scope(ctx):
        sid = sc.create_scope("agent-89", "build", variables={"env": "test"})
