    bus.add_step("indexer_wfscope_mapper_scorer", "index", step_index, "pipeline_data_indexer")
    bus.add_step("indexer_wfscope_mapper_scorer", "scope", step_scope, "agent_workflow_scope")
    bus.add_step("indexer_wfscope_mapper_scorer", "map", step_map, "pipeline_step_mapper")
    bus.add_step("indexer_wfscope_mapper_scorer", "score", step_score, "agent_task_scorer")

    result = bus.execute("indexer_wfscope_mapper_scorer", {})
