    assert "index_id" in result["context"]
    assert "scope_id" in result["context"]
    assert "mapping_id" in result["context"]
    assert "score_id" in result["context"]
    print("OK: chain 116 -- indexer_wfscope_mapper_scorer (Phase 89)")


