# Chain 117: Versioner-WfBarrier-Composer-Delegator Pipeline (Phase 90)
# =====================================================================

def test_chain117_versioner_wfbarrier_composer_delegator():
    """Version data, barrier sync, compose steps, delegate tasks."""
    bus = PipelineIntegrationBus()
    ve = PipelineDataVersioner()
    ba = AgentWorkflowBarrier()
    co = PipelineStepComposer()
    dl = AgentTaskDelegator()

    bus.register_chain("versioner_wfbarrier_composer_delegator", tags=["phase90"])

    def step_version(ctx):
        v1 = ve.create_version("pipe-90", {"schema": "v1"}, version=1)
        v2 = ve.create_version("pipe-90", {"schema": "v2"}, version=2)
        latest = ve.get_latest_version("pipe-90")
        assert latest is not None
        ctx["version_id"] = v2
        ctx["ver_stats"] = ve.get_stats()
        return ctx

    def step_barrier(ctx):
        bid = ba.create_barrier("wf-90", required_count=2, label="sync")
        ba.arrive(bid, "agent-A")
        assert ba.is_complete(bid) is False
        ba.arrive(bid, "agent-B")
        assert ba.is_complete(bid) is True
        ctx["barrier_id"] = bid
        ctx["bar_stats"] = ba.get_stats()
        return ctx

    def step_compose(ctx):
        cid = co.compose("pipe-90", ["init", "build", "test"], label="ci")
        co.append_step(cid, "deploy")
        c = co.get_composition(cid)
        assert c is not None
        ctx["comp_id"] = cid
        ctx["comp_stats"] = co.get_stats()
        return ctx

    def step_delegate(ctx):
        did = dl.delegate("task-90", "agent-lead", "agent-worker", reason="specialized")
        dl.accept_delegation(did)
        dl.complete_delegation(did, result="done")
        d = dl.get_delegation(did)
        assert d is not None
        ctx["deleg_id"] = did
        ctx["deleg_stats"] = dl.get_stats()
        return ctx

    bus.add_step("versioner_wfbarrier_composer_delegator", "version", step_version, "pipeline_data_versioner")
    bus.add_step("versioner_wfbarrier_composer_delegator", "barrier", step_barrier, "agent_workflow_barrier")
    bus.add_step("versioner_wfbarrier_composer_delegator", "compose", step_compose, "pipeline_step_composer")
    bus.add_step("versioner_wfbarrier_composer_delegator", "delegate", step_delegate, "agent_task_delegator")

    result = bus.execute("versioner_wfbarrier_composer_delegator", {})
    assert result["success"] is True
    assert result["steps_completed"] == 4
    assert "version_id" in result["context"]
    assert "barrier_id" in result["context"]
    assert "comp_id" in result["context"]
    assert "deleg_id" in result["context"]
    print("OK: chain 117 -- versioner_wfbarrier_composer_delegator (Phase 90)")


