    bus.add_step("stamper_wffinalizer_skipper_recycler", "stamp", step_stamp, "pipeline_data_stamper")
    bus.add_step("stamper_wffinalizer_skipper_recycler", "finalize", step_finalize, "agent_workflow_finalizer")
